const TROUBLE_MAJOR_DAYPARTS=['morningDrive','afternoonDrive','midday','evening'];

/** @returns {'talent'|'franchise'|false} */
function troubleOptionRemovesFromAir(opt){
  if(!opt)return false;
  if(opt.dropFranchise)return'franchise';
  if(opt.forCause||opt.cost==='forCause')return'talent';
  if(typeof opt.label!=='string')return false;
  const l=opt.label.toLowerCase();
  if(l.includes('fire')||l.includes('terminate')||(l.includes('buy out')&&l.includes('contract')))return'talent';
  return false;
}

function triggerTalentTrouble(G){
  const acts=[];
  if(!G||!G.ps||G.pendingDecisionEvent)return acts;
  const cands=[];
  G.ps.forEach(s=>{
    if(!s.prog)return;
    TROUBLE_MAJOR_DAYPARTS.forEach(slot=>{
      const sd=s.prog[slot];
      if(!sd?.talent)return;
      const t=sd.talent;
      if((t._suspended||0)>0)return;
      cands.push({s,slot,t});
    });
  });
  if(!cands.length)return acts;
  const pick=cands[Math.floor(Math.random()*cands.length)];
  const baseProb=pick.t.superstar?0.010:0.005;
  const moraleMod=pick.t.morale<50?1.35:pick.t.morale<65?1.0:0.65;
  if(Math.random()>baseProb*moraleMod)return acts;
  const tierRoll=Math.random();
  const pool=tierRoll<0.3
    ? TROUBLE_SCENARIOS.filter(sc=>sc.tier==='major')
    : TROUBLE_SCENARIOS.filter(sc=>sc.tier==='minor');
  if(!pool.length)return acts;
  const scenario=pool[Math.floor(Math.random()*pool.length)];
  const rivalPool=G.stations.filter(st=>st&&!st._bpSlotDeferred&&!st.isPlayer&&!stationIsNoncommercialInstitutional(st)&&st.rat?.share>0.03);
  const rival=rivalPool.length?rivalPool[Math.floor(Math.random()*rivalPool.length)]:null;
  G.pendingDecisionEvent={
    scenarioId:scenario.id,
    stationId:pick.s.id,
    slot:pick.slot,
    talentName:pick.t.name,
    rivalStation:rival?.callLetters||'a rival',
    year:G.year,
    period:G.period,
    ownerId:pick.s._mpOwner!==undefined?pick.s._mpOwner:0,
  };
  acts.push({v:'HIGH',
    t:`⚠ INCIDENT: ${scenario.title} — ${pick.t.name} at ${pick.s.callLetters}. Decision required.`,
    y:G.year,p:G.period,iy:true});
  return acts;
}

function clearPendingTroubleIfStale(){
  const p=G?.pendingDecisionEvent;
  if(!p)return;
  if(p.isFranchiseFormatMismatch){
    const s=G.stations.find(st=>st.id===p.stationId);
    const f=NATIONAL_FRANCHISES.find(x=>x.id===p.franchiseId);
    const r=G.franchiseRights?.[p.franchiseId];
    if(!s||!f||!r||r.holderId!==s.id||!franchiseHolderFormatMismatch(f,s))
      G.pendingDecisionEvent=null;
    return;
  }
  if(!TROUBLE_SCENARIOS.find(sc=>sc.id===p.scenarioId)){G.pendingDecisionEvent=null;return;}
  if(p.isFranchise){
    const s=G.stations.find(st=>st.id===p.stationId);
    const r=G.franchiseRights?.[p.franchiseId];
    if(!s||!r||r.holderId!==s.id)G.pendingDecisionEvent=null;
    return;
  }
  const s=G.stations.find(st=>st.id===p.stationId);
  const sd=s?.prog?.[p.slot];
  if(!sd?.talent)G.pendingDecisionEvent=null;
}

/** Clicks on #trouble-body — avoids inline `onclick` global lookup issues in some browsers. */
function wlWireTalentTroubleBodyClicks(tb){
  if(!tb)return;
  tb.onclick=function(ev){
    const btn=ev.target&&ev.target.closest?ev.target.closest('button.to'):null;
    if(!btn||btn.classList.contains('nope'))return;
    const afford=btn.getAttribute('data-wl-trouble-afford')==='1';
    const idx=parseInt(btn.getAttribute('data-wl-trouble-opt')||'-1',10);
    if(!afford){
      talentTroubleOptionUnaffordable(Number.isFinite(idx)?idx:0);
      return;
    }
    if(!Number.isFinite(idx)||idx<0)return;
    const p=G&&G.pendingDecisionEvent;
    if(!p)return;
    resolveTrouble(p.stationId,p.slot,idx);
  };
}

function showFranchiseFormatMismatchModal(){
  clearPendingTroubleIfStale();
  const pending=G?.pendingDecisionEvent;
  if(!pending?.isFranchiseFormatMismatch)return;
  const f=NATIONAL_FRANCHISES.find(x=>x.id===pending.franchiseId);
  const s=G.stations.find(st=>st.id===pending.stationId);
  const r=G.franchiseRights?.[pending.franchiseId];
  if(!f||!s||!r||r.holderId!==s.id)return;
  const ownerPid=pending.ownerId!=null?pending.ownerId:MP.playerId;
  const ownerCash=MP.mode==='live'?(G._playerCash?.[ownerPid]??G.cash):G.cash;
  const termFee=franchiseEarlyTerminationFee(f,r,G);
  const yrsLeft=franchiseYearsRemaining(r,G);
  const dests=xferOwnedStations().filter(st=>franchiseTransferDestEligible(f,st,s.id,G));
  const transferRows=dests.map(st=>franchiseXferButtonHtml(f,s.id,st)).join('');
  const canTerm=ownerCash>=termFee;
  const tt=document.getElementById('trouble-title');
  const tb=document.getElementById('trouble-body');
  if(!tt||!tb)return;
  tt.textContent='⚠ FRANCHISE FORMAT COMPLIANCE';
  tb.innerHTML=`
    <div style="background:rgba(245,166,35,.06);border:1px solid rgba(245,166,35,.25);border-radius:6px;padding:14px;margin-bottom:16px">
      <div style="font-family:var(--fd);font-size:17px;color:var(--wht);margin-bottom:6px">${f.name} <span style="color:var(--mut);font-weight:normal">· ${s.callLetters} ${SL[f.slot]||''}</span></div>
      <div style="font-size:15px;color:var(--off);margin-bottom:6px">You flipped ${s.callLetters} to <strong>${fmtLabel(s.format)}</strong>, but this syndicator requires <strong>${f.formats.map(fmtLabel).join(' or ')}</strong>. The franchise stays on your books until you transfer it or buy out the remainder of the contract.</div>
      <div style="font-size:14px;color:var(--mut)">While out of compliance, ${SL[f.slot]} runs at reduced strength and syndication fees (${f$(r.fee)}/yr) continue. At renewal, the syndicator will not extend rights on an incompatible format.</div>
    </div>
    <div style="font-size:14px;color:var(--mut);margin-bottom:10px">How do you resolve this?</div>
    ${transferRows||`<div class="di" style="margin-bottom:10px">No owned station currently qualifies — acquire or reformat another signal, or buy out the contract.</div>`}
    <button type="button" class="to${canTerm?'':' nope'}" data-wl-fr-fmt-term="1" data-wl-trouble-afford="${canTerm?'1':'0'}" style="display:block;width:100%;text-align:left;padding:10px 14px;margin-bottom:6px;cursor:${canTerm?'pointer':'not-allowed'}">
      <div style="font-family:var(--fd);font-size:15px;color:var(--wht)">Buy out contract early</div>
      <div style="font-size:13px;color:${canTerm?'var(--amb)':'var(--red)'};margin-top:2px">${f$(termFee)} termination fee (${Math.ceil(yrsLeft)} yr${Math.ceil(yrsLeft)!==1?'s':''} remaining)</div>
    </button>`;
  tb.onclick=function(ev){
    const termBtn=ev.target?.closest?.('[data-wl-fr-fmt-term]');
    if(termBtn){
      if(termBtn.getAttribute('data-wl-trouble-afford')!=='1'){
        showToast(`You need ${f$(termFee)} to buy out this franchise contract.`,'warn',7200);
        return;
      }
      openGameConfirm(
        {title:'CONFIRM FRANCHISE BUYOUT',message:`Pay ${f$(termFee)} to end "${f.name}" on ${callDisplay(s)} immediately? The ${SL[f.slot]} daypart opens for local programming.`,confirmLabel:'YES — BUY OUT',danger:true},
        ok=>{if(ok)resolveFranchiseFormatMismatchTerminate(pending.franchiseId,s.id);},
      );
    }
  };
  om('m-talent-trouble');
}
function resolveFranchiseFormatMismatchTransfer(franchiseId,fromSid,toSid){
  const s=G.stations.find(st=>st.id===fromSid);
  const f=NATIONAL_FRANCHISES.find(x=>x.id===franchiseId);
  if(!s||!f||!transferFranchiseHolder(franchiseId,fromSid,toSid,G)){
    showToast('That transfer is not available.','warn');
    return;
  }
  const to=G.stations.find(st=>st.id===toSid);
  G._franchiseXferAck={franchiseId,fromSid,toSid,toCall:to?.callLetters||callDisplay(to)};
  G.news.unshift({
    v:'MEDIUM',
    t:`📻 "${f.name}" transferred from ${s.callLetters} to ${to?.callLetters||'another station'} — contract continues through ${G.franchiseRights?.[franchiseId]?.contractEnd||'renewal'}.`,
    y:G.year,p:G.period,iy:true,
  });
  G.pendingDecisionEvent=null;
  const moreMismatch=queueNextFranchiseFormatMismatchDecision(s,G);
  MP.action('franchise_transfer',{franchiseId,fromSid,toSid});
  if(document.getElementById('m-franchise')?.classList.contains('on')){
    openFranchise(fromSid);
  }else if(document.getElementById('m-talent-trouble')?.classList.contains('on')){
    if(moreMismatch)showFranchiseFormatMismatchModal();
    else cm('m-talent-trouble');
  }else if(!moreMismatch){
    cm('m-talent-trouble');
  }
  requestAnimationFrame(()=>{
    wlMarkCommitSatisfied(`fr-xfer-${franchiseId}-${toSid}`);
    wlFlashCommitButton(`fr-xfer-${franchiseId}-${toSid}`);
  });
  renderAll();
  if(G.pendingDecisionEvent)setTimeout(()=>showFranchiseFormatMismatchModal(),400);
}
function openFranchiseFormatBuyoutConfirm(franchiseId,stationId){
  const f=NATIONAL_FRANCHISES.find(x=>x.id===franchiseId);
  const s=G.stations.find(st=>st.id===stationId);
  const r=G.franchiseRights?.[franchiseId];
  if(!f||!s||!r)return;
  const termFee=franchiseEarlyTerminationFee(f,r,G);
  openGameConfirm(
    {title:'CONFIRM FRANCHISE BUYOUT',message:`Pay ${f$(termFee)} to end "${f.name}" on ${callDisplay(s)} immediately?`,confirmLabel:'YES — BUY OUT',danger:true},
    ok=>{if(ok)resolveFranchiseFormatMismatchTerminate(franchiseId,stationId);},
  );
}
function resolveFranchiseFormatMismatchTerminate(franchiseId,stationId){
  const f=NATIONAL_FRANCHISES.find(x=>x.id===franchiseId);
  const s=G.stations.find(st=>st.id===stationId);
  const res=terminateFranchiseContractEarly(franchiseId,stationId,G);
  if(!res.ok){
    showToast(`You need ${f$(res.fee)} to buy out this franchise contract.`,'warn',7200);
    return;
  }
  G.news.unshift({
    v:'MEDIUM',
    t:`📻 "${f?.name||'Franchise'}" contract ended early on ${s?.callLetters||'station'} — ${f$(res.fee)} termination fee paid.`,
    y:G.year,p:G.period,iy:true,
  });
  G.pendingDecisionEvent=null;
  if(s&&!queueNextFranchiseFormatMismatchDecision(s,G))cm('m-talent-trouble');
  MP.action('franchise_terminate',{franchiseId,stationId,fee:res.fee});
  renderAll();
  if(G.pendingDecisionEvent)setTimeout(()=>showFranchiseFormatMismatchModal(),400);
}
function showTalentTroubleModal(){
  clearPendingTroubleIfStale();
  const pending=G.pendingDecisionEvent;
  if(!pending)return;
  if(pending.isFranchiseFormatMismatch){showFranchiseFormatMismatchModal();return;}
  const scenario=TROUBLE_SCENARIOS.find(sc=>sc.id===pending.scenarioId);
  if(!scenario)return;
  const s=G.stations.find(st=>st.id===pending.stationId);
  if(pending.isFranchise){
    const nm=pending.talentName||'Syndicated franchise';
    const desc=scenario.desc.replace(/{name}/g,nm).replace(/{rivalStation}/g,pending.rivalStation||'');
    const ownerPid=pending.ownerId!=null?pending.ownerId:MP.playerId;
    const ownerCash=MP.mode==='live'?(G._playerCash?.[ownerPid]??G.cash):G.cash;
    const mandatoryFine=troubleMandatoryFccFine(scenario.id);
    const opts=troubleScenarioOptions(scenario,pending);
    const optRows=opts.map((opt,i)=>{
      let costLabel='',costColor='var(--off)',canAfford=true;
      if(opt.cost==='fine'){
        costLabel=` — Mandatory FCC fine: ${f$(mandatoryFine)}`;
        costColor='var(--red)';
        canAfford=ownerCash>=mandatoryFine;
      }else if(opt.cost==='forCause'||opt.forCause||opt.dropFranchise){
        costLabel=mandatoryFine>0?` — FCC fine: ${f$(mandatoryFine)} (conduct clause — no termination fee)`:' — Drop franchise (no termination fee)';
        costColor=mandatoryFine>0?'var(--red)':'var(--amb)';
        canAfford=ownerCash>=mandatoryFine;
      }else if(opt.cost==='none'||opt.cost==='leave'){
        costLabel=mandatoryFine>0?` — Mandatory FCC fine: ${f$(mandatoryFine)}`:(opt.cost==='leave'?' — 1 period suspension (syndicated slot dark)':'No cash cost');
        canAfford=ownerCash>=mandatoryFine;
      }else if(typeof opt.cost==='number'){
        const totalNeed=mandatoryFine+opt.cost;
        costLabel=mandatoryFine>0?` — FCC fine: ${f$(mandatoryFine)} + ${f$(opt.cost)} legal`:` — ${f$(opt.cost)}`;
        canAfford=ownerCash>=totalNeed;
      }
      return `<button type="button" class="to${canAfford?'':' nope'}" data-wl-trouble-opt="${i}" data-wl-trouble-afford="${canAfford?'1':'0'}" style="display:block;width:100%;text-align:left;padding:10px 14px;margin-bottom:6px;cursor:${canAfford?'pointer':'not-allowed'}">
      <div style="font-family:var(--fd);font-size:15px;color:var(--wht)">${troubleOptionDisplayLabel(opt,nm)}</div>
      <div style="font-size:13px;color:${costColor};margin-top:2px">${costLabel||'No cost'}</div>
    </button>`;
    }).join('');
    const tt=document.getElementById('trouble-title');
    const tb=document.getElementById('trouble-body');
    if(!tt||!tb)return;
    tt.textContent=`⚠ ${scenario.title.toUpperCase()}`;
    tb.innerHTML=`
    <div style="background:rgba(240,88,88,.06);border:1px solid rgba(240,88,88,.15);border-radius:6px;padding:14px;margin-bottom:16px">
      <div style="font-family:var(--fd);font-size:17px;color:var(--wht);margin-bottom:6px">${nm} <span style="color:var(--mut);font-weight:normal">· ${s?.callLetters||''} ${SL[pending.slot]||''}</span></div>
      <div style="font-size:15px;color:var(--off);margin-bottom:6px">${desc}</div>
      <div style="font-size:14px;color:var(--mut);font-style:italic">${scenario.flavor}</div>
    </div>
    <div style="font-size:14px;color:var(--mut);margin-bottom:10px">How do you respond?</div>
    ${optRows}`;
    wlWireTalentTroubleBodyClicks(tb);
    om('m-talent-trouble');
    return;
  }
  const sd=s?.prog?.[pending.slot];
  const t=sd?.talent;
  if(!t){G.pendingDecisionEvent=null;return;}
  const ownerPid=pending.ownerId!=null?pending.ownerId:MP.playerId;
  const ownerCash=MP.mode==='live'?(G._playerCash?.[ownerPid]??G.cash):G.cash;
  const cyr=t.cyr||0;
  const buyout=cyr>0.1?Math.round(t.salary*cyr*0.60/500)*500:0;
  const mandatoryFine=troubleMandatoryFccFine(scenario.id);
  const raiseAmt=Math.round(t.salary*0.15/500)*500;
  const desc=scenario.desc.replace(/{name}/g,t.name).replace(/{rivalStation}/g,pending.rivalStation);
  const opts=troubleScenarioOptions(scenario,pending);
  const optRows=opts.map((opt,i)=>{
    let costLabel='',costColor='var(--off)',canAfford=true;
    if(opt.cost==='fine'){
      costLabel=` — Mandatory FCC fine: ${f$(mandatoryFine)}`;
      costColor='var(--red)';
      canAfford=ownerCash>=mandatoryFine;
    }
    else if(opt.cost==='forCause'||opt.forCause){
      costLabel=mandatoryFine>0
        ?` — FCC fine: ${f$(mandatoryFine)} (for cause — no buyout)`
        :'For-cause termination — no buyout';
      costColor=mandatoryFine>0?'var(--red)':'var(--amb)';
      canAfford=ownerCash>=mandatoryFine;
    }
    else if(opt.cost==='buyout'){
      const totalNeed = mandatoryFine + (buyout||0);
      costLabel=buyout>0
        ?` — FCC fine: ${f$(mandatoryFine)} + Buyout: ${f$(buyout)}`
        :` — FCC fine: ${f$(mandatoryFine)}`;
      costColor='var(--amb)';
      canAfford=ownerCash>=totalNeed;
    }
    else if(opt.cost==='raise'){
      costLabel=` — FCC fine: ${f$(mandatoryFine)} + Salary +${f$(raiseAmt)}/yr`;
      costColor='var(--amb)';
      canAfford=ownerCash>=mandatoryFine;
    }
    else if(opt.cost==='leave' || opt.cost==='none'){
      costLabel=mandatoryFine>0 ? ` — Mandatory FCC fine: ${f$(mandatoryFine)}` : (opt.cost==='leave' ? ' — 1 period paid leave' : 'No cash cost');
      costColor=mandatoryFine>0 ? 'var(--red)' : 'var(--mut)';
      canAfford=ownerCash>=mandatoryFine;
    }
    else if(typeof opt.cost==='number'){
      const totalNeed = mandatoryFine + opt.cost;
      costLabel= mandatoryFine>0
        ? ` — FCC fine: ${f$(mandatoryFine)} + ${f$(opt.cost)} legal`
        : ` — ${f$(opt.cost)} legal`;
      costColor='var(--amb)';
      canAfford=ownerCash>=totalNeed;
    }
    return `<button type="button" class="to${canAfford?'':' nope'}" data-wl-trouble-opt="${i}" data-wl-trouble-afford="${canAfford?'1':'0'}" style="display:block;width:100%;text-align:left;padding:10px 14px;margin-bottom:6px;cursor:${canAfford?'pointer':'not-allowed'}">
      <div style="font-family:var(--fd);font-size:15px;color:var(--wht)">${troubleOptionDisplayLabel(opt,t.name)}</div>
      <div style="font-size:13px;color:${costColor};margin-top:2px">${costLabel||'No cost'}</div>
    </button>`;
  }).join('');
  const tt=document.getElementById('trouble-title');
  const tb=document.getElementById('trouble-body');
  if(!tt||!tb)return;
  tt.textContent=`⚠ ${scenario.title.toUpperCase()}`;
  tb.innerHTML=`
    <div style="background:rgba(240,88,88,.06);border:1px solid rgba(240,88,88,.15);border-radius:6px;padding:14px;margin-bottom:16px">
      <div style="font-family:var(--fd);font-size:17px;color:var(--wht);margin-bottom:6px">${t.name} <span style="color:var(--mut);font-weight:normal">· ${s?.callLetters||''} ${SL[pending.slot]||''}</span></div>
      <div style="font-size:15px;color:var(--off);margin-bottom:6px">${desc}</div>
      <div style="font-size:14px;color:var(--mut);font-style:italic">${scenario.flavor}</div>
    </div>
    <div style="font-size:14px;color:var(--mut);margin-bottom:10px">How do you respond?</div>
    ${optRows}`;
  wlWireTalentTroubleBodyClicks(tb);
  om('m-talent-trouble');
}

function applyTroubleResolution(sid,slot,optionIdx,appealRemote){
  const pending=G.pendingDecisionEvent;
  if(!pending||pending.stationId!==sid||pending.slot!==slot)return;
  const s=G.stations.find(st=>st.id===sid);
  const scenario=TROUBLE_SCENARIOS.find(sc=>sc.id===pending.scenarioId);
  if(!scenario)return;
  const opts=troubleScenarioOptions(scenario,pending);
  const opt=opts[optionIdx];
  if(!opt)return;
  const eff=opt.effect||{};
  const ownerPid=pending.ownerId!=null?pending.ownerId:MP.playerId;
  const tCash=d=>{
    if(MP.mode!=='live'){G.cash+=d;return;}
    if(!G._playerCash)G._playerCash={};
    G._playerCash[ownerPid]=(G._playerCash[ownerPid]||0)+d;
    if(MP.playerId===ownerPid)G.cash=G._playerCash[ownerPid];
    MP.emit('player_cash_update',{playerId:ownerPid,cash:G._playerCash[ownerPid]});
  };
  const isFcc=troubleScenarioIsFcc(pending.scenarioId);
  const mandatoryFine=isFcc?troubleMandatoryFccFine(pending.scenarioId):0;
  let costPaid=0;
  if(mandatoryFine>0){tCash(-mandatoryFine);costPaid+=mandatoryFine;}
  if(typeof opt.cost==='number'){tCash(-opt.cost);costPaid+=opt.cost;}
  let troubleOutcomeNote='';
  if(pending.isFranchise){
    if(isFcc&&pending.scenarioId==='fcc_indecency'&&optionIdx===0){
      const fineAmt=mandatoryFine;
      let refund=0;
      if(appealRemote!=null&&typeof appealRemote.refund==='number'){
        refund=appealRemote.refund;
        troubleOutcomeNote=appealRemote.note||'';
      }else{
        const roll=Math.random();
        if(roll<0.60){
          refund=roll<0.25?fineAmt:Math.round(fineAmt*0.5);
          troubleOutcomeNote=refund>=fineAmt
            ?' Legal appeal succeeds — the FCC fine is dismissed.'
            :` Legal appeal partially succeeds — ${f$(refund)} of the FCC fine is recovered.`;
        }else{
          troubleOutcomeNote=' Legal appeal fails — the FCC fine stands.';
        }
      }
      if(refund>0){tCash(refund);costPaid-=refund;}
    }
    if(eff.sell)troubleApplySellDelta(s,eff.sell);
    if(eff.stationShare&&s){
      const fr=NATIONAL_FRANCHISES.find(x=>x.id===pending.franchiseId);
      let d=eff.stationShare;
      if(isFcc&&d>0){
        const id=(s.identity||0)/100;
        const fmt=COMMUNITY_IDENTITY[s.format]||0.5;
        const pull=fr?Math.min(1.15,0.85+(fr.troubleMod||1)*0.06):1;
        d=d*(0.35+id*fmt*pull);
      }
      troubleApplyStationShareDelta(s,d);
    }
    if(eff.identity&&s)s.identity=Math.max(0,Math.min(100,(s.identity||0)+eff.identity));
    const rights=G.franchiseRights?.[pending.franchiseId];
    if(rights&&typeof eff.franchiseRel==='number'){
      if(!rights.relationship)rights.relationship={};
      rights.relationship[s.id]=Math.max(0,(rights.relationship[s.id]||0)+eff.franchiseRel);
    }
    if(opt.dropFranchise){
      const fr=NATIONAL_FRANCHISES.find(x=>x.id===pending.franchiseId);
      releaseFranchiseForCause(pending.franchiseId,sid,G,{
        relationshipPenalty:Math.abs(eff.franchiseRel||25),
        sharePenalty:Math.abs(eff.stationShare||0.004),
        identityDelta:0,
        sellDelta:0,
        skipEffects:true,
      });
    }
    const nm=pending.talentName||'Franchise';
    const outcome=(opt.outcome||'Resolved.').replace(/{name}/g,nm);
    G.news.unshift({v:'MEDIUM',t:`📋 ${scenario.title}: ${outcome}${costPaid>0?' Cost: '+f$(costPaid)+'.':''}${troubleOutcomeNote}`,y:G.year,p:G.period,iy:true});
    G.pendingDecisionEvent=null;
    refreshStationOQ(s,G);
    return;
  }
  const sd=s?.prog?.[slot];
  const t=sd?.talent;
  if(!t)return;
  if(opt.cost==='fine'){
    // already paid via mandatoryFine for FCC
  }
  else if(opt.cost==='buyout'&&!opt.forCause){
    const buyout=talentFireBuyout(t);
    if(buyout>0){tCash(-buyout);costPaid+=buyout;}
  }
  else if(opt.cost==='raise'){
    const raiseAmt=Math.round(t.salary*0.15/500)*500;
    t.salary=Math.round((t.salary+raiseAmt)/500)*500;
    t.cyr=Math.max(t.cyr||2,(t.cyr||2)+2);
    t.morale=Math.min(100,(t.morale||65)+5);
  }
  else if(opt.cost==='leave'){
    // effect.suspendPeriods handles suspension
  }
  else if(typeof opt.cost==='number'){tCash(-opt.cost);costPaid+=opt.cost;}
  if(isFcc&&pending.scenarioId==='fcc_indecency'&&optionIdx===0){
    const fineAmt=mandatoryFine;
    let refund=0;
    if(appealRemote!=null&&typeof appealRemote.refund==='number'){
      refund=appealRemote.refund;
      troubleOutcomeNote=appealRemote.note||'';
    }else{
      const roll=Math.random();
      if(roll<0.60){
        refund=roll<0.25?fineAmt:Math.round(fineAmt*0.5);
        troubleOutcomeNote=refund>=fineAmt
          ?' Legal appeal succeeds — the FCC fine is dismissed.'
          :` Legal appeal partially succeeds — ${f$(refund)} of the FCC fine is recovered.`;
      }else{
        troubleOutcomeNote=' Legal appeal fails — the FCC fine stands.';
      }
    }
    if(refund>0){tCash(refund);costPaid-=refund;}
  }
  if(eff.morale)t.morale=Math.max(20,Math.min(100,(t.morale||65)+eff.morale));
  if(eff.quality){
    t.quality=Math.max(20,Math.min(100,(t.quality||50)+eff.quality));
    if(typeof t._trueQuality==='number'&&!Number.isNaN(t._trueQuality))
      t._trueQuality=Math.max(20,Math.min(100,Math.round(t._trueQuality+eff.quality)));
  }
  if(eff.loyalty)t._poachResist=(t._poachResist||0)+eff.loyalty/100;
  if(eff.suspendPeriods){t._suspended=(t._suspended||0)+eff.suspendPeriods;t._preSuspendQuality=t.quality;}
  troubleApplySellDelta(s,eff.sell);
  if(eff.stationShare&&s)troubleApplyStationShareDelta(s,troubleFccAudienceShareDelta(s,t,eff.stationShare));
  if(eff.identity&&s)s.identity=Math.max(0,Math.min(100,(s.identity||0)+eff.identity));
  if(eff.fine&&!isFcc){tCash(-eff.fine);costPaid+=eff.fine;}
  const fireOpt=troubleOptionRemovesFromAir(opt)==='talent';
  if(fireOpt){
    if(s&&sd){
      const nm=t.name;
      clearCoHostPairingState(sd);
      setSlotTalentB(sd,null);
      sd.talent=null;
      coerceMusicVoiceTrackModesGlobally(G);
      const penalty={morningDrive:.28,afternoonDrive:.18,midday:.12,evening:.08,overnight:.04}[slot]||.12;
      sd.quality=Math.max(10,Math.round((sd.quality||30)*(1-penalty)));
      s.oq=Math.round(Object.entries(SW).reduce((sum,[sl,w])=>sum+effSlotQForOq(s.prog[sl])*w,0));
      refreshStationOQ(s,G);
      try{
        logHistory(s,'TALENT',`${nm} released after incident — ${SL[slot]} (not benched).`,G);
      }catch(_e){}
      try{
        const causeNote=opt.forCause?' (for-cause termination — no buyout)':'';
        showToast(`${nm} is off the roster — not benched.${causeNote} You can hire a new host for ${SL[slot]} when ready.`,'info',5600);
      }catch(_e){}
    }
  }
  const outcome=(opt.outcome||'Resolved.').replace(/{name}/g,t.name);
  G.news.unshift({v:'MEDIUM',t:`📋 ${scenario.title}: ${outcome}${costPaid>0?' Cost: '+f$(costPaid)+'.':''}${troubleOutcomeNote}`,y:G.year,p:G.period,iy:true});
  G.pendingDecisionEvent=null;
}

function talentTroubleOptionUnaffordable(_optionIdx){
  showToast(
    'You do not have enough cash for this response. Pick another option or return after you can cover the fines and buyouts shown on the button.',
    'warn',
    8200,
  );
}

function resolveTrouble(sid,slot,optionIdx){
  if(!G.pendingDecisionEvent)return;
  const pending=G.pendingDecisionEvent;
  const scenario=TROUBLE_SCENARIOS.find(sc=>sc.id===pending.scenarioId);
  if(!scenario)return;
  const opts=troubleScenarioOptions(scenario,pending);
  const opt=opts[optionIdx];
  if(!opt)return;
  const runResolve=()=>{
    let appealRemote=null;
    if(troubleScenarioIsFcc(pending.scenarioId)&&pending.scenarioId==='fcc_indecency'&&optionIdx===0){
      const fineAmt=troubleMandatoryFccFine('fcc_indecency');
      const roll=Math.random();
      let refund=0,note='';
      if(roll<0.60){
        refund=roll<0.25?fineAmt:Math.round(fineAmt*0.5);
        note=refund>=fineAmt
          ?' Legal appeal succeeds — the FCC fine is dismissed.'
          :` Legal appeal partially succeeds — ${f$(refund)} of the FCC fine is recovered.`;
      }else{
        note=' Legal appeal fails — the FCC fine stands.';
      }
      appealRemote={refund,note};
    }
    applyTroubleResolution(sid,slot,optionIdx,appealRemote);
    MP.action('trouble_resolve',{sid,slot,optionIdx,appealRefund:appealRemote?.refund,appealNote:appealRemote?.note});
    cm('m-talent-trouble');
    renderAll();
  };
  const removeKind=troubleOptionRemovesFromAir(opt);
  if(!removeKind){
    runResolve();
    return;
  }
  const s=G.stations.find(st=>st.id===sid);
  const mandatoryFine=troubleScenarioIsFcc(pending.scenarioId)?troubleMandatoryFccFine(pending.scenarioId):0;
  const troubleOverlay=document.getElementById('m-talent-trouble');
  const troubleWasOpen=!!(troubleOverlay&&troubleOverlay.classList.contains('on'));
  if(troubleWasOpen)cm('m-talent-trouble',{wlTutorialSuppress:true});
  if(removeKind==='franchise'&&pending.isFranchise){
    const fr=NATIONAL_FRANCHISES.find(x=>x.id===pending.franchiseId);
    const frName=fr?.name||pending.talentName||'syndicated show';
    const costLine=mandatoryFine>0?` You pay ${f$(mandatoryFine)} FCC fine — no termination fee under the conduct clause.`:' No termination fee under the conduct clause.';
    openGameConfirm(
      {title:'CONFIRM FRANCHISE DROP',message:`Drop "${frName}" from ${callDisplay(s)} ${SL[slot]}?${costLine} The daypart goes dark until you replace programming.`,confirmLabel:'YES — DROP FRANCHISE',danger:true},
      ok=>{
        if(!ok){
          if(troubleWasOpen&&G?.pendingDecisionEvent)showTalentTroubleModal();
          return;
        }
        runResolve();
      },
    );
    return;
  }
  const sd=s?.prog?.[slot];
  const t=sd?.talent;
  if(!t){
    runResolve();
    return;
  }
  const buyout=opt.forCause||opt.cost==='forCause'?0:talentFireBuyout(t);
  const parts=[];
  if(mandatoryFine>0)parts.push(`${f$(mandatoryFine)} FCC fine`);
  if(opt.cost==='buyout'&&buyout>0)parts.push(`${f$(buyout)} buyout`);
  const costLine=parts.length?` If you confirm, you pay: ${parts.join(' + ')}.`:'';
  const causeLine=opt.forCause||opt.cost==='forCause'
    ?' Termination is for cause under the conduct clause — no contract buyout.'
    :' They will not go on your talent bench — they leave the company.';
  const msg=`Remove ${t.name} from ${callDisplay(s)} ${SL[slot]} immediately?${causeLine}${costLine}`;
  openGameConfirm(
    {title:opt.forCause||opt.cost==='forCause'?'CONFIRM FOR-CAUSE TERMINATION':'CONFIRM RELEASE',message:msg,confirmLabel:'YES — REMOVE FROM STATION',danger:true},
    ok=>{
      if(!ok){
        if(troubleWasOpen&&G?.pendingDecisionEvent)showTalentTroubleModal();
        return;
      }
      runResolve();
    },
  );
}
