function fmpForYear(year){
  // FM receiver penetration — calibrated to real history
  // 1970: ~20% (FM radios mostly home hi-fi, rare in cars)
  // 1976–80: steeper in-car uptake so Atlanta FM music is a real Top-10 force by ~1980
  // 1983: FM standard in most new cars (65%)
  // 1990: near-universal (85%)
  const base=0.20;
  const p1=_smoothstep(1970,1976,year)*0.27; // early adoption — 1970–72 stay fringe
  const p2=_smoothstep(1976,1981,year)*0.215; // car/stereo boom (compressed vs old 1977–1983)
  const p3=_smoothstep(1983,1990,year)*0.195; // slight trim so long-run ~1990+ stays in band
  const p4=_smoothstep(1990,2000,year)*0.12; // final holdouts
  return _clamp01(base+p1+p2+p3+p4);
}
/** FM receiver penetration adjusted per market — modest; ramps 1972–1990 so 1970 stays near national baseline */
function effectiveFmpForMarket(year,marketId){
  const m=MARKETS[marketId||'atlanta']||MARKETS.atlanta;
  const bias=(m.fmPenBias||0)*_smoothstep(1972,1990,year);
  return _clamp01(fmpForYear(year)+bias);
}
function streamForYear(year){
  if(year<2000)return 0;
  return _clamp01(0.02+_smoothstep(2000,2020,year)*0.58);
}
function amViabForYear(year){
  // AM music cultural viability — collapses post-1985, near-zero by 1998
  // Calibrated to Duncan data: AM music stations reformatting 1988-1997.
  // Last Atlanta AM music holdouts (WQXI/WPLO equivalents) gone by 1996-97.
  // Viability should hit near-zero ~1998; tiny floor (old gospel AMs, etc.) = 0.04.
  const v1=_smoothstep(1975,1988,year)*0.45; // steady erosion through late 80s
  const v2=_smoothstep(1988,1997,year)*0.51; // rapid collapse — last music AMs gone by ~1997
  return Math.max(0.04,1.0-v1-v2);
}
/**
 * Late-1970s FM music listening preference: stereo music and clean audio pull audiences
 * to FM as receiver penetration rises, while talk stays AM-weighted. Ramps mid-70s, full
 * by ~1979–86, then fades (FM is the default — no permanent artificial lift). Applied only
 * in appl() for full-power FM; does not affect revenue.
 */
function fmMusicEraPreferenceMult(s, year, fmp, marketId) {
  if (!s || s.isPublic || s.sig.type !== 'FM') return 1;
  if (['NEWS_TALK', 'SPORTS_TALK', 'PERSONALITY_TALK', 'ALL_NEWS'].includes(s.format)) return 1;
  const strong = new Set(['TOP40', 'ALBUM_ROCK', 'BEAUTIFUL_MUSIC', 'ADULT_CONTEMP', 'SOUL_RNB', 'CLASSIC_ROCK', 'MOR', 'OLDIES', 'RHYTHMIC', 'HOT_AC', 'URBAN_CONTEMP', 'ALT_ROCK', 'AAA']);
  let fmtW = 0;
  if (strong.has(s.format)) fmtW = 1;
  else if (s.format === 'COUNTRY') fmtW = 0.55;
  else if (['SPANISH', 'CLASSIC_HITS', 'ADULT_STANDARDS'].includes(s.format)) fmtW = 0.45;
  else if (s.format === 'GOSPEL') fmtW = 0.72;
  else return 1;
  // FM-friendly music lanes that defined late-70s Atlanta dial wars
  const late70sCore = new Set(['TOP40', 'ALBUM_ROCK', 'BEAUTIFUL_MUSIC', 'ADULT_CONTEMP', 'SOUL_RNB', 'MOR']);
  if (late70sCore.has(s.format) && year >= 1976)
    fmtW = Math.min(1.09, fmtW * (1 + _smoothstep(1976, 1979, year) * 0.14));
  // Stereo/listener shift: ramps mid-70s; fades post-1986 as FM becomes default
  const eraWindow = _smoothstep(1971, 1976, year) * (1 - _smoothstep(1986, 1992, year));
  const fmpRamp = _smoothstep(0.24, 0.50, fmp);
  // 1976–80: extra stereo / quiet-AM flight to FM (trimmed vs prior so one FM rarely locks #1 every run)
  const late70sBurst = _smoothstep(1975, 1978, year) * (1 - _smoothstep(1981, 1986, year));
  const raw = 0.60 * eraWindow * fmpRamp * fmtW * (1 + late70sBurst * 0.40);
  const inner = Math.min(1.58, 1 + raw);
  const frag = (MARKETS[marketId || 'atlanta'] || MARKETS.atlanta).fmMusicFragMult ?? 1;
  return Math.min(1.62, 1 + (inner - 1) * frag);
}
