/** Resolve {FREQ}, {CITY}, {ABBREV}, {AMCHOP}, {CALL} in a brand name */
function resolveBrand(brand, freq, city, marketId, callLetters){
  const yr=(typeof G!=='undefined'&&G?.year)||1970;
  const fmWhole=fmBrandAnalogWholeMhz(freq, yr);
  const freqShort=fmWhole!=null?fmWhole:String(freq||'').replace(/\s*(AM|FM)\s*$/i,'').trim();
  const mkt=MARKETS[marketId]||MARKETS.atlanta;
  const cityLabel=mkt.label||city||'City';
  const abbrev=MARKET_BRAND_ABBREV[marketId]||cityLabel.split(/\s+/)[0]||'City';
  const amchop=amDialBrandToken(freq, callLetters, marketId)||freqShort;
  const call=brandCallBaseForToken(callLetters);
  const out=String(brand||'')
    .replace(/{FREQ}/g, freqShort)
    .replace(/{AMCHOP}/g, amchop)
    .replace(/{CALL}/g, call)
    .replace(/{CITY}/g, cityLabel)
    .replace(/{ABBREV}/g, abbrev);
  return out.replace(/\s{2,}/g,' ').trim();
}
/** V/X/Y/Z/Q appearing after the leading W or K (real stations use the last/exotic letter in "X-100.3" style brands). */
const EXOTIC_CALL_BRAND_LETTERS=new Set(['V','X','Y','Z','Q']);
function exoticLettersInCallSign(callLetters){
  const base=stripCallBandSuffix(String(callLetters||'')).toUpperCase().replace(/[^A-Z]/g,'');
  if(base.length<2)return [];
  const out=[],seen=new Set();
  for(let i=1;i<base.length;i++){
    const ch=base[i];
    if(EXOTIC_CALL_BRAND_LETTERS.has(ch)&&!seen.has(ch)){seen.add(ch);out.push(ch);}
  }
  return out;
}
/** Same marketing identity after stripping a leading dial (e.g. "94.7 the Beat" → "the beat") — blocks duplicate slogans on different frequencies. */
function brandMarketIdentityKey(brand){
  const s=String(brand||'').toLowerCase().replace(/\s+/g,' ').trim();
  const m=s.match(/^\d+(\.\d+)?\s+(.+)$/);
  if(m)return m[2].trim();
  return s;
}
function collectBrandIdentityKeysFromStationList(list, excludeId){
  const set=new Set();
  (list||[]).forEach(st=>{
    if(!st||!st.brand)return;
    if(excludeId&&st.id===excludeId)return;
    set.add(brandMarketIdentityKey(st.brand));
  });
  return set;
}
function collectMarketBrandIdentityKeys(excludeSid){
  return collectBrandIdentityKeysFromStationList(typeof G!=='undefined'?G.stations:null, excludeSid);
}
// Get format-aware brand suggestions for a station (with resolved tokens; no duplicate slogans vs rivals)
function getBrandSuggestions(s){
  const fmtKey=canonicalHitsFormatKey(s.format);
  let raw=BRANDS[fmtKey]||['{FREQ} Radio'];
  const y=G?.year??1970;
  const isAmSt=s&&(s.sig?.type==='AM'&&!s.fmBooster);
  if(y>=1970&&y<=1979&&isAmSt&&EARLY_AM_DIAL_BRAND_FORMATS.has(fmtKey))raw=[...EARLY_AM_DIAL_BRAND_PATTERNS,...raw];
  if(y>=1970&&y<=1979&&!isAmSt&&BRANDS_1970S_FM_FORMATS.has(fmtKey))raw=[...BRANDS_1970S_FM_EXTRA,...raw];
  const city=G?.city||'Atlanta';
  const mktId=G?.marketId||ACTIVE_MARKET||'atlanta';
  const freqShort=stationFreqDial(s);
  const taken=new Set(
    (G.stations||[]).filter(st=>st&&st.id!==s.id).map(st=>brandMarketIdentityKey(st.brand||''))
  );
  const takenExact=new Set(
    (G.stations||[]).filter(st=>st&&st.id!==s.id).map(st=>String(st.brand||'').toLowerCase().replace(/\s+/g,' ').trim()).filter(Boolean)
  );
  const seen=new Set();
  const base=[];
  raw.forEach(b=>{
    const resolved=resolveBrand(b, s.freq, city, mktId, s.callLetters);
    if(!resolved)return;
    const idK=brandMarketIdentityKey(resolved);
    const ex=String(resolved).toLowerCase().replace(/\s+/g,' ').trim();
    if(taken.has(idK))return;
    if(takenExact.has(ex))return;
    if(seen.has(idK))return;
    seen.add(idK);
    base.push(resolved);
  });
  const def=defaultPlayerStationBrand(s);
  const out=[];
  if(def){
    const dk=brandMarketIdentityKey(def);
    const dex=String(def).toLowerCase().replace(/\s+/g,' ').trim();
    if(!taken.has(dk)&&!takenExact.has(dex)&&!seen.has(dk)){out.push(def);seen.add(dk);}
  }
  base.forEach(b=>{if(!out.includes(b))out.push(b);});
  exoticLettersInCallSign(s.callLetters).forEach(L=>{
    const resolved=`${L}-${freqShort}`;
    const idK=brandMarketIdentityKey(resolved);
    const exR=String(resolved).toLowerCase().replace(/\s+/g,' ').trim();
    if(taken.has(idK)||takenExact.has(exR)||seen.has(idK))return;
    if(out.includes(resolved))return;
    seen.add(idK);
    out.push(resolved);
  });
  return out.length?out:[def||resolveBrand('{FREQ} Radio', s.freq, city, mktId, s.callLetters)];
}

