const GRADE_TITLES={
  A:['Market Dominator','The Legend','Top Dog','Untouchable'],
  B:['Strong Performer','Solid Operator','Market Player','The Pro'],
  C:['Middling Manager','Surviving','Holding On','In the Pack'],
  D:['Struggling Broadcaster','Barely Afloat','On the Bubble','Under Pressure'],
  F:['Station Failure','Going Dark','Distress Sale','Bankrupt'],
};
const DECADE_NAMES={1979:'THE SEVENTIES',1989:'THE EIGHTIES',1999:'THE NINETIES',2009:'THE 2000s',2019:'THE 2010s',2020:'THE FULL ERA'};

// ── TALENT & GENERATION ───────────────────────────────────────────
/** Free-agent ask ranges by daypart × tier ($/yr, pre-inflation). Wider bands = more “shopping” feel; still ordered star > mid > entry. */
const SAL={morningDrive:{entry:[9500,24000],mid:[19000,42000],star:[32000,75000]},afternoonDrive:{entry:[7500,20000],mid:[14000,34000],star:[24000,58000]},midday:{entry:[6000,16000],mid:[11000,28000],star:[18000,42000]},evening:{entry:[6500,17000],mid:[12000,32000],star:[21000,48000]},overnight:{entry:[5500,14000],mid:[9500,24000],star:[16000,38000]}};
/** True on-air quality bands (scouting noise layered on top; pool skews middling vs legacy). */
const QRG={entry:[24,52],mid:[36,66],star:[50,82]};
/** Periods on-air (~4 calendar years at 2 periods/yr) to fold hidden performance into slot quality. */
const TALENT_REVEAL_PERIODS=8;
function clampTalentFit01(v){
  return Math.max(0.08,Math.min(0.98,typeof v==='number'&&!Number.isNaN(v)?v:0.3));
}
/** Actual ability (internal ratings / salary merit); falls back to visible scout rating for legacy saves. */
function talentTrueQuality(t){
  if(t&&typeof t._trueQuality==='number'&&!Number.isNaN(t._trueQuality))return Math.round(t._trueQuality);
  return Math.round(t?.quality||0);
}
function talentTrueFormatFit(t,fmt){
  if(!t||!fmt)return clampTalentFit01(undefined);
  const read=(key)=>{
    const m=t._trueFormatFit;
    if(m&&typeof m[key]==='number'&&!Number.isNaN(m[key]))return m[key];
    const f=t.formatFit;
    if(f&&typeof f[key]==='number'&&!Number.isNaN(f[key]))return f[key];
    return undefined;
  };
  let v=read(fmt);
  if(v==null&&isHitsFormatLineage(fmt)){
    const alt=fmt==='CHR'?'TOP40':fmt==='TOP40'?'CHR':null;
    if(alt)v=read(alt);
  }
  return clampTalentFit01(v);
}
/** Spoken-word formats share partial skill transfer (news ↔ personality ↔ sports). */
function talentTalkFormatCrossFit(fmtA,fmtB){
  if(!fmtA||!fmtB||fmtA===fmtB)return 1;
  const pair=new Set([fmtA,fmtB]);
  if(pair.has('ALL_NEWS')&&pair.has('NEWS_TALK'))return 0.88;
  if(pair.has('NEWS_TALK')&&pair.has('PERSONALITY_TALK'))return 0.78;
  if(pair.has('NEWS_TALK')&&pair.has('SPORTS_TALK'))return 0.62;
  if(pair.has('PERSONALITY_TALK')&&pair.has('SPORTS_TALK'))return 0.55;
  if(pair.has('ALL_NEWS')&&pair.has('PERSONALITY_TALK'))return 0.65;
  if(pair.has('ALL_NEWS')&&pair.has('SPORTS_TALK'))return 0.52;
  return 0.5;
}
function talentDestFormatFitRaw(talent,destFormat,opts){
  const useScout=opts&&opts.scout===true;
  const srcFmt=opts?.srcFormat;
  let raw=useScout
    ? talentScoutFormatFit01(talent,destFormat)
    : talentTrueFormatFit(talent,destFormat);
  if(!useScout&&srcFmt){
    const srcOnAir=talentTrueFormatFit(talent,srcFmt);
    if(srcFmt===destFormat)raw=Math.max(raw,srcOnAir);
    else if(TALK_FMTS.includes(srcFmt)&&TALK_FMTS.includes(destFormat))
      raw=Math.max(raw,srcOnAir*talentTalkFormatCrossFit(srcFmt,destFormat));
    else if(FADJ[srcFmt]?.includes(destFormat)||FADJ[destFormat]?.includes(srcFmt))
      raw=Math.max(raw,srcOnAir*0.72);
  }
  return typeof raw==='number'&&!Number.isNaN(raw)?raw:0.3;
}
/** Scout `formatFit` vs station format — CHR/TOP40 save drift won’t zero out fit in hire UI / doHire. */
function talentScoutFormatFit01(t,stationFormat){
  if(!t?.formatFit||!stationFormat)return 0.3;
  let v=t.formatFit[stationFormat];
  if(typeof v!=='number'||Number.isNaN(v)){
    const alt=canonicalHitsFormatKey(stationFormat);
    if(alt!==stationFormat)v=t.formatFit[alt];
  }
  if(typeof v!=='number'||Number.isNaN(v))return 0.3;
  return clampTalentFit01(v);
}
/** Rounded delta (slot quality points) between true vs scouted contribution for this station format. */
function talentPerformanceRevealDeltaForStation(fmt,t,kind){
  const sq=Math.round(t.quality||0), tq=talentTrueQuality(t);
  const sf=clampTalentFit01(t.formatFit?.[fmt]), tf=talentTrueFormatFit(t,fmt);
  if(kind==='xfer'){
    const scout=(sq/100)*sf*0.35*18, tru=(tq/100)*tf*0.35*18;
    return Math.round(tru-scout);
  }
  const scout=(sq/100)*sf*35, tru=(tq/100)*tf*35;
  return Math.round(tru-scout);
}
/** After hire / shuffle / xfer, schedule gradual slot-quality drift toward true performance. */
function initTalentPerformanceReveal(sd,t,fmt,kind){
  if(!sd||!t)return;
  const d=talentPerformanceRevealDeltaForStation(fmt,t,kind);
  if(!d){
    t._perfRevealStepsLeft=0;
    t._perfRevealDeltaRemaining=0;
    t._talentPerfRevealed=true;
    return;
  }
  t._perfRevealStepsLeft=TALENT_REVEAL_PERIODS;
  t._perfRevealDeltaRemaining=d;
  t._talentPerfRevealed=false;
}
function applyTalentPerformanceRevealDecayStep(sd,vtStress){
  const t=sd?.talent;
  if(!t)return;
  const left=t._perfRevealStepsLeft|0;
  if(left<1)return;
  const rem=t._perfRevealDeltaRemaining|0;
  if(!rem)return;
  const vt=Math.max(0,Math.min(1,Number(vtStress)||0));
  const vtK=1-0.072*vt;
  let step=Math.round((rem/left)*vtK);
  if(step===0)step=rem>0?1:(rem<0?-1:0);
  if(step===0)return;
  t._perfRevealDeltaRemaining=rem-step;
  t._perfRevealStepsLeft=left-1;
  if(t._perfRevealStepsLeft===0)t._talentPerfRevealed=true;
  sd.quality=Math.min(100,Math.max(10,Math.round((sd.quality||20)+step)));
}
/** Optional co-host: chemistry-led pairing (morning + afternoon drive only). */
/** Books until co-host pairing chemistry is fully revealed (~1 calendar year at 2 periods/yr). */
const COHOST_CHEM_REVEAL_PERIODS=2;
const COHOST_SLOT_STRENGTH={morningDrive:1,afternoonDrive:0.42,midday:0,evening:0,overnight:0};
function daypartAllowsCoHostModel(sl){
  return(sl==='morningDrive'||sl==='afternoonDrive');
}
/** Second on-air talent in a dual daypart (`talentB`). Legacy saves may still use `coHost`. */
function slotTalentB(sd){
  if(!sd)return null;
  return sd.talentB!=null?sd.talentB:(sd.coHost||null);
}
function setSlotTalentB(sd,t){
  if(!sd)return;
  if(t){ sd.talentB=t; delete sd.coHost; }
  else { delete sd.talentB; delete sd.coHost; }
}
/** When chair A is cleared but chair B remains, promote B into `talent` so slots stay consistent. */
function promoteSlotChairBtoAIfNeeded(sd,sl){
  if(!sd||sd.talent)return;
  const b=slotTalentB(sd);
  if(!b)return;
  if(sl&&!daypartAllowsCoHostModel(sl)){setSlotTalentB(sd,null);return;}
  setSlotTalentB(sd,null);
  sd.talent=b;
  clearPairingChemistryOnly(sd);
}
/** Canonical order for pairing chemistry / scout hash so chair assignment does not flip the model. */
function pairingChemTalentOrder(ta,tb){
  if(!ta||!tb)return[ta,tb];
  const ka=String(ta.id||'')+'\t'+normTalentNameKey(ta.name||'');
  const kb=String(tb.id||'')+'\t'+normTalentNameKey(tb.name||'');
  return ka<=kb?[ta,tb]:[tb,ta];
}
function migrateLegacyCoHostKeysToTalentB(G){
  (G.stations||[]).forEach(s=>{
    if(!s?.prog)return;
    DAYPART_SLOTS.forEach(sl=>{
      const sd=s.prog[sl];
      if(!sd)return;
      const leg=sd.coHost;
      if(leg&&!sd.talentB){ sd.talentB=leg; delete sd.coHost; }
      if(!daypartAllowsCoHostModel(sl)&&(sd.talentB||sd.coHost)){
        setSlotTalentB(sd,null);
        clearPairingChemistryOnly(sd);
      }
    });
  });
}
/** Revert slot-quality estimate from pairing + delete chemistry metadata only (does not remove on-air talent). */
function clearPairingChemistryOnly(sd){
  if(!sd)return;
  const adj=sd._cohostSlotAdjApplied|0;
  if(adj){
    sd.quality=Math.min(100,Math.max(10,Math.round((sd.quality||20)-adj)));
    delete sd._cohostSlotAdjApplied;
  }
  delete sd._cohostChemActual;
  delete sd._cohostChemEstimate;
  delete sd._cohostChemRevealStepsLeft;
  delete sd._cohostChemRevealRem;
  delete sd._cohostChemRevealed;
}
function cohostPersonalityFormatMult(fmt){
  if(TALK_FMTS.includes(fmt)||fmt==='ALL_NEWS')return 1.08;
  return 0.86;
}
function daypartCoHostModelStrength(sl,fmt){
  const w=COHOST_SLOT_STRENGTH[sl]||0;
  if(w<=0)return 0;
  return w*cohostPersonalityFormatMult(fmt);
}
function talentChemEff01(t,fmt){
  if(!t||!fmt)return 0.35;
  return Math.max(0.08,Math.min(1,(talentTrueQuality(t)/100)*talentTrueFormatFit(t,fmt)));
}
function rollCoHostChemistryPair(primary,cohost,fmt){
  const [p,c]=pairingChemTalentOrder(primary,cohost);
  const ep=talentChemEff01(p,fmt);
  const ec=talentChemEff01(c,fmt);
  const sim=1-Math.min(1,Math.abs(ep-ec)/0.82);
  const style=(ep+ec)*0.5;
  const noise=(Math.random()*2-1)*0.26;
  const base=sim*0.52+style*0.26-0.20+noise;
  const actual=Math.max(-1,Math.min(1,base));
  const estNoise=(Math.random()*2-1)*0.19;
  const estimate=Math.max(-1,Math.min(1,actual+estNoise));
  return{actual,estimate};
}
/** Deterministic chemistry preview for hire UI (stable; actual pairing still rolled at hire). */
function cohostChemistryScoutPreview01(primary,cohost,fmt){
  const [a,b]=pairingChemTalentOrder(primary,cohost);
  const ep=talentChemEff01(a,fmt);
  const ec=talentChemEff01(b,fmt);
  const sim=1-Math.min(1,Math.abs(ep-ec)/0.82);
  const style=(ep+ec)*0.5;
  const idLo=String(Math.min(Number(a.id)||0,Number(b.id)||0));
  const idHi=String(Math.max(Number(a.id)||0,Number(b.id)||0));
  const h=wlHash32(`${idLo}|${idHi}|${normTalentNameKey(a.name||'')}|${normTalentNameKey(b.name||'')}|${fmt}|chemscout`);
  const n=(h%2001)/2000-0.5;
  const est=sim*0.52+style*0.26-0.20+n*0.24;
  return Math.max(-1,Math.min(1,est));
}
function coHostSlotQualityDeltaPts(primary,cohost,fmt,sl,chem){
  const str=daypartCoHostModelStrength(sl,fmt);
  if(str<=0||!primary||!cohost||typeof chem!=='number'||Number.isNaN(chem))return 0;
  const [p,c]=pairingChemTalentOrder(primary,cohost);
  const ep=talentChemEff01(p,fmt);
  const ec=talentChemEff01(c,fmt);
  const blend=0.5*ep+0.5*ec;
  const anchor=(blend-0.44)*2.6*str;
  const chemSwing=chem*7.0*str;
  const d=anchor+chemSwing;
  return Math.max(-13.5,Math.min(10.2,d));
}
function chemistryEstimateLabel01(est){
  if(est<-0.34)return'Weak';
  if(est<-0.07)return'Fair';
  if(est<0.20)return'Good';
  return'Great';
}
function chemistryLabelColor01(v){
  if(typeof v!=='number'||Number.isNaN(v))return'var(--off)';
  if(v<-0.07)return'var(--red)';
  if(v<0.20)return'var(--amb)';
  return'var(--grn)';
}
/** Manage Talent co-host card: predicted vs actual chemistry + settling progress while books run. */
function coHostChemistryStatusHtml(sd,primaryName){
  if(!sd)return'';
  const pName=rosterHtmlEsc(primaryName||'lead host');
  const est=sd._cohostChemEstimate;
  const act=sd._cohostChemActual;
  const hasEst=typeof est==='number'&&!Number.isNaN(est);
  const hasAct=typeof act==='number'&&!Number.isNaN(act);
  const estL=chemistryEstimateLabel01(hasEst?est:0);
  if(sd._cohostChemRevealed&&hasAct){
    const actL=chemistryEstimateLabel01(act);
    const actCol=chemistryLabelColor01(act);
    let note='';
    if(act<-0.07)note='<div style="margin-top:4px;font-size:12px;color:var(--red);line-height:1.45">Weak pairing can drag share even when slot quality looks stable — consider replacing the co-host or swapping lead ↔ co-host.</div>';
    else if(act>=0.20)note='<div style="margin-top:4px;font-size:12px;color:var(--grn);line-height:1.45">Strong on-air pairing.</div>';
    return`<div class="mt-chem-status" style="font-size:13px;color:var(--off);margin-top:6px;line-height:1.5">
      <div><span style="color:var(--mut)">Predicted chemistry</span> with ${pName}: <strong>${estL}</strong></div>
      <div style="margin-top:2px"><span style="color:var(--mut)">Actual chemistry</span>: <strong style="color:${actCol}">${actL}</strong></div>${note}
    </div>`;
  }
  const left=sd._cohostChemRevealStepsLeft|0;
  const rem=sd._cohostChemRevealRem|0;
  let settle='Pairing still emerging — give it a book or two for the real read.';
  if(left>0){
    settle=`Pairing still emerging · <strong>${left}</strong> book${left===1?'':'s'} remaining (~${left===1?'6':'12'} mo)`;
    if(rem){
      const drift=rem>0?'higher':'lower';
      settle+=` · slot quality may settle ${drift} (~${Math.abs(rem)} pts total)`;
    }
    settle+='. Ratings can move before slot quality catches up.';
  }
  return`<div class="mt-chem-status" style="font-size:13px;color:var(--off);margin-top:6px;line-height:1.5">
    <div><span style="color:var(--mut)">Predicted chemistry</span> with ${pName}: <strong>${estL}</strong></div>
    <div style="margin-top:2px;color:var(--mut)">${settle}</div>
  </div>`;
}
/** Legacy dual-host slots missing chemistry metadata (pre-feature saves). */
function ensureSlotPairingChemistryBackfill(G){
  if(!G?.stations)return;
  G.stations.forEach(s=>{
    if(!s?.prog)return;
    DAYPART_SLOTS.forEach(sl=>{
      if(!daypartAllowsCoHostModel(sl))return;
      const sd=s.prog[sl];
      const b=slotTalentB(sd);
      if(!sd?.talent||!b)return;
      if(typeof sd._cohostChemActual==='number'&&!Number.isNaN(sd._cohostChemActual))return;
      const cr=rollCoHostChemistryPair(sd.talent,b,s.format);
      initCoHostChemistryReveal(sd,s.format,sl,sd.talent,b,cr);
    });
  });
}
/** Cap in-progress chemistry reveals when the horizon shortens (8 books → 2). */
function migrateCoHostChemistryRevealHorizon(G){
  if(!G?.stations)return;
  G.stations.forEach(s=>{
    if(!s?.prog)return;
    DAYPART_SLOTS.forEach(sl=>{
      const sd=s.prog[sl];
      if(!sd||sd._cohostChemRevealed)return;
      const left=sd._cohostChemRevealStepsLeft|0;
      if(left>COHOST_CHEM_REVEAL_PERIODS)sd._cohostChemRevealStepsLeft=COHOST_CHEM_REVEAL_PERIODS;
    });
  });
}
/** Daypart weight sum (for listening-mass split). */
const _SW_SUM=Object.values(SW).reduce((a,v)=>a+v,0);
/** Pull weight for allocating a station's AQH across dayparts (slot Q, brand, format skew). */
function daypartSlotAppealRaw(st,sl,G){
  if(!st||st._bpSlotDeferred||!st.rat||stationIsNoncommercialInstitutional(st))return 0;
  const op=simulcastOperationalSource(st);
  const sd=op.prog?.[sl];
  if(!sd)return 1e-6;
  let slotCore=0.10+0.90*(Math.max(0,Math.min(100,slotQualityForOQ(op,sl,G)))/100);
  const fr=getStationFranchise(op,sl,G);
  if(!sd.talent&&!fr){
    const mode=sd.staffingMode;
    if(mode==='paid')slotCore*=0.40;
    else if(mode==='light')slotCore*=0.55;
    else slotCore*=0.46;
  }
  if(slotTalentB(sd)&&daypartCoHostModelStrength(sl,op.format)>0){
    let chem=0;
    if(sd._cohostChemRevealed&&typeof sd._cohostChemActual==='number')chem=sd._cohostChemActual;
    else if(typeof sd._cohostChemEstimate==='number')chem=sd._cohostChemEstimate*0.42;
    slotCore*=1+chem*0.15*daypartCoHostModelStrength(sl,op.format);
  }
  const sh=Math.max(0.002,typeof st.rat.share==='number'?st.rat.share:0.002);
  const id=(st.identity||0)/100;
  const brandK=0.40+0.38*Math.min(1,sh/0.13)+0.22*id;
  let fmtK=1;
  const fmt=op.format||st.format;
  if(TALK_FMTS.includes(fmt)||fmt==='ALL_NEWS'){
    if(sl==='morningDrive'||sl==='afternoonDrive')fmtK=1.14;
    else if(sl==='overnight')fmtK=0.86;
    else if(sl==='evening')fmtK=0.94;
  }else if(sl==='midday')fmtK=1.05;
  else if(sl==='overnight')fmtK=0.92;
  const tpm=talentFranchiseRatingsEffect(op,G);
  slotCore*=tpm.ceilingMult;
  const dw=SW[sl]||0.08;
  return Math.max(1e-6,slotCore*brandK*fmtK*(0.50+0.50*dw/0.38));
}
/** Estimated AQH in one daypart — station total AQH × daypart pull share. */
function daypartStationAqhInSlot(st,sl,G){
  if(!st?.rat)return 0;
  const aqh=Math.max(0,Number(st.rat.aqh)||0);
  if(aqh<=0)return 0;
  let pullSum=0;
  let pullSl=0;
  DAYPART_SLOTS.forEach(s=>{
    const p=daypartSlotAppealRaw(st,s,G);
    pullSum+=p;
    if(s===sl)pullSl=p;
  });
  if(pullSum<=1e-12)return aqh/DAYPART_SLOTS.length;
  return aqh*(pullSl/pullSum);
}
/** Live derived in-daypart audience share (0–1) before/at recalc. */
function daypartDerivedShare01(st,sl,G){
  if(!st||!G||!DAYPART_SLOTS.includes(sl))return 0;
  const comm=(G.stations||[]).filter(s=>s&&!s._bpSlotDeferred&&s.rat&&!stationIsNoncommercialInstitutional(s));
  if(!comm.length)return 0;
  let mktAqh=0;
  comm.forEach(s=>{mktAqh+=daypartStationAqhInSlot(s,sl,G);});
  if(mktAqh<=1e-12)return 0;
  return Math.round((daypartStationAqhInSlot(st,sl,G)/mktAqh)*1e6)/1e6;
}
/** Clear stale independent-pool daypart shares after model switch to derived AQH split. */
function migrateDaypartAudienceDerivedV2(G){
  if(!G||G._daypartAudienceDerivedV2)return;
  G._daypartAudienceDerivedV2=1;
  (G.stations||[]).forEach(s=>{
    if(!s)return;
    if(s.momDp)DAYPART_SLOTS.forEach(sl=>{delete s.momDp[sl];});
    if(s.rat?.dp)DAYPART_SLOTS.forEach(sl=>{delete s.rat.dp[sl];});
  });
}
function ensureStationDaypartRatFields(st){
  if(!st||!st.rat)return;
  if(!st.rat.dp)st.rat.dp={};
  if(!st.momDp)st.momDp={};
  DAYPART_SLOTS.forEach(sl=>{
    if(!st.momDp[sl])st.momDp[sl]={tgt:0.01,cur:0.01};
    if(!st.rat.dp[sl])st.rat.dp[sl]={share:st.momDp[sl].cur||0.01,aqh:0};
  });
}
/**
 * Per-daypart audience estimates — derived from headline AQH, split by programming pull, then
 * normalized within each daypart. Weighted daypart shares reconcile with overall rat.share.
 */
function recalcDaypartAudience(stations,G){
  if(!stations?.length||!G)return;
  const comm=stations.filter(s=>s&&!s._bpSlotDeferred&&s.rat&&!stationIsNoncommercialInstitutional(s));
  if(!comm.length)return;
  const aqhBySt=comm.map(st=>{
    const bySl=Object.create(null);
    DAYPART_SLOTS.forEach(sl=>{bySl[sl]=daypartStationAqhInSlot(st,sl,G);});
    return{st,bySl};
  });
  DAYPART_SLOTS.forEach(sl=>{
    let mktAqh=0;
    aqhBySt.forEach(row=>{mktAqh+=row.bySl[sl];});
    aqhBySt.forEach(row=>{
      const st=row.st;
      ensureStationDaypartRatFields(st);
      const stAqh=row.bySl[sl];
      const tgt=mktAqh>1e-12?stAqh/mktAqh:1/comm.length;
      const cur=st.momDp[sl].cur??st.rat.dp[sl]?.share??tgt;
      const d=tgt-cur;
      let spd=d>0?0.72:0.78;
      const tpm=talentFranchiseRatingsEffect(st,G);
      if(d<0)spd*=tpm.spdLossMult;
      else spd*=tpm.spdGainMult;
      spd=Math.min(0.95,spd);
      const ns=Math.max(0,cur+d*spd);
      st.momDp[sl]={tgt,cur:ns};
      st.rat.dp[sl]={share:Math.round(ns*10000)/10000,aqh:Math.round(stAqh)};
    });
  });
}
/** Derived in-daypart audience share (0–1) from recalc — live estimate before first recalc. */
function daypartListeningShare01(st,sl,G){
  const dp=st.rat?.dp?.[sl];
  if(dp&&typeof dp.share==='number'&&!Number.isNaN(dp.share))return dp.share;
  return daypartDerivedShare01(st,sl,G);
}
/** Per-daypart estimated listening share (0–1) by station id — archived each book for YoY. */
function buildDaypartListeningSharesForStations(stations,G){
  const comm=(stations||[]).filter(s=>s&&!s._bpSlotDeferred&&s.rat&&!stationIsNoncommercialInstitutional(s));
  const out=Object.create(null);
  DAYPART_SLOTS.forEach(sl=>{
    const byId=Object.create(null);
    comm.forEach(st=>{byId[st.id]=daypartListeningShare01(st,sl,G);});
    out[sl]=byId;
  });
  return out;
}
function buildDaypartRankRowsForSlot(sl,G){
  const comm=(G.stations||[]).filter(s=>s&&!s._bpSlotDeferred&&s.rat&&!stationIsNoncommercialInstitutional(s));
  return comm.map(st=>({st,share:daypartListeningShare01(st,sl,G)}))
    .sort((a,b)=>b.share-a.share)
    .map((row,i)=>({st:row.st,share:row.share,rank:i+1}));
}
function rankerHistoryEntryAt(G,year,period){
  const h=G?.rankerHistory;
  if(!h?.length)return null;
  for(let i=h.length-1;i>=0;i--){
    const c=h[i];
    if(Number(c.year)===Number(year)&&Number(c.period)===Number(period))return c;
  }
  return null;
}
function priorYearSameBookEntry(G){
  const snap=G._mktRankBookSnap;
  const y=Number(snap?.year??G.year??1970);
  const p=Number(snap?.period??G.period??1);
  return rankerHistoryEntryAt(G,y-1,p);
}
function formatDaypartYoYHtml(deltaPts,hasPriorBook,priorSh){
  const lbl='<span style="color:var(--mut);letter-spacing:.06em;font-size:11px">TREND FROM LAST YEAR:</span> ';
  if(!hasPriorBook)return lbl+'<span class="mt-dp-yoy" style="color:var(--mut)">—</span>';
  if(priorSh==null)return lbl+'<span class="mt-dp-yoy" style="color:var(--mut)">no daypart archive yet</span>';
  if(deltaPts==null||Math.abs(deltaPts)<0.05)return lbl+'<span class="mt-dp-yoy" style="color:var(--mut)">flat</span>';
  const col=deltaPts>0?'var(--grn)':'var(--red)';
  const dir=deltaPts>0?'Up':'Down';
  const arr=deltaPts>0?'▲':'▼';
  return lbl+`<span class="mt-dp-yoy" style="color:${col}">${arr} ${dir} ${Math.abs(deltaPts).toFixed(1)} pts</span>`;
}
/** Frozen book overall rank + share for one station (matches Ranker table). */
function stationHeadlineRankShare(s,G){
  if(!s||!G)return null;
  const snap=G._mktRankBookSnap;
  if(snap?.rows?.length){
    const sid=String(s.id);
    const hit=snap.rows.find(r=>{
      if(r.key===`s:${sid}`)return true;
      if(r.key.startsWith('p:'))return r.key.split(':').includes(sid);
      if(r.key.startsWith('str:'))return r.key.slice(4)===sid;
      return false;
    });
    if(hit)return{rank:hit.rank,share:hit.share};
  }
  const live=buildMarketRankRowsIncludingStreams(G.stations,G);
  const ix=live.findIndex(r=>marketRankRowContainsStationId(r,s.id));
  if(ix<0)return null;
  return{rank:ix+1,share:live[ix].share};
}
/** Manage Talent: daypart audience estimate — top 5 + share, YoY, your rank if outside top 5. */
function manageTalentDaypartBookBriefingHtml(s,sl,G){
  if(!s||!G||!DAYPART_SLOTS.includes(sl))return'';
  const rows=buildDaypartRankRowsForSlot(sl,G);
  if(!rows.length)return'';
  const myRow=rows.find(r=>r.st.id===s.id);
  const myRank=myRow?myRow.rank:0;
  const myShare=myRow?myRow.share:0;
  const priorEntry=priorYearSameBookEntry(G);
  const priorSh=priorEntry?.daypartShares?.[sl]?.[s.id];
  const hasPrior=!!priorEntry;
  const yoyDelta=priorSh!=null?Math.round((myShare-priorSh)*1000)/10:null;
  const snap=G._mktRankBookSnap;
  const bookY=Number(snap?.year??G.year??1970);
  const bookP=Number(snap?.period??G.period??1);
  const bookLbl=`${bookY} ${PERIODS[bookP-1]||'SPR'}`;
  const headline=stationHeadlineRankShare(s,G);
  const headlineNote=headline
    ?`<p style="margin:0 0 10px 0;font-size:11px;color:var(--off);line-height:1.45">Full-week share (Ranker): <strong style="color:var(--wht)">${shn(headline.share)}%</strong> · <strong style="color:var(--wht)">#${headline.rank}</strong> overall</p>`
    :'';
  const top5=rows.slice(0,5);
  const inTop5=myRank>=1&&myRank<=5;
  const listRows=top5.map(({st,share,rank})=>{
    const isMe=st.id===s.id;
    const host=st.prog?.[sl]?.talent;
    const hostLbl=host?`<span style="color:var(--mut);font-weight:400"> · ${rosterHtmlEsc(host.name)}</span>`:'';
    const callHtml=isMe
      ?`<strong style="color:var(--amb)">${callDisplay(st)}</strong>`
      :`<span style="color:var(--wht)">${callDisplay(st)}</span>`;
    return`<div style="display:flex;align-items:baseline;gap:8px;padding:5px 0;font-size:13px;line-height:1.35;border-bottom:1px solid rgba(255,255,255,.06)">
      <span style="color:var(--mut);font-family:var(--fd);font-size:12px;min-width:1.5em;text-align:right">${rank}</span>
      <span style="flex:1;min-width:0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;color:${mpStationColor(st)}">${callHtml}${hostLbl}</span>
      <span style="color:var(--off);font-family:var(--ft);font-size:13px;white-space:nowrap" title="Estimated share of listeners in this daypart">${shn(share)}%</span>
    </div>`;
  }).join('');
  const youLine=!inTop5&&myRank>0
    ?`<div style="margin-top:10px;padding:8px 10px;background:rgba(245,166,35,.07);border:1px solid rgba(245,166,35,.28);border-radius:6px;font-size:13px;color:var(--off);line-height:1.45">
        <strong style="color:var(--amb)">${callDisplay(s)}</strong> ranks <strong style="color:var(--wht)">#${myRank}</strong> of ${rows.length} · <strong style="color:var(--wht)">${shn(myShare)}%</strong>
      </div>`
    :'';
  const yoyLine=`<div style="margin-top:${youLine?8:10}px;font-size:12px;line-height:1.45">${formatDaypartYoYHtml(yoyDelta,hasPrior,priorSh)}</div>`;
  return`<section class="mt-daypart-ratings" style="margin:0 0 14px 0;padding:12px 14px;border:1px solid rgba(255,255,255,.1);border-radius:8px;background:rgba(0,0,0,.22)">
    <p class="msh" style="margin:0;font-size:12px;letter-spacing:.16em">DAYPART AUDIENCE ESTIMATE — ${SL[sl]}</p>
    <p style="margin:2px 0 6px 0;font-size:11px;color:var(--mut);letter-spacing:.04em">${bookLbl} · ${rows.length} stations · estimated in-daypart share</p>
    ${headlineNote}
    <p style="margin:0 0 10px 0;font-size:10px;color:var(--mut);line-height:1.4;font-style:italic">Derived from latest book AQH, split by programming strength. Daypart shares blend to your full-week Ranker total.</p>
    ${listRows}
    ${youLine}
    ${yoyLine}
  </section>`;
}
function clearCoHostPairingState(sd){
  clearPairingChemistryOnly(sd);
}
/** Bench second-chair only (no `mpIsMe` check). Used by multiplayer apply and {@link benchCoHostIfPresentInternal}. */
function benchSecondChairTalentCore(sid,slot,benchOwnerMpId){
  const s=G.stations.find(st=>st.id===sid);
  if(!s)return false;
  const sd=s.prog?.[slot];
  const b=slotTalentB(sd);
  if(!b)return false;
  ensureTalentBench(G);
  G._benchSeq=(G._benchSeq||0)+1;
  const benchId='b'+G._benchSeq;
  const owner=benchOwnerMpId|0;
  G.talentBench.push({id:benchId,talent:b,_mpOwner:owner,sid,slot});
  setSlotTalentB(sd,null);
  clearPairingChemistryOnly(sd);
  refreshStationOQ(s,G);
  return true;
}
/** Bench second-chair talent only; clears pairing chemistry on the slot. */
function benchCoHostIfPresentInternal(sid,slot){
  const s=G.stations.find(st=>st.id===sid);
  if(!s||!mpIsMe(s))return false;
  const owner=MP.mode==='live'?(s._mpOwner!=null?s._mpOwner:MP.playerId):0;
  return benchSecondChairTalentCore(sid,slot,owner);
}
/**
 * Before replacing the primary host (shuffle, transfer, roster move), bench anyone still in the second chair.
 * Otherwise `setSlotTalentB(sd,null)` deletes them from the game without a bench entry.
 * @returns {string|null} benched talent display name, if any
 */
function benchCoHostBeforePrimaryReplaceOrNull(sid,slot){
  const s=G.stations.find(st=>st.id===sid);
  if(!s)return null;
  const owner=MP.mode==='live'?(s._mpOwner!=null?s._mpOwner:MP.playerId):0;
  const sd=s.prog?.[slot];
  const b=slotTalentB(sd);
  if(!b)return null;
  const nm=b.name||'Co-host';
  return benchSecondChairTalentCore(sid,slot,owner)?nm:null;
}
function initCoHostChemistryReveal(sd,fmt,sl,primary,cohost,chemRoll){
  if(!sd||!primary||!cohost||!chemRoll)return;
  sd._cohostChemActual=chemRoll.actual;
  sd._cohostChemEstimate=chemRoll.estimate;
  const [p,c]=pairingChemTalentOrder(primary,cohost);
  const estPts=Math.round(coHostSlotQualityDeltaPts(p,c,fmt,sl,chemRoll.estimate));
  const actPts=Math.round(coHostSlotQualityDeltaPts(p,c,fmt,sl,chemRoll.actual));
  sd.quality=Math.min(100,Math.max(10,Math.round((sd.quality||20)+estPts)));
  sd._cohostSlotAdjApplied=estPts;
  const d=actPts-estPts;
  if(!d){
    sd._cohostChemRevealStepsLeft=0;
    sd._cohostChemRevealRem=0;
    sd._cohostChemRevealed=true;
  }else{
    sd._cohostChemRevealStepsLeft=COHOST_CHEM_REVEAL_PERIODS;
    sd._cohostChemRevealRem=d;
    sd._cohostChemRevealed=false;
  }
}
function applyCoHostChemistryRevealDecayStep(sd,vtStress){
  if(!sd?.talent||!slotTalentB(sd))return;
  const left=sd._cohostChemRevealStepsLeft|0;
  if(left<1)return;
  const rem=sd._cohostChemRevealRem|0;
  if(!rem)return;
  const vt=Math.max(0,Math.min(1,Number(vtStress)||0));
  const vtK=1-0.065*vt;
  let step=Math.round((rem/left)*vtK);
  if(step===0)step=rem>0?1:(rem<0?-1:0);
  if(step===0)return;
  sd._cohostChemRevealRem=rem-step;
  sd._cohostChemRevealStepsLeft=left-1;
  if(sd._cohostChemRevealStepsLeft===0)sd._cohostChemRevealed=true;
  sd.quality=Math.min(100,Math.max(10,Math.round((sd.quality||20)+step)));
  sd._cohostSlotAdjApplied=(sd._cohostSlotAdjApplied|0)+step;
}
/** Small station-level franchise softening when a revealed co-host pairing is toxic (personality-heavy slots). */
function stationCoHostFranchiseSoftPenalty(s){
  if(!s?.prog)return 0;
  let pen=0;
  DAYPART_SLOTS.forEach(sl=>{
    const sd=s.prog[sl];
    if(!sd?.talent||!slotTalentB(sd))return;
    if(!sd._cohostChemRevealed)return;
    const chem=sd._cohostChemActual;
    if(typeof chem!=='number'||Number.isNaN(chem)||chem>=0)return;
    const str=daypartCoHostModelStrength(sl,s.format);
    if(str<=0)return;
    pen+=-chem*0.042*str;
  });
  return Math.min(0.09,pen);
}
function payrollHalfPeriodForDaypartSlot(sd){
  let row=0;
  if(sd?.talent)row+=Math.round((sd.talent.salary||0)/2);
  const b=slotTalentB(sd);
  if(b)row+=Math.round((b.salary||0)/2);
  return row;
}
/** Sum of host + co-host annual salaries ($/yr), then rounded to nearest $500 (portfolio display / financials). */
function roundTotalAnnualTalentPay500(n){
  n=Number(n);
  if(!Number.isFinite(n))return 0;
  return Math.round(n/500)*500;
}
function sumAnnualTalentPayrollForOwnedStations(ps){
  if(!ps||!ps.length)return 0;
  let tot=0;
  for(let i=0;i<ps.length;i++){
    const s=ps[i];
    if(!s?.prog)continue;
    for(const k of Object.keys(s.prog)){
      const sd=s.prog[k];
      if(!sd)continue;
      if(sd.talent){
        const v=Number(sd.talent.salary);
        if(Number.isFinite(v))tot+=v;
      }
      const b=slotTalentB(sd);
      if(b){
        const v2=Number(b.salary);
        if(Number.isFinite(v2))tot+=v2;
      }
    }
  }
  return roundTotalAnnualTalentPay500(tot);
}
/** Calendar-ish years at current station for co-host comp (periods accrue 2/yr; hire year may be preserved). */
function cohostStationTenureYears(t,G){
  if(!t||!G)return 0;
  const fromPeriods=Math.floor((t.periodsAtStation||0)/2);
  const hy=typeof t._hireYear==='number'&&!Number.isNaN(t._hireYear)?Math.max(0,G.year-t._hireYear):0;
  return Math.max(fromPeriods,hy);
}
/** +1%/yr after year 10, capped +20% (co-host floor only; primary uses a separate curve). */
function cohostFloorTenurePrem01(years){
  if(years<10)return 0;
  return Math.min(0.20,Math.max(0,(years-10)*0.01));
}
function adjustCohostSalaryForRole(t,sl,G){
  if(!t)return;
  const tenureY=cohostStationTenureYears(t,G);
  let mult=0.74;
  if(tenureY>=20)mult=0.95;
  else if(tenureY>=10)mult=0.88;
  const sal0=Number(t.salary)||0;
  t.salary=Math.max(3500,Math.round(sal0*mult/500)*500);
  const tier=talentTrueQuality(t)<42?'entry':talentTrueQuality(t)<68?'mid':'star';
  const mktAdj=G?.marketId||ACTIVE_MARKET;
  const flBoost=1+(marketRankTierOnAirPayMult(mktAdj)-1)*0.58;
  const baseFl=Math.round(salInfl((SAL[sl]?.[tier]?.[0]||5000),G.year)*0.58*flBoost/500)*500;
  if(t.salary<baseFl)t.salary=baseFl;
  const slotBx=Math.round(slotStarMaxBaseForDaypart(sl)*marketRankTierOnAirPayMult(mktAdj));
  const isDrive=sl==='morningDrive'||sl==='afternoonDrive';
  let capMult=1;
  if(isDrive&&tenureY>=20)capMult=1.08;
  else if(isDrive&&tenureY>=10)capMult=1.05;
  const cap=Math.round(salInfl(Math.round(slotBx*0.62*capMult),G.year)/500)*500;
  if(t.salary>cap)t.salary=cap;
  if(tenureY>=10){
    const parts=[`tenY=${tenureY}`,`mult=${mult}`,`capX${capMult}`];
    if(sal0>0&&t.salary>Math.round(sal0*0.74/500)*500)parts.push('above_generic_mult');
    t._cohostCompDebug=parts.join(';');
  }else{
    t._cohostCompDebug=null;
  }
}
function debugCoHostDaypartDiag(s,sl){
  const sd=s?.prog?.[sl];
  const c=slotTalentB(sd);
  if(!sd?.talent||!c){
    console.warn('debugCoHostDaypartDiag: need station id, co-hosted slot',{sid:s?.id,sl});
    return null;
  }
  const fmt=s.format;
  const p=sd.talent;
  const str=daypartCoHostModelStrength(sl,fmt);
  const ep=talentChemEff01(p,fmt);
  const ec=talentChemEff01(c,fmt);
  const est=sd._cohostChemEstimate;
  const act=sd._cohostChemActual;
  const estPts=Math.round(coHostSlotQualityDeltaPts(p,c,fmt,sl,typeof est==='number'?est:0));
  const actPts=Math.round(coHostSlotQualityDeltaPts(p,c,fmt,sl,typeof act==='number'?act:0));
  const slotQ=Math.round(sd.quality||0);
  const tenG=typeof G!=='undefined'&&G?G:null;
  const coTen=tenG?cohostStationTenureYears(c,tenG):null;
  const out={
    slot:sl,call:s.callLetters,format:fmt,modelStrength:Math.round(str*1000)/1000,
    primaryHost:{name:p.name,contrib01:Math.round(ep*1000)/1000},
    coHost:{name:c.name,contrib01:Math.round(ec*1000)/1000,salary:c.salary,tenureStationYrs:coTen,_cohostCompDebug:c._cohostCompDebug||null},
    expectedChemLabel:chemistryEstimateLabel01(typeof est==='number'?est:0),
    expectedChem01:typeof est==='number'?Math.round(est*1000)/1000:null,
    actualChem01:typeof act==='number'?Math.round(act*1000)/1000:null,
    slotDeltaIfEstimatePts:estPts,slotDeltaIfActualPts:actPts,slotQuality:slotQ,
    slotAdjAppliedPts:sd._cohostSlotAdjApplied|0,
    revealStepsLeft:sd._cohostChemRevealStepsLeft|0,revealed:!!sd._cohostChemRevealed,
  };
  console.log('[cohostDiag]',out);
  return out;
}
window.debugCoHostDaypartDiag=function(sid,sl){
  const s=(typeof G!=='undefined'&&G?.stations&&sid)?G.stations.find(st=>st.id===sid):null;
  return debugCoHostDaypartDiag(s,sl);
};
