function normTalentNameKey(name){
  if(!name||typeof name!=='string')return '';
  return name.trim().toLowerCase().replace(/\s+/g,' ');
}
function collectMarketTalentNameKeys(G){
  const usedFirst=new Set();
  const usedFull=new Set();
  const usedLast=new Set();
  if(!G?.stations)return {usedFirst,usedFull,usedLast};
  G.stations.forEach(st=>{
    if(!st.prog)return;
    Object.values(st.prog).forEach(sd=>{
      [sd?.talent,slotTalentB(sd)].forEach(tal=>{
        const raw=tal?.name;
        if(!raw)return;
        const parts=raw.trim().split(/\s+/).filter(Boolean);
        if(!parts.length)return;
        usedFirst.add(parts[0]);
        if(parts.length>=2)usedLast.add(parts[parts.length-1]);
        usedFull.add(normTalentNameKey(raw));
      });
    });
  });
  return {usedFirst,usedFull,usedLast};
}
function buildWeightedFirstPool(fmt,year,marketId,gender){
  const isFemale=gender==='female';
  const yr=year||1970;
  const mkt=(typeof MARKETS!=='undefined'&&MARKETS[marketId])||{};
  const blackPop=typeof mkt.blackPop==='number'?mkt.blackPop:0.35;
  const hispPop1970=mkt.hispPop1970??0.01;
  const hispPop2000=mkt.hispPop2000??0.08;
  const hispPop2020=mkt.hispPop2020??0.115;
  const hispPop=yr<=2000
    ?hispPop1970+Math.max(0,yr-1970)/30*(hispPop2000-hispPop1970)
    :Math.min(hispPop2020,hispPop2000+(yr-2000)/20*(hispPop2020-hispPop2000));
  const isUrbanFmt=['URBAN_CONTEMP','SOUL_RNB','GOSPEL','RHYTHMIC'].includes(fmt);
  const isSpanishFmt=fmt==='SPANISH';
  const isCountryFmt=['COUNTRY','CLASSIC_HITS','CLASSIC_ROCK','ALBUM_ROCK'].includes(fmt);
  const isModernFmt=yr>=1985;
  const isNewsTalkish=TALK_FMTS.includes(fmt)||fmt==='ALL_NEWS';
  const firstClassic=isFemale?NF_WOMEN_70S:NF_CLASSIC;
  const blackPool=isFemale?NF_BLACK_F:NF_BLACK_M;
  const latinoPool=isFemale?NF_LATINO_F:NF_LATINO_M;
  const modernPool=isFemale?NF_MODERN_F:NF_MODERN_M;
  let pool=[];
  const classicWeight=yr<=1985?4:yr<=2000?2:1;
  for(let i=0;i<classicWeight;i++)pool.push(...firstClassic);
  if(isNewsTalkish)for(let i=0;i<3;i++)pool.push(...firstClassic);
  const blackWeight=isUrbanFmt?6:Math.round(blackPop*10);
  for(let i=0;i<blackWeight;i++)pool.push(...blackPool);
  if(yr>=1990&&!isCountryFmt){
    const hispWeight=isSpanishFmt?8:Math.round(hispPop*10);
    for(let i=0;i<hispWeight;i++)pool.push(...latinoPool);
  }
  if(isModernFmt&&!isCountryFmt)pool.push(...modernPool);
  if(['TOP40','ALBUM_ROCK','CLASSIC_ROCK','ALT_ROCK','AAA','HOT_AC'].includes(fmt)&&yr>=1975)pool.push(...NF_HANDLES);
  if(isCountryFmt&&yr<1990)pool=pool.filter(n=>isFemale?NF_WOMEN_70S.includes(n):NF_CLASSIC.includes(n));
  return pool;
}
function buildLastNamePool(region,usedLastBlock){
  const regExtra=NL_REGIONAL[region]||NL_REGIONAL.Southeast;
  let pool=[...NL_BASE,...regExtra];
  if(usedLastBlock?.size){
    const filtered=pool.filter(l=>!usedLastBlock.has(l));
    if(filtered.length)pool=filtered;
  }
  return pool;
}
const gn=(nameCtx)=>{
  const ctx=nameCtx||{};
  const fmt=ctx.fmt;
  const year=ctx.year??((typeof G!=='undefined'&&G?.year)||1970);
  const marketId=(typeof G!=='undefined'&&G?.marketId)||ACTIVE_MARKET||'atlanta';
  const mkt=(typeof MARKETS!=='undefined'&&MARKETS[marketId])||{};
  const region=mkt.region||'Southeast';
  const mk=collectMarketTalentNameKeys(typeof G!=='undefined'?G:null);
  const usedFirst=new Set(mk.usedFirst);
  const usedFull=new Set(mk.usedFull);
  if(ctx.usedFullNames)ctx.usedFullNames.forEach(k=>usedFull.add(k));
  const gender=ctx.gender==='female'?'female':'male';
  const poolFirst=buildWeightedFirstPool(fmt,year,marketId,gender);
  const availFirst=poolFirst.filter(f=>!usedFirst.has(f));
  const poolF=availFirst.length?availFirst:poolFirst;
  const lastPool=buildLastNamePool(region,ctx.usedLastNames);
  const overflow=[...NL_OVERFLOW,...NL_BASE];
  for(let attempt=0;attempt<72;attempt++){
    const first=pick(poolF);
    const last=pick(lastPool);
    const full=`${first} ${last}`;
    const key=normTalentNameKey(full);
    if(!usedFull.has(key)){
      usedFirst.add(first);
      usedFull.add(key);
      if(ctx.usedFullNames)ctx.usedFullNames.add(key);
      return full;
    }
  }
  for(let attempt=0;attempt<48;attempt++){
    const first=pick(poolF);
    const last=pick(overflow);
    const full=`${first} ${last}`;
    const key=normTalentNameKey(full);
    if(!usedFull.has(key)){
      usedFull.add(key);
      if(ctx.usedFullNames)ctx.usedFullNames.add(key);
      return full;
    }
  }
  const fb=`${pick(poolF)} ${pick(lastPool)}`;
  const fbKey=normTalentNameKey(fb);
  if(ctx.usedFullNames)ctx.usedFullNames.add(fbKey);
  return fb;
};
let UC=new Set();
/** During genMarket(), accumulates brand identity keys so rivals don't share slogans (e.g. two "the Beat"). */
let _gbBrandIdTaken=null;
/** Blocked 3-letter suffixes (after W/K) — slurs, sexual/vulgar, KKK, etc. Real-world collisions are OK. */
const CALL_SUFFIX_DENY=new Set([
  'FUK','ASS','SEX','CUM','FAG','TIT','NIG','JEW','SPIC','KKK','POO','PEE','SHT','CNT','DIK','FCK','FGT','BCH','DCK','JIZ','PIS','DYK','WET','JAP','GOK','KKX','KFK','RAP',
]);
function isAcceptableCallSuffix3(x){
  const u=String(x||'').toUpperCase();
  if(u.length!==3)return false;
  if(/K{3}/.test(u))return false;
  if(CALL_SUFFIX_DENY.has(u))return false;
  return true;
}
/** Blocked 2-letter suffixes (after W/K). K+KK → KKK is rejected in isAcceptableCallSuffix2. */
const CALL_SUFFIX2_DENY=new Set([
  'FU','AS','SE','CU','TI','NI','JE','SP','PO','PE','SH','CN','DI','FC','FG','BC','DC','JI','PI','DY','WE','JA','GO','KF','RA',
]);
function isAcceptableCallSuffix2(x,pref){
  const u=String(x||'').toUpperCase();
  if(u.length!==2)return false;
  if(CALL_SUFFIX2_DENY.has(u))return false;
  if(pref==='K'&&u==='KK')return false;
  return true;
}
function randomCallSuffix2(){
  const L='ABCDEFGHIJKLMNOPQRSTUVWXYZ';
  if(typeof crypto!=='undefined'&&crypto.getRandomValues){
    const arr=new Uint8Array(2);
    crypto.getRandomValues(arr);
    return L[arr[0]%26]+L[arr[1]%26];
  }
  return L[Math.floor(Math.random()*26)]+L[Math.floor(Math.random()*26)];
}
/** One per market: old-style 3-character call (W/K + 2 letters), e.g. WLW, KGO — respects market prefix; unique in UC. */
function gcHeritage3Letter(){
  const pref=getCallPrefixForMarket(ACTIVE_MARKET);
  const L='ABCDEFGHIJKLMNOPQRSTUVWXYZ';
  let s,t=0;
  do{
    const x=randomCallSuffix2();
    if(!isAcceptableCallSuffix2(x,pref))continue;
    s=pref+x;
    t++;
  }while((!s||(UC.has(s)||!isAcceptableCallSuffix2(s.slice(1),pref)))&&t<900);
  if(t>=900){
    let found=null;
    outer:for(let i=0;i<26;i++){
      for(let j=0;j<26;j++){
        const x=L[i]+L[j];
        if(!isAcceptableCallSuffix2(x,pref))continue;
        const cand=pref+x;
        if(!UC.has(cand)){found=cand;break outer;}
      }
    }
    s=found||(pref+'ZZ');
  }
  UC.add(s);
  return s;
}
function randomCallSuffix3(){
  const L='ABCDEFGHIJKLMNOPQRSTUVWXYZ';
  if(typeof crypto!=='undefined'&&crypto.getRandomValues){
    const arr=new Uint8Array(3);
    crypto.getRandomValues(arr);
    return L[arr[0]%26]+L[arr[1]%26]+L[arr[2]%26];
  }
  return L[Math.floor(Math.random()*26)]+L[Math.floor(Math.random()*26)]+L[Math.floor(Math.random()*26)];
}
function gc(){
  // Use ACTIVE_MARKET only — during genMarket(), G may still be the previous session; ACTIVE_MARKET is set in startPlay before genMarket.
  const pref=getCallPrefixForMarket(ACTIVE_MARKET);
  const L='ABCDEFGHIJKLMNOPQRSTUVWXYZ';
  let s,t=0;
  do{
    const x=randomCallSuffix3();
    s=pref+x;
    t++;
  }while((UC.has(s)||!isAcceptableCallSuffix3(s.slice(1)))&&t<900);
  if(t>=900){
    let found=null;
    outer:for(let i=0;i<26;i++){
      for(let j=0;j<26;j++){
        for(let k=0;k<26;k++){
          const x=L[i]+L[j]+L[k];
          if(!isAcceptableCallSuffix3(x))continue;
          const cand=pref+x;
          if(!UC.has(cand)){found=cand;break outer;}
        }
      }
    }
    s=found||(pref+'ZZX');
  }
  UC.add(s);
  return s;
}
function gb(f,freq,city,marketId,identityTaken,callLetters){
  const yr=(typeof G!=='undefined'&&G?.year)||1970;
  let p=[...(BRANDS[f]||['{FREQ} Radio'])];
  const mkt=marketId||(typeof G!=='undefined'&&G?.marketId)||ACTIVE_MARKET||'atlanta';
  const c=city||(typeof G!=='undefined'&&G?.city)||MARKETS[mkt]?.label||'Atlanta';
  const taken=identityTaken instanceof Set?identityTaken:(_gbBrandIdTaken instanceof Set?_gbBrandIdTaken:collectMarketBrandIdentityKeys());
  const isAm=/\bAM\s*$/i.test(String(freq||''));
  if(yr<=1979&&isAm&&EARLY_AM_DIAL_BRAND_FORMATS.has(f))p=[...EARLY_AM_DIAL_BRAND_PATTERNS,...p];
  if(yr>=1970&&yr<=1979&&!isAm&&BRANDS_1970S_FM_FORMATS.has(f))p=[...BRANDS_1970S_FM_EXTRA,...p];
  if(f==='NEWS_TALK'&&yr>=1990)p=[...p,...BRANDS_NEWS_TALK_POLITICAL_MODERN];
  if(f==='SPORTS_TALK'&&yr>=1990)p=[...p,...BRANDS_SPORTS_TALK_FAN_MODERN];
  const pool=[...p];
  exoticLettersInCallSign(callLetters).forEach(L=>{
    pool.push(`${L}-{FREQ}`);
    if(yr<=1979&&isAm)pool.push(`${L}-{AMCHOP}`);
  });
  pool.sort(()=>Math.random()-0.5);
  for(let attempt=0;attempt<Math.min(160,pool.length*12);attempt++){
    const raw=pool[attempt%pool.length];
    const resolved=resolveBrand(raw, freq, c, mkt, callLetters);
    if(!resolved)continue;
    const idKey=brandMarketIdentityKey(resolved);
    if(taken.has(idKey))continue;
    taken.add(idKey);
    return resolved;
  }
  const fb=resolveBrand('{FREQ} Radio', freq, c, mkt, callLetters);
  const fk=brandMarketIdentityKey(fb);
  if(!taken.has(fk)){
    taken.add(fk);
    return fb;
  }
  const callBase=stripCallBandSuffix(callLetters)||'';
  const bumped=callBase?`${fb} · ${callBase}`:fb;
  const fk2=brandMarketIdentityKey(bumped);
  if(!taken.has(fk2)){
    taken.add(fk2);
    return bumped;
  }
  return fb;
}
/** Pick a new brand for `s` that doesn't collide with other stations' on-air identities. */
function gbBrandForStationReplace(s,newFmt){
  const taken=collectMarketBrandIdentityKeys(s.id);
  const myKey=brandMarketIdentityKey(s.brand||'');
  // Simulcast receivers copy the source's brand string — same identity key as the partner.
  // Never remove that key from `taken` or gb() will happily "re-pick" the partner's on-air name.
  const othersShareKey=myKey&&(G.stations||[]).some(
    st=>st&&st.id!==s.id&&brandMarketIdentityKey(st.brand||'')===myKey
  );
  if(myKey&&!othersShareKey)taken.delete(myKey);
  return gb(newFmt,s.freq,G?.city,G?.marketId,taken,s.callLetters);
}
const rnd=(a,b)=>Math.random()*(b-a)+a;
const ri=(a,b)=>Math.floor(rnd(a,b+1));
const pick=a=>a[Math.floor(Math.random()*a.length)];
/** Currency for UI — prefers $6.8M / $47.4M / $489K over $47441K for millions. */
const f$=n=>{
  const x=Number(n);
  if(!Number.isFinite(x))return '$—';
  const neg=x<0;
  const v=Math.abs(x);
  const p=neg?'-$':'$';
  if(v<1000)return p+Math.round(v).toLocaleString();
  if(v<1e6){
    const k=v/1000;
    const s=k>=100?String(Math.round(k)):(Math.round(k*10)/10).toFixed(1).replace(/\.0$/,'');
    return p+s+'K';
  }
  if(v<1e9){
    const m=v/1e6;
    const s=m>=100?String(Math.round(m)):(Math.round(m*10)/10).toFixed(1).replace(/\.0$/,'');
    return p+s+'M';
  }
  return p+(Math.round(v/1e7)/100).toFixed(2)+'B';
};
/** Station lineup Pay column — round to nearest $500 before `f$` (annual salary). */
const f$Pd=n=>{
  const x=Number(n);
  if(!Number.isFinite(x))return f$(NaN);
  return f$(Math.round(x/500)*500);
};
const pct=n=>(n*100).toFixed(1)+'%';
/** Share as rating points (no % suffix) — book / cume style display */
const shn=n=>(n*100).toFixed(1);
var _dmbOpenCoh=null;
