var _wlGmFiredToastScheduled=false;
function wlGmSoloFireLocksBoard(){
  if(MP.mode==='live'||!G||!G.sc||!G.sc.gmMode||!G._gm||!G._gm.fired)return false;
  if(typeof wlCampaignHasPendingAssignmentEnd==='function'&&wlCampaignHasPendingAssignmentEnd(G))return false;
  return true;
}
/** After dismissal in GM mode, Next Period must not run — board is frozen until Return to Scenarios. */
function wlGmApplyAdvanceButtonState(){
  if(MP.mode==='live'||!G)return;
  if(typeof wlCampaignScrubPendingEndForNonCareerGame==='function')wlCampaignScrubPendingEndForNonCareerGame(G);
  const btn=document.getElementById('abtn');
  if(!btn)return;
  if(typeof wlCampaignShouldBlockAdvTurn==='function'&&wlCampaignShouldBlockAdvTurn(G)){
    btn.disabled=false;
    btn.textContent='▶ VIEW POSTING REVIEW';
    btn.title='Your assignment ended — open the career review to continue.';
    return;
  }
  btn.title='';
  if(wlGmSoloFireLocksBoard()){
    btn.disabled=true;
    btn.textContent='POSTING ENDED';
    return;
  }
  btn.disabled=false;
  btn.textContent='▶ NEXT PERIOD';
}
function wlCampaignPromptPendingEndModal(msg){
  if(typeof msg==='string'&&msg)showToast(msg,'warn',6400);
  if(typeof wlCampaignEnsureEndModalVisible==='function')wlCampaignEnsureEndModalVisible(G);
}
/** Resume / render: surface dismissal card once if already fired (no assignment summary blocking). */
function wlGmScheduleFiredDismissToastIfNeeded(){
  if(!G||!G._gm||!G._gm.fired)return;
  if(typeof wlCampaignHasPendingAssignmentEnd==='function'&&wlCampaignHasPendingAssignmentEnd(G)){
    if(typeof wlCampaignEnsurePendingEndModalAfterRender==='function')wlCampaignEnsurePendingEndModalAfterRender(G);
    if(typeof wlCampaignEnsureEndModalVisible==='function')wlCampaignEnsureEndModalVisible(G);
    return;
  }
  if(!wlGmSoloFireLocksBoard())return;
  if(document.getElementById('wl-gm-fired-toast-ok'))return;
  if(_wlGmFiredToastScheduled)return;
  _wlGmFiredToastScheduled=true;
  requestAnimationFrame(()=>{
    _wlGmFiredToastScheduled=false;
    if(!wlGmSoloFireLocksBoard())return;
    if(document.getElementById('wl-gm-fired-toast-ok'))return;
    wlShowGmFiredDismissToast(G);
  });
}
var _wlToastSeq=0,_wlToastHoldUntil=0,_wlToastTimer=null;
function showToast(msg,type='info',holdMs){
  const stack=document.getElementById('wl-toast-stack');
  if(!stack)return;
  const ms=Number.isFinite(holdMs)&&holdMs>0?holdMs:3500;
  const el=document.createElement('div');
  el.className='wl-toast wl-toast--'+(type==='warn'?'warn':'info');
  el.setAttribute('role','status');
  el.textContent=msg;
  stack.appendChild(el);
  const cap=5;
  while(stack.children.length>cap)stack.removeChild(stack.firstChild);
  setTimeout(()=>{ try{ stack.removeChild(el);}catch(_e){} },ms);
}
/** Plain-text message plus Account link (HTML) — use only with escaped `msg`. */
function showToastWithSubscribeCta(msg,type,holdMs){
  const stack=document.getElementById('wl-toast-stack');
  if(!stack)return;
  const ms=Number.isFinite(holdMs)&&holdMs>0?holdMs:10000;
  const esc=String(msg||'')
    .replace(/&/g,'&amp;')
    .replace(/</g,'&lt;')
    .replace(/>/g,'&gt;')
    .replace(/"/g,'&quot;');
  const el=document.createElement('div');
  el.className='wl-toast wl-toast--'+(type==='warn'?'warn':'info');
  el.setAttribute('role','status');
  el.innerHTML=
    '<span class="wl-toast-msg" style="display:block">'+esc+'</span>'+
    '<a class="wl-toast-cta" href="/account.html" target="_blank" rel="noopener noreferrer">View plans &amp; subscribe</a>';
  stack.appendChild(el);
  const cap=5;
  while(stack.children.length>cap)stack.removeChild(stack.firstChild);
  setTimeout(()=>{ try{ stack.removeChild(el);}catch(_e){} },ms);
}
/** GM dismissal: rich toast + return to scenario select (solo + campaign paths). */
function wlGmFiredToastEscape(s){
  return String(s||'')
    .replace(/&/g,'&amp;')
    .replace(/</g,'&lt;')
    .replace(/>/g,'&gt;')
    .replace(/"/g,'&quot;');
}
function wlShowGmFiredDismissToast(G){
  const gn=document.getElementById('wl-game-notice');
  if(!gn||typeof G==='undefined'||!G)return;
  const seq=++_wlToastSeq;
  _wlToastHoldUntil=Date.now()+86400000;
  if(_wlToastTimer){clearTimeout(_wlToastTimer);_wlToastTimer=null;}
  gn.hidden=false;
  gn.className='wl-game-notice wl-game-notice--warn';
  let headline='You have been dismissed as General Manager.';
  let detail='Ownership cites sustained underperformance versus formal expectations.';
  try{
    if(typeof wlGmMode!=='undefined'&&wlGmMode&&typeof wlGmMode.getGmDismissalToastCopy==='function'){
      const c=wlGmMode.getGmDismissalToastCopy(G);
      if(c&&c.headline)headline=String(c.headline);
      if(c&&c.detail)detail=String(c.detail);
    }
  }catch(_e){}
  const finish=function(){
    if(seq!==_wlToastSeq)return;
    _wlToastHoldUntil=0;
    gn.hidden=true;
    gn.innerHTML='';
    gn.className='wl-game-notice';
    try{if(typeof wlCampaignDeactivate==='function')wlCampaignDeactivate();}catch(_e){}
    try{
      if(typeof G!=='undefined'&&G){
        delete G.campaignAssignment;
        G.careerCampaign=false;
        delete G._wlGmFiredFromCampaign;
      }
    }catch(_e){}
    try{if(typeof openScenSelect==='function')openScenSelect(typeof getLocalSave==='function'?getLocalSave():null);}catch(_e){}
    try{if(typeof rHdr==='function')rHdr();}catch(_e){}
  };
  gn.innerHTML=
    '<span style="display:flex;flex-wrap:wrap;align-items:flex-start;gap:10px 14px;justify-content:space-between">'+
    '<span style="flex:1;min-width:220px;line-height:1.45;font-size:14px">'+
    '<strong style="display:block;margin-bottom:6px;color:var(--red);letter-spacing:0.04em;font-size:13px">'+
    wlGmFiredToastEscape(headline)+'</strong>'+
    '<span style="color:var(--off)">'+wlGmFiredToastEscape(detail)+'</span>'+
    '</span>'+
    '<button type="button" class="cfm" style="flex-shrink:0;padding:8px 16px;font-size:13px;letter-spacing:1px" id="wl-gm-fired-toast-ok">RETURN TO SCENARIOS</button></span>';
  const btn=document.getElementById('wl-gm-fired-toast-ok');
  if(btn)btn.onclick=function(){finish();};
}
try{globalThis.wlShowGmFiredDismissToast=wlShowGmFiredDismissToast;}catch(_e){}
const qc=q=>q>=68?'good':q>=44?'warn':'poor';
/** Unrounded price index — same phases as salInfl (talent / general nominal levels in-game). */
function salInflMultiplier(year){
  const y=year==null||!Number.isFinite(Number(year))?1970:Number(year);
  const p1=Math.max(0,Math.min(15,y-1970));
  const p2=Math.max(0,Math.min(15,y-1985));
  const p3=Math.max(0,y-2000);
  return 1.0+p1*0.070+p2*0.035+p3*0.015;
}
function salInfl(base,year){
  const m=salInflMultiplier(year);
  return Math.round(base*m/500)*500;
}

function eraTalentMult(year){
  // Early-70s: stronger compression so 1971 top morning Q~85 lands ~$22–26K (not $30K+); 1975+ unchanged from prior curve.
  if(year<=1970) return 0.42;
  if(year<=1971) return 0.48;
  if(year<=1972) return 0.54;
  if(year<=1973) return 0.60;
  if(year<=1974) return 0.70;
  if(year<=1977) return 0.74 + (year-1973)*0.055;
  if(year<=1980) return 0.96 + (year-1977)*0.0133;
  return 1.00;
}

function marketTalentMult(marketId){
  const mkt=MARKETS[marketId||ACTIVE_MARKET]||MARKETS.atlanta;
  const rs=typeof mkt.revScale==='number'?mkt.revScale:1.0;
  return Math.max(0.70, Math.min(1.35, 0.70 + rs*0.30));
}

/** Daypart salary-cap anchors ($ at 1970 scale before salInfl). */
function slotStarMaxBaseForDaypart(sl){
  const m={morningDrive:60000,afternoonDrive:42000,midday:28000,evening:22000,overnight:16000};
  return m[sl]||42000;
}
/**
 * Lifts incumbent / hire anchors in larger metros (orthogonal to revScale → marketTalentMult).
 * Keeps small markets unchanged.
 */
function marketRankTierOnAirPayMult(marketId){
  const rt=(MARKETS[marketId||ACTIVE_MARKET]||MARKETS.atlanta).rankTier||'medium';
  if(rt==='mega')return 1.17;
  if(rt==='large')return 1.12;
  if(rt==='medium')return 1.04;
  return 1.0;
}
/** Lift salary floors on high-share stations so #1 signals in large metros do not drift at entry-tier pay. */
function talentStationSharePayFloorMult(s){
  const sh=Number(s?.rat?.share)||0;
  if(sh>=0.12)return 1.24;
  if(sh>=0.09)return 1.16;
  if(sh>=0.07)return 1.09;
  return 1;
}
/** Fall on-air raise: smooth share ramp + extra lift for mega/large when books are competitive (replaces stepped perfPressure). */
function talentFallPerfPressureFromShare(stShare,marketId){
  const sh=Number(stShare);
  if(!Number.isFinite(sh)||sh<=0)return 0;
  let p=Math.max(0,(sh-0.04)*0.095);
  p=Math.min(0.010,p);
  const rt=(MARKETS[marketId||ACTIVE_MARKET]||MARKETS.atlanta).rankTier||'medium';
  if(sh>=0.068){
    if(rt==='mega')p+=0.0022;
    else if(rt==='large')p+=0.0016;
    else if(rt==='medium')p+=0.0008;
  }
  return Math.min(0.0135,p);
}
/** Fall COLA for on-air talent — slightly faster in top markets post-1985 (consolidation era still lags mega/large reality). */
function talentFallBaseInflationForMarket(year,marketId){
  let b=year<=1980?0.012:year<=1990?0.018:year<=2000?0.015:year<=2010?0.010:0.008;
  if(year>=1985){
    const rt=(MARKETS[marketId||ACTIVE_MARKET]||MARKETS.atlanta).rankTier||'medium';
    if(rt==='mega')b+=0.0018;
    else if(rt==='large')b+=0.0012;
    else if(rt==='medium')b+=0.0006;
  }
  return b;
}
/** Contract renewal demand multiplier — strong #2 books (≈9+) in mega/large land between old 8% and 12% tiers. */
function contractRenewalPerfDemandMult(stShare,marketId){
  const sh=Number(stShare)||0;
  const rt=(MARKETS[marketId||ACTIVE_MARKET]||MARKETS.atlanta).rankTier||'medium';
  const top=rt==='mega'||rt==='large';
  if(sh>0.12)return top?1.34:1.30;
  if(top&&sh>0.095)return 1.26;
  if(sh>0.08)return top?1.22:1.18;
  if(sh>0.05)return 1.10;
  return 1.00;
}

/** 0–1 weight: drive slots get full elite comp; other dayparts get small spill (narrow realism, not global SAL lift). */
function eliteCompDriveSlotStrength(sl){
  if(sl==='morningDrive'||sl==='afternoonDrive')return 1;
  if(sl==='midday')return 0.32;
  if(sl==='evening')return 0.18;
  if(sl==='overnight')return 0.12;
  return 0;
}
/** True when talent merits incumbent cap/floor premium (does not change SAL tables). */
function eliteCompQualifiesForPremium(t,sl){
  if(!t)return false;
  const disp=Math.round(t.quality||0);
  const tq=talentTrueQuality(t);
  const drivePrime=sl==='morningDrive'||sl==='afternoonDrive';
  const rt=(typeof G!=='undefined'&&G)
    ?((MARKETS[G.marketId||ACTIVE_MARKET]||{}).rankTier||'medium')
    :'medium';
  const driveQGate=(rt==='mega'||rt==='large')?88:92;
  if(tq>=90)return true;
  if(t.superstar===true)return true;
  if(drivePrime&&disp>=driveQGate)return true;
  return false;
}
/**
 * Incumbent Fall cap/floor multipliers for elite talent — scaled by drive slot strength, capped +35% on cap.
 * @returns {[number,number]} [capMult, floorMult]
 */
function eliteTalentIncumbentPremiumMults(t,sl,stShare){
  if(!t||!eliteCompQualifiesForPremium(t,sl))return[1,1];
  const str=eliteCompDriveSlotStrength(sl);
  if(str<=0)return[1,1];
  let add=0;
  const tq=talentTrueQuality(t);
  if(tq>=95)add+=0.20;
  else if(tq>=90)add+=0.10;
  if(t.superstar===true)add+=0.10;
  const sh=typeof stShare==='number'&&!Number.isNaN(stShare)?stShare:0;
  const rt=(typeof G!=='undefined'&&G)
    ?((MARKETS[G.marketId||ACTIVE_MARKET]||{}).rankTier||'medium')
    :'medium';
  const topMkt=rt==='mega'||rt==='large';
  if(sh>0.12)add+=0.07;
  else if(topMkt&&sh>0.095)add+=0.054;
  else if(sh>0.08)add+=0.04;
  add=Math.min(0.35,add);
  const capM=1+add*str;
  const floorM=1+Math.min(0.15,add*0.5*str);
  return[capM,floorM];
}
/**
 * Minimum plausible renewal annual ($) for elite drive hosts — anchors extensions without huge mandatory jumps.
 * Uses existing salInfl + marketTalentMult + slot tier band (not new SAL ranges).
 */
function eliteRenewalAnchorAnnual(s,slot,t){
  if(!s||!t||!G)return null;
  const str=eliteCompDriveSlotStrength(slot);
  if(str<0.99||!eliteCompQualifiesForPremium(t,slot))return null;
  const disp=Math.round(t.quality||0);
  const tq=talentTrueQuality(t);
  const tier=disp<42?'entry':disp<68?'mid':'star';
  const band=SAL[slot]?.[tier]||SAL[slot]?.mid||[15000,40000];
  const salPt=tq>=95?band[1]:Math.round((band[0]+band[1])/2);
  let anchor=salInfl(salPt,G.year);
  anchor=Math.round(anchor*marketTalentMult(G.marketId||ACTIVE_MARKET)/500)*500;
  let k=1.06;
  if(tq>=95)k+=0.07;
  else if(tq>=90)k+=0.04;
  if(t.superstar===true)k+=0.05;
  const sh=s.rat?.share||0;
  if(sh>0.12)k+=0.06;
  else if(sh>0.08)k+=0.04;
  const rt=(MARKETS[G.marketId||ACTIVE_MARKET]||{}).rankTier||'medium';
  if((rt==='mega'||rt==='large')&&sh>0.088&&sh<=0.12)k+=0.02;
  return Math.round(anchor*k/500)*500;
}
/** Console diagnostics: `wlEliteCompDiagnostics()` — Fall host cap base vs elite + renewal anchors (year fixed at 1994 for benchmarks). */
function wlEliteCompDiagnostics(){
  const slotStarMaxFor=sl=>({morningDrive:60000,afternoonDrive:42000,midday:28000,evening:22000,overnight:16000})[sl]||42000;
  const mkT=(tq,disp,sup)=>({_trueQuality:tq,quality:disp,superstar:!!sup});
  const tenureCapMult=1.12;
  const y=1994;
  const runCap=(label,mktId,sl,t,share)=>{
    const slotStarMax=slotStarMaxFor(sl);
    const baseCap=Math.round(salInfl(slotStarMax,y)*tenureCapMult/500)*500;
    const [capE,floorE]=eliteTalentIncumbentPremiumMults(t,sl,share);
    return{
      label,
      mkt:mktId,
      slot:sl,
      share,
      tq:talentTrueQuality(t),
      disp:t.quality,
      sup:!!t.superstar,
      capBase:baseCap,
      capElite:Math.round(baseCap*capE/500)*500,
      floorMult:floorE,
    };
  };
  const rows=[
    runCap('Sea AM80','seattle','morningDrive',mkT(80,80,false),0.10),
    runCap('Sea AM90','seattle','morningDrive',mkT(90,90,false),0.10),
    runCap('Sea AM98','seattle','morningDrive',mkT(98,98,false),0.10),
    runCap('Sea AM98*','seattle','morningDrive',mkT(98,98,true),0.10),
    runCap('Sea AM98 sh13','seattle','morningDrive',mkT(98,98,false),0.13),
    runCap('Sea PM98','seattle','afternoonDrive',mkT(98,98,false),0.10),
    runCap('Wic AM98','wichita','morningDrive',mkT(98,98,false),0.10),
    runCap('NY AM98','newyork','morningDrive',mkT(98,98,false),0.10),
  ];
  let renewAnch=[];
  if(typeof G!=='undefined'&&G){
    const pm=G.marketId,py=G.year;
    const sShare={rat:{share:0.10}};
    const anch=[];
    try{
      G.year=y;
      [
        ['seattle',80,false],
        ['seattle',90,false],
        ['seattle',98,false],
        ['seattle',98,true],
        ['wichita',98,false],
        ['newyork',98,false],
      ].forEach(([mkt,q,sup])=>{
        G.marketId=mkt;
        const tal=mkT(q,q,sup);
        anch.push({mkt,slot:'morningDrive',tq:q,superstar:sup,renewAnch:eliteRenewalAnchorAnnual(sShare,'morningDrive',tal)});
      });
      G.marketId='seattle';
      anch.push({mkt:'seattle',slot:'afternoonDrive',tq:98,superstar:false,renewAnch:eliteRenewalAnchorAnnual(sShare,'afternoonDrive',mkT(98,98,false))});
    }finally{
      G.marketId=pm;
      G.year=py;
    }
    renewAnch=anch;
    if(typeof console!=='undefined'&&console.table){
      console.table(rows);
      console.table(anch);
    }
  }else if(typeof console!=='undefined'&&console.table)console.table(rows);
  return{year:y,caps:rows,renewAnch};
}
try{globalThis.wlEliteCompDiagnostics=wlEliteCompDiagnostics;}catch(_e){}

/**
 * 0–1: desirable talent with real negotiating power — used to steepen “short = expensive / long ≠ steal” renewals.
 * Co-hosts get a damped score (second chair has less market leverage than lead).
 */
function talentRenewalLeverage01(s,slot,t,isCoHost){
  if(!s||!t)return 0;
  let v=0;
  const q=Number(t.quality);
  if(Number.isFinite(q))v+=Math.max(0,Math.min(0.26,(q-54)/118));
  const sh=Number(s.rat?.share);
  if(Number.isFinite(sh))v+=Math.max(0,Math.min(0.20,(sh-0.044)/0.088));
  const mktId=(typeof G!=='undefined'&&G?.marketId)||ACTIVE_MARKET||'atlanta';
  const rt=(MARKETS[mktId]||{}).rankTier||'medium';
  if(rt==='mega')v+=0.042;
  else if(rt==='large')v+=0.032;
  else if(rt==='medium')v+=0.014;
  if(t.superstar===true)v+=0.11;
  const mor=Number(t.morale);
  if(Number.isFinite(mor)){
    if(mor>=76)v+=0.07;
    else if(mor<46)v-=0.09;
  }
  if(slot==='morningDrive'||slot==='afternoonDrive')v+=0.055;
  else if(slot==='midday')v+=0.028;
  const tq=talentTrueQuality(t);
  if(tq>=90)v+=0.07;
  else if(tq>=82)v+=0.04;
  if(!isCoHost){
    const rpp=s._rivalPoachPending;
    if(rpp&&rpp.slot===slot&&rpp.talentId===t.id)v+=0.14;
  }
  if(isCoHost)v*=0.74;
  return Math.max(0,Math.min(1,v));
}

/** All-news pay vs music — morning drive in top markets stays competitive (was a flat 0.60 haircut). */
function allNewsSlotPayDiscount(slot,marketId){
  const rt=(MARKETS[marketId||ACTIVE_MARKET]||MARKETS.atlanta).rankTier||'medium';
  const top=rt==='mega'||rt==='large';
  if(slot==='morningDrive')return top?0.86:(rt==='medium'?0.74:0.68);
  if(slot==='afternoonDrive')return top?0.78:0.70;
  if(slot==='midday')return top?0.74:0.66;
  return top?0.70:0.64;
}
/** Free-agent asks scale with the hiring station’s book — leaders pay more for drive talent. */
function stationBookStrengthPayMult(st,slot){
  if(!st||!st.rat)return 1;
  const sh=typeof stationCardDisplayShare01==='function'?stationCardDisplayShare01(st):(Number(st.rat.share)||0);
  if(!Number.isFinite(sh)||sh<=0)return 1;
  let m=1;
  if(sh>=0.14)m+=0.22;
  else if(sh>=0.10)m+=0.15;
  else if(sh>=0.07)m+=0.10;
  else if(sh>=0.05)m+=0.06;
  if((slot==='morningDrive'||slot==='afternoonDrive')&&sh>=0.08)m+=0.05;
  const mid=(typeof G!=='undefined'&&G?.marketId)||ACTIVE_MARKET||'atlanta';
  const rt=(MARKETS[mid]||MARKETS.atlanta).rankTier||'medium';
  if((rt==='mega'||rt==='large')&&sh>=0.09)m+=0.05;
  return Math.min(1.42,m);
}

function mkTal(slot,fmt,tier='mid',year=1970,nameCtx,talOpts){
  talOpts=talOpts||{};
  const isTalkFmt = TALK_FMTS.includes(fmt);
  const isAllNews = fmt === 'ALL_NEWS';
  const marketId=(typeof G!=='undefined'&&G?.marketId)||ACTIVE_MARKET||'atlanta';
  let talkDiscount = isAllNews ? allNewsSlotPayDiscount(slot,marketId)
    : isTalkFmt ? (tier==='star'?0.92:tier==='mid'?0.72:0.62)
    : 1.0;
  // Outside AM drive, spoken-word hosts still anchor dayparts (esp. large-market N/T evenings).
  if(isTalkFmt && !isAllNews && slot !== 'morningDrive'){
    const bump = slot === 'afternoonDrive' ? 0.055 : slot === 'midday' ? 0.045 : slot === 'evening' ? 0.085 : slot === 'overnight' ? 0.05 : 0.04;
    talkDiscount = Math.min(0.95, talkDiscount + bump);
  }

  if(!FM[fmt]||FM[fmt]?.public||FM[fmt]?.institutional)return null;

  const sr=SAL[slot]?.[tier]||[15000,40000],qr=QRG[tier]||QRG.mid;
  const trueQ=Math.round(rnd(qr[0],qr[1]));
  const trueFf={};
  Object.keys(FM).forEach(f=>{
    trueFf[f]=f===fmt?rnd(0.52,0.88):rnd(0.10,0.48);
  });
  let scoutQ=Math.round(trueQ+rnd(-11,11));
  scoutQ=Math.max(18,Math.min(97,scoutQ));
  const scoutFf={};
  Object.keys(trueFf).forEach(f=>{
    const noise=f===fmt?rnd(-0.07,0.07):rnd(-0.11,0.11);
    scoutFf[f]=clampTalentFit01(trueFf[f]+noise);
  });

  const _rawSal = tier==='star'
    ? Math.max(rnd(sr[0],sr[1]), rnd(sr[0],sr[1]))
    : rnd(sr[0],sr[1]);
  const baseSal=Math.round(_rawSal/500)*500;
  const _careerStartYear=Math.max(1950, year-ri(0,28));

  const entryLo=SAL[slot]?.entry?.[0]||5000;
  const starHi=SAL[slot]?.star?.[1]||40000;
  const qNorm=Math.max(0,Math.min(1,trueQ/100));
  const salSpan=starHi-entryLo;
  const salPos=qNorm*qNorm*(3-2*qNorm);
  const qualTarget=Math.round((entryLo+salSpan*salPos)/500)*500;

  let qualAdjSal=Math.round((qualTarget*0.62+baseSal*0.38)/500)*500;

  if(trueQ<80) qualAdjSal=Math.round(qualAdjSal*0.88/500)*500;
  if(year>=1974 && year<=1978 && trueQ<80) qualAdjSal=Math.round(qualAdjSal*0.92/500)*500;

  const bookMult=typeof talOpts.stationBookPayMult==='number'&&!Number.isNaN(talOpts.stationBookPayMult)
    ?Math.max(1,Math.min(1.42,talOpts.stationBookPayMult))
    :1;
  let finalSal=Math.round(
    salInfl(qualAdjSal,year)
    * talkDiscount
    * eraTalentMult(year)
    * marketTalentMult(marketId)
    * bookMult
  /500)*500;
  const radioTenureYrs=Math.max(0,year-_careerStartYear);
  if(radioTenureYrs>=12){
    const tenBoost=1+Math.min(0.09,(radioTenureYrs-11)*0.0035);
    finalSal=Math.round(finalSal*tenBoost/500)*500;
  }

  // Anchor to market on-air pay for this daypart — loose cap so pools don’t collapse to one number;
  // stars may ask further above the average than entry-level candidates.
  if(G?.stations?.length){
    const salz=[];
    for(let i=0;i<G.stations.length;i++){
      const v=G.stations[i]?.prog?.[slot]?.talent?.salary;
      if(typeof v==='number'&&!Number.isNaN(v)) salz.push(v);
    }
    if(salz.length>=3){
      const avg=salz.reduce((a,b)=>a+b,0)/salz.length;
      let capMult=tier==='star'?1.78:tier==='mid'?1.45:1.30;
      if(slot==='evening')capMult+=tier==='star'?0.06:tier==='mid'?0.10:0.08;
      if(bookMult>1.06)capMult*=Math.min(1.32,0.88+bookMult*0.38);
      finalSal=Math.min(finalSal,Math.round(avg*capMult/500)*500);
    }
  }
  const tierSalMult=tier==='star'?1:tier==='mid'?0.93:0.84;
  finalSal=Math.round(finalSal*tierSalMult/500)*500;
  finalSal=Math.round(finalSal*marketRankTierOnAirPayMult(marketId)/500)*500;
  const rk=(MARKETS[marketId||ACTIVE_MARKET]||{}).rankTier||'medium';
  if((rk==='mega'||rk==='large')&&(slot==='afternoonDrive'||slot==='evening'||slot==='midday')){
    finalSal=Math.round(finalSal*1.055/500)*500;
  }

  const gender=Math.random()<0.5?'female':'male';
  const name=gn({...nameCtx,fmt,year,gender});
  if(nameCtx?.usedLastNames){
    const parts=name.trim().split(/\s+/);
    const last=parts[parts.length-1];
    if(last)nameCtx.usedLastNames.add(last);
  }
  if(nameCtx?.usedFullNames)nameCtx.usedFullNames.add(normTalentNameKey(name));

  const tal={
    id:Math.random().toString(36).substr(2,8),
    name,
    gender,
    slot,
    quality:scoutQ,
    _trueQuality:trueQ,
    formatFit:scoutFf,
    _trueFormatFit:trueFf,
    _perfRevealStepsLeft:0,
    _perfRevealDeltaRemaining:0,
    salary:finalSal,
    cyr:ri(1,2),
    morale:Math.round(rnd(55,85)),
    _hireYear:year,
    _careerStartYear,
    _portraitFirstHireYear:year,
    superstar:false
  };
  try{if(typeof wlTalentRetention!=='undefined'&&typeof G!=='undefined'&&G)wlTalentRetention.ensurePersonality(tal,G);}catch(_e){}
  return tal;
}

function shuffleTalentPoolInPlace(pool){
  for(let i=pool.length-1;i>0;i--){
    const j=Math.floor(Math.random()*(i+1));
    const tmp=pool[i];pool[i]=pool[j];pool[j]=tmp;
  }
  return pool;
}

function mkPool(slot,fmt,year,station){
  const nameCtx={usedLastNames:new Set(),usedFullNames:new Set()};
  const pool=[];
  const tiers=['entry','mid','mid',Math.random()<0.22?'star':'mid'];
  const bookMult=station?stationBookStrengthPayMult(station,slot):1;
  for(const tier of tiers){
    const t=mkTal(slot,fmt,tier,year,nameCtx,{stationBookPayMult:bookMult});
    if(t)pool.push(t);
  }
  return shuffleTalentPoolInPlace(pool);
}

/** Cache key for hire/replace free-agent lists — same draw until period advances or a hire/poach lands (no reroll-by-back). */
function wlFreeAgentPoolCacheKey(sid,slot,hireKind){
  return `${sid}\t${G.turn|0}\t${G.year}\t${G.period|0}\t${slot}\t${hireKind}`;
}
/** @param {'hire'|'replace'|'cohost'} hireKind */
function getOrCreateFreeAgentPool(s,slot,hireKind){
  if(!G._wlFaPoolCache)G._wlFaPoolCache={};
  const k=wlFreeAgentPoolCacheKey(s.id,slot,hireKind);
  const ent=G._wlFaPoolCache[k];
  if(Array.isArray(ent)&&ent.length)return ent;
  const pool=mkPool(slot,s.format,G.year,s);
  G._wlFaPoolCache[k]=pool;
  return pool;
}
function invalidateFreeAgentPoolCachesForSlot(sid,slot){
  if(!G._wlFaPoolCache)return;
  const p=`${sid}\t${G.turn|0}\t${G.year}\t${G.period|0}\t${slot}\t`;
  Object.keys(G._wlFaPoolCache).forEach(k=>{
    if(k.startsWith(p))delete G._wlFaPoolCache[k];
  });
}

/** Hire modal only: experience + rough remaining-career band (does not expose retirement triggers). */
function hireTalentCareerLine(t, year){
  const cs=t._careerStartYear;
  if(typeof cs!=='number'||Number.isNaN(cs))return '';
  const exp=Math.max(0, Math.floor(year-cs));
  const softCap=35;
  const rem=Math.max(0, softCap-exp);
  let band;
  if(rem>=22)band='~20–30+ yrs left';
  else if(rem>=15)band='~15–22 yrs left';
  else if(rem>=10)band='~10–15 yrs left';
  else if(rem>=5)band='~5–10 yrs left';
  else if(rem>=1)band='~1–5 yrs left';
  else band='~0–5 yrs left';
  return `<div style="font-size:13px;color:var(--mut);margin-top:2px;line-height:1.25">${exp} yrs experience · <span style="color:var(--off)">${band}</span></div>`;
}

