/** campaignMode.js and other early scripts read market labels via `window.MARKETS` (const MARKETS is not a global var). */
if (typeof window !== 'undefined') window.MARKETS = MARKETS;

// ── AM/FM non-duplication (game-design caps; not literal FCC text) ────────────
/** Map pilot market rankTier → FCC simulcast policy tier (1 = largest / strictest). */
function marketRankTierToFccSimulcastTier(marketId){
  const rt=(MARKETS[marketId||'atlanta']||MARKETS.atlanta).rankTier||'medium';
  if(rt==='mega')return 1;
  if(rt==='large')return 2;
  return 3;
}
/**
 * Max % of FM schedule that may duplicate co-owned AM (0–100).
 * @param {number} year
 * @param {1|2|3} fccTier — from marketRankTierToFccSimulcastTier
 */
function getMaxSimulcastPct(year,fccTier){
  const y=year||1970;
  const t=fccTier<2?1:fccTier>2?3:Math.round(fccTier);
  if(y>=1996)return 100;
  if(y>=1986){
    if(t===1)return 80;
    return 100;
  }
  if(y>=1979){
    if(t===1)return 60;
    if(t===2)return 75;
    return 100;
  }
  if(t===1)return 50;
  if(t===2)return 60;
  return 80;
}
function getMaxSimulcastPctForMarket(year,marketId){
  return getMaxSimulcastPct(year,marketRankTierToFccSimulcastTier(marketId));
}
window.marketRankTierToFccSimulcastTier=marketRankTierToFccSimulcastTier;
window.getMaxSimulcastPct=getMaxSimulcastPct;
window.getMaxSimulcastPctForMarket=getMaxSimulcastPctForMarket;

/** FCC-style call area: W east of Mississippi (in-game), K west — per-market hard rule for gc() / rename */
function getCallPrefixForMarket(marketId){
  const m=MARKETS[marketId||'atlanta']||MARKETS.atlanta;
  return m.callPrefix==='K'?'K':'W';
}
/** Phase 1 pilot markets — single registry (Node: scripts/market-ids.cjs). Order = Nielsen DMA rank (scenario picker). */
const ALL_PLAYABLE_MARKET_IDS=Object.freeze([
  'newyork','losangeles','chicago','sanfrancisco','dallas','houston','atlanta','seattle','phoenix','nashville','wichita',
]);
const PHASE1_MARKET_IDS=ALL_PLAYABLE_MARKET_IDS;
/** Dev/local playtest — MARKETS rows only; never add to ALL_PLAYABLE_MARKET_IDS or billing. */
const DEV_PLAYTEST_MARKET_IDS=Object.freeze([]);
/** Mega markets only — benchmarks, ecology quick mode, mega-scoped FM rules. */
const DEV_BENCHMARK_MEGA_MARKET_IDS=Object.freeze(['newyork','losangeles','chicago']);
/** True on Vite dev (`main.js`) or localhost — unlocks DEV_PLAYTEST_MARKET_IDS in scenario picker. */
function wlIsDevPlayEnvironment(){
  try{
    if(typeof window==='undefined')return false;
    if(window.__WL_DEV_PLAYTEST_MARKETS__===true)return true;
    const h=String(window.location?.hostname||'');
    return h==='localhost'||h==='127.0.0.1';
  }catch(_e){return false;}
}
function wlIsDevPlaytestMarketId(id){
  return DEV_PLAYTEST_MARKET_IDS.includes(String(id||'').trim());
}
/** Scenario picker + solo MP host list (production = PHASE1 only). */
function wlUiMarketIds(){
  if(!wlIsDevPlayEnvironment())return Array.from(PHASE1_MARKET_IDS);
  const extra=DEV_PLAYTEST_MARKET_IDS.filter(id=>MARKETS[id]&&!PHASE1_MARKET_IDS.includes(id));
  return [...PHASE1_MARKET_IDS,...extra];
}
function wlIsPlayableMarketId(id){
  const m=String(id||'').trim();
  if(!m||!MARKETS[m])return false;
  if(PHASE1_MARKET_IDS.includes(m))return true;
  return wlIsDevPlayEnvironment()&&wlIsDevPlaytestMarketId(m);
}
if(typeof window!=='undefined'){
  window.ALL_PLAYABLE_MARKET_IDS=ALL_PLAYABLE_MARKET_IDS;
  window.PHASE1_MARKET_IDS=PHASE1_MARKET_IDS;
  window.DEV_PLAYTEST_MARKET_IDS=DEV_PLAYTEST_MARKET_IDS;
  window.DEV_BENCHMARK_MEGA_MARKET_IDS=DEV_BENCHMARK_MEGA_MARKET_IDS;
  window.wlIsDevPlayEnvironment=wlIsDevPlayEnvironment;
  window.wlUiMarketIds=wlUiMarketIds;
  window.wlIsPlayableMarketId=wlIsPlayableMarketId;
}
/**
 * Plan-only Phase-1 ids (billing). Use for multiplayer host market list — not trial solo commitment.
 */
function wlGetPlanPhase1MarketIds(){
  if(typeof window!=='undefined'&&Array.isArray(window.__WL_PLAN_MARKET_IDS)&&window.__WL_PLAN_MARKET_IDS.length)
    return window.__WL_PLAN_MARKET_IDS;
  return['atlanta'];
}
/**
 * Playable market ids for the current Clerk plan + signup trial solo picker rules.
 * Trial campaign commit → empty (classic solo cannot start a new city); MP uses `wlGetPlanPhase1MarketIds`.
 */
function wlGetAllowedPhase1MarketIds(){
  const base=wlGetPlanPhase1MarketIds();
  try{
    const slug=typeof window!=='undefined'?String(window.__WL_CLERK_PLAN_SLUG||'').trim():'';
    if(slug!=='trial_user')return base;
    const kind=wlTrialLockKind();
    const lock=typeof window!=='undefined'?String(window.__WL_TRIAL_LOCKED_MARKET_ID||'').trim():'';
    if(kind==='solo'&&lock&&wlIsPlayableMarketId(lock))return[lock];
    if(kind==='tutorial')return['atlanta'];
    if(kind==='campaign')return[];
  }catch(_e){}
  if(wlIsDevPlayEnvironment()){
    const out=[...base];
    for(const id of DEV_PLAYTEST_MARKET_IDS){
      if(MARKETS[id]&&!out.includes(id))out.push(id);
    }
    return out;
  }
  return base;
}
if(typeof window!=='undefined')window.wlGetAllowedPhase1MarketIds=wlGetAllowedPhase1MarketIds;
if(typeof window!=='undefined')window.wlGetPlanPhase1MarketIds=wlGetPlanPhase1MarketIds;

/** Pro plan only — keep in sync with server/planMarkets.js and src/billingEntitlements.js */
const WL_PRO_ONLY_MARKET_IDS=Object.freeze(['seattle','sanfrancisco','wichita','phoenix','dallas','houston']);
function wlProOnlyMarketIds(){
  if(typeof window!=='undefined'&&Array.isArray(window.__WL_PRO_ONLY_MARKET_IDS)&&window.__WL_PRO_ONLY_MARKET_IDS.length)
    return window.__WL_PRO_ONLY_MARKET_IDS;
  return WL_PRO_ONLY_MARKET_IDS;
}
function wlIsProOnlyMarketId(id){
  return wlProOnlyMarketIds().includes(String(id||'').trim());
}
function wlMarketPlanLockTitle(marketId,planSlug){
  const id=String(marketId||'').trim();
  const m=MARKETS[id];
  const label=m?.label||id;
  if(id==='sanfrancisco')return 'San Francisco is a Pro market — open Account to upgrade to Pro.';
  if(wlIsProOnlyMarketId(id))return `${label} is a Pro market — open Account to upgrade to Pro.`;
  if(planSlug==='free_user')return 'Upgrade in Account to play markets beyond Atlanta.';
  return 'Upgrade in Account to play this market.';
}
if(typeof window!=='undefined'){
  window.wlIsProOnlyMarketId=wlIsProOnlyMarketId;
  window.wlMarketPlanLockTitle=wlMarketPlanLockTitle;
}

/** Nielsen DMA rank within each size tier (mirrors ALL_PLAYABLE_MARKET_IDS). */
const WL_SCENARIO_PICKER_TIER_ORDER=Object.freeze(['mega','large','medium','small']);
const WL_SCENARIO_PICKER_TIER_LABELS=Object.freeze({
  mega:'Mega markets (#1–3)',
  large:'Large markets',
  medium:'Medium markets',
  small:'Smaller markets',
});
function wlScenarioPickerNielsenRank(id){
  const i=ALL_PLAYABLE_MARKET_IDS.indexOf(String(id||'').trim());
  return i<0?99:i;
}
function wlScenarioPickerMarketsByTier(){
  const byTier=new Map();
  WL_SCENARIO_PICKER_TIER_ORDER.forEach(t=>byTier.set(t,[]));
  const dev=[];
  wlUiMarketIds().forEach(id=>{
    if(wlIsDevPlaytestMarketId(id)&&!PHASE1_MARKET_IDS.includes(id)){dev.push(id);return;}
    const t=(MARKETS[id]||{}).rankTier||'medium';
    const bucket=byTier.has(t)?byTier.get(t):byTier.get('medium');
    bucket.push(id);
  });
  WL_SCENARIO_PICKER_TIER_ORDER.forEach(tier=>{
    const list=byTier.get(tier)||[];
    list.sort((a,b)=>wlScenarioPickerNielsenRank(a)-wlScenarioPickerNielsenRank(b));
  });
  return{byTier,dev};
}
/** Lock label for scenario picker dropdown options not on the current plan. */
function wlScenarioPickerMarketOptionTitle(id,planSlug,allowSet){
  if(allowSet.has(id))return'';
  let lockTitle=wlMarketPlanLockTitle(id,planSlug);
  const _trialLock=typeof window!=='undefined'?String(window.__WL_TRIAL_LOCKED_MARKET_ID||'').trim():'';
  if(planSlug==='trial_user'&&wlTrialLockKind()==='campaign')
    lockTitle='Your free trial is the GM career — resume from Load game or subscribe for classic solo.';
  else if(planSlug==='trial_user'&&_trialLock&&_trialLock!==id)
    lockTitle='Your free trial uses one market — resume that save or subscribe to play other cities.';
  else if(planSlug!=='pro'&&wlIsProOnlyMarketId(id))
    lockTitle=wlMarketPlanLockTitle(id,'starter');
  return lockTitle;
}
function wlScenarioPickerMarketLockSuffix(id,planSlug,allowSet){
  const mId=String(id||'').trim();
  if(allowSet.has(mId))return{suffix:'',locked:false};
  if(wlIsDevPlayEnvironment()&&wlIsDevPlaytestMarketId(mId))return{suffix:'',locked:false};
  if(wlIsProOnlyMarketId(mId))return{suffix:' (PRO ONLY)',locked:true};
  if(planSlug==='free_user')return{suffix:' (STARTER ONLY)',locked:true};
  if(planSlug==='starter')return{suffix:' (PRO ONLY)',locked:true};
  if(planSlug==='trial_user'&&wlTrialLockKind()==='solo'){
    const lock=typeof window!=='undefined'?String(window.__WL_TRIAL_LOCKED_MARKET_ID||'').trim():'';
    if(lock&&lock!==mId&&!wlIsProOnlyMarketId(mId))return{suffix:'',locked:true};
  }
  return{suffix:' (PRO ONLY)',locked:true};
}
function wlScenarioPickerMarketSelectHtml(selectedId,planSlug,allowSet){
  const{byTier,dev}=wlScenarioPickerMarketsByTier();
  let html=`<select id="scen-market-select" class="scen-market-select" aria-label="Choose a market" onchange="pickMarketFromScenarioSelect(this)">`;
  WL_SCENARIO_PICKER_TIER_ORDER.forEach(tier=>{
    const list=byTier.get(tier)||[];
    if(!list.length)return;
    html+=`<optgroup label="${WL_SCENARIO_PICKER_TIER_LABELS[tier]}">`;
    list.forEach(id=>{
      const m=MARKETS[id];
      if(!m)return;
      const{suffix,locked}=wlScenarioPickerMarketLockSuffix(id,planSlug,allowSet);
      const sel=id===selectedId?' selected':'';
      const dis=locked?' disabled':'';
      const tip=wlScenarioPickerMarketOptionTitle(id,planSlug,allowSet);
      const title=tip?` title="${rosterHtmlEsc(tip)}"`:'';
      html+=`<option value="${id}"${sel}${dis}${title}>${m.label}${suffix}</option>`;
    });
    html+=`</optgroup>`;
  });
  if(dev.length){
    html+=`<optgroup label="Dev playtest">`;
    dev.forEach(id=>{
      const m=MARKETS[id];
      if(!m)return;
      const sel=id===selectedId?' selected':'';
      html+=`<option value="${id}"${sel}>${m.label} (DEV)</option>`;
    });
    html+=`</optgroup>`;
  }
  html+=`</select>`;
  return html;
}
function pickMarketFromScenarioSelect(sel){
  const id=String(sel?.value||'').trim();
  if(!id)return;
  const devOk=wlIsDevPlayEnvironment()&&wlIsDevPlaytestMarketId(id);
  if(!wlGetAllowedPhase1MarketIds().includes(id)&&!devOk){
    if(sel&&_selectedMarket)sel.value=_selectedMarket;
    return;
  }
  pickMarketPhase1(id);
}
if(typeof window!=='undefined')window.pickMarketFromScenarioSelect=pickMarketFromScenarioSelect;

/** Multiplayer host market dropdown — options match billing plan (free: Atlanta only; Starter/Pro/trial: full set per planMarkets). */
function wlMpRefreshMarketSelect(){
  try{
    const sel=document.getElementById('mp-market');
    if(!sel)return;
    const allowed=wlGetPlanPhase1MarketIds();
    const allow=new Set(allowed);
    const prev=sel.value;
    sel.innerHTML='';
    const{byTier}=wlScenarioPickerMarketsByTier();
    WL_SCENARIO_PICKER_TIER_ORDER.forEach(tier=>{
      (byTier.get(tier)||[]).forEach(id=>{
        if(!allow.has(id)&&!(wlIsDevPlayEnvironment()&&wlIsDevPlaytestMarketId(id)))return;
        const m=MARKETS[id];
        if(!m)return;
        const opt=document.createElement('option');
        opt.value=id;
        const tierLbl=String(m.rankTier||'').replace(/^./,ch=>ch.toUpperCase());
        opt.textContent=`${m.label} — ${m.region} · ${tierLbl}`;
        sel.appendChild(opt);
      });
    });
    if(allow.has(prev))sel.value=prev;
    else if(allowed.length)sel.value=allowed[0];
    else sel.value='atlanta';
  }catch(_e){}
}
if(typeof window!=='undefined')window.wlMpRefreshMarketSelect=wlMpRefreshMarketSelect;

