function wlAiTrialQuotaToast(data){
  try{
    if(data&&data.code==='trial_quota_exhausted'){
      wlShowTrialCreativeNoticeLimitReached();
      showToastWithSubscribeCta(
        'Trial AI credits are used up — your promotion boost still applies. Subscribe for more generation credits.',
        'warn',
        10400
      );
      return true;
    }
    if(data&&data.code==='guest_quota_exhausted'){
      try{
        if(typeof window.__WL_ANALYTICS_CAPTURE==='function')
          window.__WL_ANALYTICS_CAPTURE('guest_ai_limit_hit',{kind:String(data.kind||'')});
      }catch(_e){}
      showToastWithSubscribeCta(
        'Free guest AI limit reached — create an account or subscribe on Account for more logos, vans, and jingles.',
        'warn',
        10400
      );
      return true;
    }
    if(data&&data.code==='quota_exceeded'){
      try{wlAnalyticsPaywallViewed('ai_limit');}catch(_e){}
      const line=
        typeof data.error==='string'&&data.error.trim()
          ?data.error.trim()
          :'Monthly AI generation limit reached for your plan — upgrade for a higher cap, or try again next month (UTC).';
      showToastWithSubscribeCta(line,'warn',11200);
      return true;
    }
  }catch(_e){}
  return false;
}
/**
 * POST/GET creative endpoints failed — still grant in-game promo benefits for paid van/jingle purchases when quotas are exhausted, monthly caps hit, or the service cannot generate assets (503/5xx/network).
 */
function wlPromotionBenefitEligibleWhenCreativeUnavailable(res,data,feature){
  const d=data&&typeof data==='object'?data:{};
  if(d.code==='plan_unavailable')return false;
  if(res&&res.ok&&d.ok===true)return false;
  if(d.code==='trial_quota_exhausted')return true;
  if(d.code==='guest_quota_exhausted')return true;
  if(d.code==='quota_exceeded'){
    const k=d.kind;
    if(feature==='jingle')return k==='jingle';
    if(feature==='van')return k==='van'||k==='logo';
  }
  if(!res)return false;
  const st=(typeof res.status==='number'&&Number.isFinite(res.status))?res.status:0;
  if(st===503||st===502||st===504)return true;
  if(st>=500&&st<600&&st!==501)return true;
  return false;
}
