      if(isPhoenixDiagMarket(dialCtx.marketId)&&phoenixDiagTierInjectFormatBlocked(cand.fmt))continue;
      if(isPhoenixDiagMarket(dialCtx.marketId)&&phoenixDiagTierInjectRockBlocked(cand.fmt))continue;
