/** After full BP build: trim excess AM 50kW by tier; reassign clear-channel flags to top two survivors. */
function applyMarketTierAmPowerCaps(stations, marketId){
  const cap=am50kwCapForMarket(marketId);
  const am50=[];
  for(let i=0;i<stations.length;i++){
    const s=stations[i];
    if(!s||s._bpSlotDeferred)continue;
    if(s.sig?.type==='AM'&&s.sig.pw==='50kw') am50.push(i);
  }
  const sorted=am50.slice().sort((a,b)=>{
    const pa=AM50_PRIORITY_BP_IDX.indexOf(a), pb=AM50_PRIORITY_BP_IDX.indexOf(b);
    const oa=pa===-1?999:pa, ob=pb===-1?999:pb;
    if(oa!==ob)return oa-ob;
    return a-b;
  });
  const toDowngrade=sorted.slice(cap);
  toDowngrade.forEach((idx,i)=>{
    const newPw=AM50_DOWNGRADE_CHAIN[Math.min(i, AM50_DOWNGRADE_CHAIN.length-1)];
    applyAmPwToStation(stations[idx], newPw);
  });
  // Local/regional frequencies cannot keep inflated power after tier trim (e.g. 10 kW on a local channel).
  applyAmFccPowerNormalization(stations, null);
  reassignAmClearChannelFlags(stations);
}

/**
 * Optional per-market FM dial → ERP tier (game tokens). Keys must match `s.freq` strings.
 * AM uses `window.AMFCC.normalizeAmPw` + optional `amFacilityByFreq` on MARKETS.
 */
function applyMarketDialFacilityOverrides(stations, marketId){
  const m=MARKETS[marketId];
  if(!m)return;
  if(m.amFacilityByFreq){
    const amap=m.amFacilityByFreq;
    const AMFCC=typeof window!=='undefined'?window.AMFCC:null;
    stations.forEach(s=>{
      if(!s||s._bpSlotDeferred||s.fmBooster||s.sig?.type!=='AM')return;
      const pw=amap[s.freq];
      if(pw){
        let use=pw;
        if(AMFCC&&typeof AMFCC.normalizeAmPw==='function')use=AMFCC.normalizeAmPw(s.freq,pw);
        applyAmPwToStation(s,use);
      }
    });
  }
  if(m.fmFacilityByFreq){
    const fmap=m.fmFacilityByFreq;
    stations.forEach(s=>{
      if(!s||s._bpSlotDeferred||s.fmBooster||s.sig?.type!=='FM')return;
      const pw=fmap[s.freq];
      if(pw) applyFmFacilityToStation(s,pw);
    });
  }
}

/** Lower-48 AM frequency ↔ power normalization (loads/saves + post–BP build). */
function applyAmFccPowerNormalization(stations, logCtx){
  const AMFCC=typeof window!=='undefined'?window.AMFCC:null;
  if(!AMFCC||typeof AMFCC.normalizeAmPw!=='function')return;
  stations.forEach(s=>{
    if(!s||s._bpSlotDeferred||s.fmBooster||s.sig?.type!=='AM')return;
    const prev=s.sig.pw;
    const next=AMFCC.normalizeAmPw(s.freq, prev);
    if(next===prev)return;
    applyAmPwToStation(s, next);
    if(logCtx){
      logCtx._amFccAuditLog=logCtx._amFccAuditLog||[];
      logCtx._amFccAuditLog.push({callLetters:s.callLetters,freq:s.freq,from:prev,to:next});
    }
    if(typeof console!=='undefined'&&console.debug) console.debug('[AM FCC]', s.callLetters, s.freq, prev, '→', next);
  });
}

/** Clear-channel universe/revenue bonus only for 50 kW on clear-style dial positions. */
function reassignAmClearChannelFlags(stations){
  const AMFCC=typeof window!=='undefined'?window.AMFCC:null;
  stations.forEach(s=>{ if(s) delete s.clearChannel; });
  const idxs=[];
  stations.forEach((s,i)=>{
    if(!s||s._bpSlotDeferred||s.sig?.type!=='AM'||s.sig.pw!=='50kw')return;
    if(AMFCC&&typeof AMFCC.isClearChannelFreq==='function'){
      if(!AMFCC.isClearChannelFreq(s.freq))return;
    }
    idxs.push(i);
  });
  idxs.sort((a,b)=>{
    const pa=AM50_PRIORITY_BP_IDX.indexOf(a), pb=AM50_PRIORITY_BP_IDX.indexOf(b);
    const oa=pa===-1?999:pa, ob=pb===-1?999:pb;
    if(oa!==ob)return oa-ob;
    return a-b;
  });
  idxs.slice(0,2).forEach(i=>{ if(stations[i]) stations[i].clearChannel=true; });
}

function mkStn(bp,freq,year=1970){
  let{type,fmt,pw,str}=bp;
  if(type==='AM'&&pw==='50kw'&&typeof G!=='undefined'&&G&&G.marketId&&G.stations){
    const cap=am50kwCapForMarket(G.marketId);
    const n=countAm50kwStations(G.stations);
    if(cap<99&&n>=cap){
      pw=AM50_DOWNGRADE_CHAIN[Math.min(n-cap, AM50_DOWNGRADE_CHAIN.length-1)];
    }
  }
  if(type==='AM'&&typeof window!=='undefined'&&window.AMFCC&&typeof window.AMFCC.normalizeAmPw==='function'){
    pw=window.AMFCC.normalizeAmPw(freq,pw);
  }
  const tt=STT[str]||'mid',qb=STQ[str]||[40,60];
  const stId=Math.random().toString(36).substr(2,8);
  const nameCtx={usedLastNames:new Set(),usedFullNames:new Set()};
  // Tier step-down: each slot is one tier weaker than the previous
  // star→mid→entry. Morning leads, afternoon follows, midday is bench depth.
  const afTier=tt==='star'?'mid':tt==='mid'?'entry':'entry';
  const isDa=type==='AM'&&pw==='DA';
  const prog={
    morningDrive:  {talent:mkTal('morningDrive',fmt,tt,year,nameCtx),quality:Math.round(rnd(qb[0],qb[1]))},
    midday:        {talent:fmt!=='BEAUTIFUL_MUSIC'?mkTal('midday',fmt,'entry',year,nameCtx):null,quality:Math.round(rnd(qb[0]-10,qb[1]-10))},
    afternoonDrive:{talent:mkTal('afternoonDrive',fmt,afTier,year,nameCtx),quality:Math.round(rnd(qb[0]-5,qb[1]-5))},
    evening:       isDa
      ? {talent:null,quality:Math.round(rnd(12,22))}
      : {talent:Math.random()>.4?mkTal('evening',fmt,'entry',year,nameCtx):null,quality:Math.round(rnd(qb[0]-15,qb[1]-15))},
    overnight:     {talent:null,quality:Math.round(rnd(isDa?10:15,isDa?22:30))},
  };
  Object.values(prog).forEach(s=>s.quality=Math.max(10,Math.min(100,s.quality)));
  const oq=Math.round(Object.entries(SW).reduce((acc,[sl,w])=>acc+effSlotQForOq(prog[sl])*w,0));
  const reach=type==='AM'?(RA[pw]||.85):(RF[pw]||.70);
  const sb=SBR[str]||[.50,.70];
  const callLetters=gc();
  return{
    id:stId,
    callLetters,freq,brand:gb(fmt,freq,(typeof G!=='undefined'&&G?.city)||MARKETS[ACTIVE_MARKET]?.label||'Atlanta',ACTIVE_MARKET,_gbBrandIdTaken,callLetters),
    sig:{type,pw,reach,universe:UNIVERSE[`${type}_${pw}`]||0.65},
    launchPeriod:0, // set after creation — total periods elapsed at launch
    format:fmt,prog,oq,str,
    rat:{cur:{},hist:[],share:0,aqh:0,margin:type==='AM'?.012:.018},
    ops:{spots:FM[fmt]?.sp||14,sell:rnd(sb[0],sb[1]),promo:0,progBudget:0},
    stream:{active:false,aqh:0,rev:0,upkeep:0,dragOffset:0,launchYear:0},
    digital:(()=>{
      let seed=0; for(let i=0;i<stId.length;i++)seed=((seed*33)|0)+stId.charCodeAt(i);
      return{
        enabled:false,strength:0,trend:0,maturity:0,
        volatilitySeed:(seed>>>0)%1000000007,
        breakoutCooldown:0,lastRev:0,
      };
    })(),
    fin:{rev:0,cost:0,ebitda:0},
    cp:null,mom:{},pers:ap(str),isPlayer:false,color:'#888',flog:[],
    simulcastWith:null, // legacy pair link (migrated to simulcastSourceStationId); kept for save compatibility
    simulcastSourceStationId:null, // programming source id when this leg is a simulcast receiver (star model)
    fmSimulcastDupPct:100, // % of FM clock duplicating co-owned AM (non-dup era); 100 = full simulcast
    fmRemainderFormat:null, // FM-only: format for (100−dup)% when AM/FM non-dup applies
    demoLean:0,         // -1.0 younger .. +1.0 older
    progInvestment:0,   // one-time spend this period
    entryTurn:null,     // {year,period} when entered market (for ranker blanks)
    identity:0,         // 0–100 community identity score; builds slowly, burns fast
    identityBudget:0,   // recurring community investment spend per period
    _formatAge:0,       // periods in current format (resets on format change)
    _identityPeak:0,    // highest identity ever reached (used for betrayal penalty)
    aiArchetype:null,   // rival strategic persona (assigned lazily)
    aiMem:null,
    _aiSnap:null,
    _aiStrategicState:null,
    _aiLastMajorReason:null,
    programmingFocus:PROGRAMMING_FOCUS_BALANCED,
    budgetStress:0,
  };
}

