function soloPlayerCanAffordReentry(G){
  if(MP.mode==='live')return false;
  const minP=soloCheapestAcquisitionPrice(G);
  if(minP==null||!Number.isFinite(minP))return false;
  return (G.cash||0)>=minP;
}

/** MP: sell weakest of several stations — returns true if a sale ran. */
function mpExecuteForcedDistressSale(G,pid,pname){
  const pStns=G.ps.filter(s=>s._mpOwner===pid);
  if(pStns.length<2)return false;
  const weakest=[...pStns].sort((a,b)=>(a.fin?.ebitda||0)-(b.fin?.ebitda||0))[0];
  if(!weakest)return false;
  const lmaOp=stationIsPlayerLmaLesseeOperation(weakest);
  const price=lmaOp?0:distressSaleProceeds(weakest);
  const _soldCall=weakest.callLetters;
  const _oldFreq=weakest.freq;
  const _oldFmt=weakest.format;
  const _oldLbl=fmtLabel(_oldFmt);
  if(!G._playerCash)G._playerCash={};
  if(price>0)G._playerCash[pid]=(G._playerCash[pid]||0)+price;
  if(MP.playerId===pid)G.cash=G._playerCash[pid];
  MP.emit('player_cash_update',{playerId:pid,cash:G._playerCash[pid]});
  breakSimulcast(G,weakest.id);
  normalizeSimulcastLinksInPlace(G);
  weakest.isPlayer=false;
  weakest._mpOwner=undefined;
  weakest.color=weakest.color||'#6b7280';
  clearPlayerLmaLesseeFields(weakest);
  G.ps=G.stations.filter(s=>s.isPlayer);
  aiRebrandStationAfterDistressSale(G,weakest);
  const newLbl=fmtLabel(weakest.format);
  G.news.unshift({v:'HIGH',t:lmaOp
    ?`Still negative: ${pname} forced to end LMA on ${_soldCall} (${_oldFreq}, ${_oldLbl}) — no license sale; operation returned to licensor. Station continues as ${weakest.callLetters} — ${newLbl}, "${weakest.brand}".`
    :`Still negative: distress sale — ${pname}'s ${_soldCall} (${_oldFreq}, ${_oldLbl}) sold for ${f$(price)}. The license continues as ${weakest.callLetters} on ${weakest.freq} — ${newLbl}, "${weakest.brand}".`,y:G.year,p:G.period});
  return true;
}

/** MP: last station, still underwater after grace — remove from play (observer). */
function mpExecuteBankruptcy(G,pid,pname){
  mpEnsureBankruptFlags(G);
  const pStns=G.ps.filter(s=>s._mpOwner===pid);
  pStns.forEach(weakest=>{
    const lmaOp=stationIsPlayerLmaLesseeOperation(weakest);
    const price=lmaOp?0:distressSaleProceeds(weakest);
    const _soldCall=weakest.callLetters;
    const _oldFreq=weakest.freq;
    const _oldFmt=weakest.format;
    const _oldLbl=fmtLabel(_oldFmt);
    if(!G._playerCash)G._playerCash={};
    if(price>0)G._playerCash[pid]=(G._playerCash[pid]||0)+price;
    breakSimulcast(G,weakest.id);
    normalizeSimulcastLinksInPlace(G);
    weakest.isPlayer=false;
    weakest._mpOwner=undefined;
    weakest.color=weakest.color||'#6b7280';
    clearPlayerLmaLesseeFields(weakest);
    G.ps=G.stations.filter(s=>s.isPlayer);
    aiRebrandStationAfterDistressSale(G,weakest);
    const newLbl=fmtLabel(weakest.format);
    G.news.unshift({v:'HIGH',t:lmaOp
      ?`Bankruptcy: ${pname} — LMA on ${_soldCall} (${_oldFreq}, ${_oldLbl}) ended (no sale proceeds). Station continues as ${weakest.callLetters} — ${newLbl}, "${weakest.brand}".`
      :`Bankruptcy: ${pname} — ${_soldCall} (${_oldFreq}, ${_oldLbl}) sold for ${f$(price)}. License continues as ${weakest.callLetters} on ${weakest.freq} — ${newLbl}, "${weakest.brand}".`,y:G.year,p:G.period});
  });
  G._playerCash[pid]=Math.max(0,G._playerCash[pid]||0);
  if(MP.playerId===pid)G.cash=G._playerCash[pid];
  MP.emit('player_cash_update',{playerId:pid,cash:G._playerCash[pid]});
  G._mpBankrupt[pid]=true;
  G._mpDebtWarningQ[pid]=0;
  if(MP.playerId===pid)showToast('Bankruptcy: You are out of active play. You can stay and watch the market.','warn');
}

/** Solo: last station liquidated — observer mode only if you cannot afford any acquisition target. */
function soloExecuteBankruptcy(G){
  const wasSoloBankrupt=!!(G&&G._soloBankrupt);
  const stns=[...G.ps];
  stns.forEach(weakest=>{
    const lmaOp=stationIsPlayerLmaLesseeOperation(weakest);
    const price=lmaOp?0:distressSaleProceeds(weakest);
    const _soldCall=weakest.callLetters;
    const _oldFreq=weakest.freq;
    const _oldFmt=weakest.format;
    const _oldLbl=fmtLabel(_oldFmt);
    if(price>0)G.cash=(G.cash||0)+price;
    breakSimulcast(G,weakest.id);
    normalizeSimulcastLinksInPlace(G);
    weakest.isPlayer=false;
    clearPlayerLmaLesseeFields(weakest);
    G.ps=G.stations.filter(s=>s.isPlayer);
    aiRebrandStationAfterDistressSale(G,weakest);
    const newLbl=fmtLabel(weakest.format);
    G.news.unshift({v:'HIGH',t:lmaOp
      ?`Forced exit: LMA on ${_soldCall} (${_oldFreq}, ${_oldLbl}) ended — no license sale. Station continues as ${weakest.callLetters} on ${weakest.freq} — ${newLbl}, "${weakest.brand}".`
      :`Forced sale: ${_soldCall} (${_oldFreq}, ${_oldLbl}) sold for ${f$(price)}. The license continues as ${weakest.callLetters} on ${weakest.freq} — ${newLbl}, "${weakest.brand}".`,y:G.year,p:G.period});
  });
  G.cash=Math.max(0,G.cash||0);
  G.debtWarningQ=0;
  const canContinue=soloPlayerCanAffordReentry(G);
  G._soloBankrupt=!canContinue;
  if(G._soloBankrupt){
    showToast('Bankruptcy: You are out of active play. You can still advance periods to watch the market.','warn');
    if(!wasSoloBankrupt){ requestAnimationFrame(()=>{ try{wlShowSoloBankruptcyCoach();}catch(_e){} }); }
  }else{
    showToast('Your group has no stations, but you have capital. Use Acquire a Station to get back on the air.','info');
  }
}

// ── PRESSURE ──────────────────────────────────────────────────────
function checkPressure(G){
  const alerts=[];
  if(G.score.isSandbox)return alerts;
  // Warn player if on a format past its sunset — revenue will keep falling
  const fmtSunsets={BEAUTIFUL_MUSIC:1995,MOR:1998};
  (MP.mode==='live' ? G.ps.filter(s=>s._mpOwner===MP.playerId&&!G._mpBankrupt?.[MP.playerId]) : (G._soloBankrupt?[]:G.ps)).forEach(s=>{
    const sunset=fmtSunsets[s.format];
    if(sunset&&G.year>=sunset){
      const yearsOver=G.year-sunset;
      const urgency=yearsOver>=5?'🚨':'⚠';
      alerts.push(`${urgency} ${s.callLetters} (${fmtLabel(s.format)}): This format has been commercially extinct since ${sunset}. Audience appeal is near zero — reformat immediately.`);
    }
  });
  // Solo inspect harnesses: keep the human slot on-air for AI pressure metrics (no autopilot bankruptcy).
  if(MP.mode!=='live'&&typeof window!=='undefined'&&window.__WL_SHARE_INSPECT_ONLY)return alerts;
  if(MP.mode==='live'){
    mpEnsureBankruptFlags(G);
    if(!G._mpDebtWarningQ||typeof G._mpDebtWarningQ!=='object')G._mpDebtWarningQ={};
    const owners=[...new Set(G.ps.map(s=>s._mpOwner).filter(id=>id!==undefined&&id!==null))].sort((a,b)=>a-b);
    owners.forEach(pid=>{
      if(G._mpBankrupt[pid])return;
      const pCash=G._playerCash?.[pid]??0;
      const pStns=G.ps.filter(s=>s._mpOwner===pid);
      const pname=(MP.players||[]).find(p=>p.playerId===pid)?.name||`Player ${pid+1}`;
      if(pCash<0){
        G._mpDebtWarningQ[pid]=(G._mpDebtWarningQ[pid]||0)+1;
        const q=G._mpDebtWarningQ[pid];
        if(q===1){
          alerts.push(`⚠ Distress — ${pname}: cash ${f$(pCash)}. Restore positive cash by next period or face a forced sale.`);
          if(MP.playerId===pid)showToast('You are in distress. Restore positive cash by next period or face a forced sale.','warn');
        }else if(q>=2){
          if(pStns.length>1){
            if(mpExecuteForcedDistressSale(G,pid,pname))G._mpDebtWarningQ[pid]=0;
          }else if(pStns.length===1){
            mpExecuteBankruptcy(G,pid,pname);
            alerts.push(`Bankruptcy: ${pname} is out of active play.`);
          }else{
            if(!G._playerCash)G._playerCash={};
            G._playerCash[pid]=Math.max(0,G._playerCash[pid]||0);
            if(MP.playerId===pid)G.cash=G._playerCash[pid];
            MP.emit('player_cash_update',{playerId:pid,cash:G._playerCash[pid]});
            G._mpDebtWarningQ[pid]=0;
          }
        }
      }else{
        G._mpDebtWarningQ[pid]=0;
      }
    });
    return alerts;
  }

  if(G._soloBankrupt)return alerts;

  const _pressCash=G.cash;
  const _pressMyStns=G.ps;
  const _tier0StarterCampaign=MP.mode!=='live'&&G.campaignAssignment&&((G.campaignAssignment.tier|0)===0);
  const _soloDistressExitQ=_tier0StarterCampaign?5:2;
  /** Tier 0 only: shallow negative cash does not advance solo distress — avoids two half-period dips ending the rung before operating math stabilizes. */
  const _soloDistressCashTrip=_tier0StarterCampaign?-20000:0;
  const _cashCountsSoloDistress=_pressCash<_soloDistressCashTrip;
  if(_cashCountsSoloDistress){
    G.debtWarningQ=(G.debtWarningQ||0)+1;
    if(G.debtWarningQ===1){
      alerts.push(`⚠ Distress: cash ${f$(_pressCash)}. Restore positive cash by next period or face a forced sale.`);
      showToast('You are in distress. Restore positive cash by next period or face a forced sale.','warn');
    }else if(_tier0StarterCampaign&&G.debtWarningQ===2){
      alerts.push(`⚠ Still negative: cash ${f$(_pressCash)}. Corporate gives one more period on your starter posting — restore cash next turn or face a forced exit.`);
      showToast('Still in distress — one more period to restore cash before corporate forces an exit.','warn');
    }else if(_tier0StarterCampaign&&G.debtWarningQ===3){
      alerts.push(`⚠ Deep negative: cash ${f$(_pressCash)}. Starter posting: show a credible path — restore cash or corporate will force an exit.`);
      showToast('Deep cash distress — limited periods remain before forced exit.','warn');
    }else if(_tier0StarterCampaign&&G.debtWarningQ===4){
      alerts.push(`⚠ Sustained deep negative: cash ${f$(_pressCash)}. Last chance on your starter posting — restore cash next period or corporate forces an exit.`);
      showToast('Sustained distress — one more period before forced exit.','warn');
    }else if(G.debtWarningQ>=_soloDistressExitQ){
      const weakest=_pressMyStns.length?[..._pressMyStns].sort((a,b)=>(a.fin?.ebitda||0)-(b.fin?.ebitda||0))[0]:null;
      if(weakest&&_pressMyStns.length>1){
        const lmaOp=stationIsPlayerLmaLesseeOperation(weakest);
        const price=lmaOp?0:distressSaleProceeds(weakest);
        const _soldCall=weakest.callLetters;
        const _oldFreq=weakest.freq;
        const _oldFmt=weakest.format;
        const _oldLbl=fmtLabel(_oldFmt);
        if(price>0)G.cash+=price;
        breakSimulcast(G,weakest.id);
        normalizeSimulcastLinksInPlace(G);
        weakest.isPlayer=false;
        clearPlayerLmaLesseeFields(weakest);
        G.ps=G.stations.filter(s=>s.isPlayer);
        aiRebrandStationAfterDistressSale(G,weakest);
        const newLbl=fmtLabel(weakest.format);
        G.news.unshift({v:'HIGH',t:lmaOp
          ?`Still negative: ended LMA on ${_soldCall} (${_oldFreq}, ${_oldLbl}) — no license sale; operation returned to licensor. Station continues as ${weakest.callLetters} — ${newLbl}, "${weakest.brand}".`
          :`Still negative: distress sale — ${_soldCall} (${_oldFreq}, ${_oldLbl}) sold for ${f$(price)}. License continues as ${weakest.callLetters} on ${weakest.freq} — ${newLbl}, "${weakest.brand}".`,y:G.year,p:G.period});
        G.debtWarningQ=0;
      }else if(_pressMyStns.length===1&&weakest){
        soloExecuteBankruptcy(G);
        alerts.push(G._soloBankrupt?'Bankruptcy: You are out of active play.':'Your last station was sold — use Acquire when you are ready to buy back in.');
      }
    }
  }else{G.debtWarningQ=0;}
  return alerts;
}

/** Light OQ nudge so 1970 opening rankers skew market-plausible; variance from mkStn remains. */
function applyMarketOpeningShape(stations,marketId){
  const m=MARKETS[marketId];
  if(!m)return;
  stations.forEach(s=>{
    if(!s||s._bpSlotDeferred)return;
    let f=1;
    if(s.format==='COUNTRY'){
      if(s.sig?.type==='AM'){
        if(marketId==='nashville')f*=1.09;
        if(marketId==='losangeles')f*=0.84;
        if(marketId==='newyork')f*=0.93;
        if(marketId==='chicago')f*=0.88;
      }else if(s.sig?.type==='FM'){
        if(marketId==='newyork')f*=0.62;
        if(marketId==='losangeles')f*=0.78;
        if(marketId==='chicago')f*=0.85;
        if(marketId==='nashville')f*=1.06;
      }
    }
    if(s.format==='MOR'&&s.sig?.type==='AM'&&(marketId==='newyork'||marketId==='chicago'))f*=1.04;
    if(s.format==='NEWS_TALK'&&s.sig?.type==='AM'&&(marketId==='newyork'||marketId==='chicago'))f*=1.03;
    if(marketId==='newyork'){
      if(['TOP40','ALBUM_ROCK'].includes(s.format)&&s.sig?.type==='FM')f*=1.045;
      if(s.format==='BEAUTIFUL_MUSIC'&&s.sig?.type==='FM')f*=1.04;
      if(s.format==='NEWS_TALK'&&s.sig?.type==='AM')f*=1.035;
    }
    if(marketId==='losangeles'){
      if(['ALBUM_ROCK','TOP40'].includes(s.format)&&s.sig?.type==='FM')f*=1.03;
      if(['SPANISH','URBAN_CONTEMP'].includes(s.format))f*=1.025;
    }
    if(marketId==='chicago'){
      if(['TOP40','ALBUM_ROCK'].includes(s.format)&&s.sig?.type==='FM')f*=1.02;
    }
    if(marketId==='nashville'&&s.format==='COUNTRY'&&s.sig?.type==='FM')f*=1.05;
    if(isPhoenixDiagMarket(marketId)){
      const pf=phoenixDiagOpeningOqMult(s);
      if(pf!==1)f*=pf;
    }
    if(marketId==='dallas'){
      const df=dallasOpeningOqMult(s);
      if(df!==1)f*=df;
    }
    if(f!==1){
      s.oq=Math.round(Math.min(90,Math.max(15,s.oq*f)));
      Object.values(s.prog).forEach(sd=>{if(sd&&sd.quality!=null)sd.quality=Math.round(Math.min(93,sd.quality*Math.sqrt(f)));});
    }
  });
}

/**
 * Modern cold-start only (`startYear` ≥ 2000): modest OQ / identity / talent-franchise lift on
 * 1–2 strongest commercial candidates so mega/large markets open with credible leader concentration.
 * Caller should run this **after** `injectMegaFragmentationThroughPeriod` (when used) so new dial slots
 * participate in the follow-up `seedRat`, then `recalc`. Does not touch public NCE, religious network, or brokered economics.
 */
function applyModernColdStartCommercialIncumbentConcentration(stations,startYear,marketId,mockGCtx){
  const y=Math.round(Number(startYear))||1970;
  if(y<2000||!stations)return;
  const m=MARKETS[marketId||ACTIVE_MARKET]||MARKETS.atlanta;
  const tier=String(m.rankTier||'medium');
  if(tier!=='mega'&&tier!=='large')return;
  const eraRamp=Math.max(0.38,Math.min(1,_smoothstep(2000,2011,y)));
  const want=tier==='mega'?2:1;
  const fmtPri=fmt=>{
    const M={
      TOP40:1,HOT_AC:1,URBAN_CONTEMP:0.98,RHYTHMIC:0.95,COUNTRY:0.96,
      NEWS_TALK:0.94,SPORTS_TALK:0.9,ADULT_CONTEMP:0.96,ALBUM_ROCK:0.88,CLASSIC_ROCK:0.86,
      ALT_ROCK:0.85,AAA:0.85,SPANISH:0.92,PERSONALITY_TALK:0.82,ALL_NEWS:0.88,CLASSIC_HITS:0.8,
      OLDIES:0.72,MOR:0.55,BEAUTIFUL_MUSIC:0.5,ADULT_STANDARDS:0.62,GOSPEL:0.7,
    };
    return M[fmt]??0.64;
  };
  const bumpStrSteps=(s,steps)=>{
    const order=['weak','niche','emerging','moderate','strong','dominant'];
    let ix=order.indexOf(s.str);
    if(ix<0)return;
    for(let u=0;u<steps&&ix<order.length-1;u++){
      ix++;
      s.str=order[ix];
    }
  };
  const Gx=mockGCtx||{year:y,marketId:marketId||ACTIVE_MARKET,adx:1,streamDrag:0,period:1};
  const list=[];
  for(let i=0;i<stations.length;i++){
    const s=stations[i];
    if(!s||s._bpSlotDeferred||stationIsNoncommercialInstitutional(s))continue;
    if(s.isPlayer||s.isZombie||s.isNicheSurvival)continue;
    if(stationBrokeredEconomicsActive(s,Gx))continue;
    if(s.format==='BROKERED_PROGRAMMING')continue;
    if(!FM[s.format])continue;
    const eu=Math.min(1.2,effUniverse(s));
    const mstm=STM[s.str]||{b:0.7};
    const pq=(s.oq/100)*0.34+eu*0.32+fmtPri(s.format)*0.22+(mstm.b||0.7)*0.12;
    list.push({s,pq:pq*eraRamp});
  }
  const cmp=(a,b)=>{
    const d=b.pq-a.pq;
    if(Math.abs(d)>1e-9)return d;
    return String(a.s.id||'').localeCompare(String(b.s.id||''));
  };
  list.sort(cmp);
  const picked=[];
  const addIf=s=>{
    if(!s)return;
    const id=s.id;
    if(picked.some(x=>x.id===id))return;
    picked.push(s);
  };
  if(want===2&&tier==='mega'){
    const mus=list.filter(o=>o.s.sig?.type==='FM'&&!TALK_FMTS.includes(o.s.format));
    const tlk=list.filter(o=>TALK_FMTS.includes(o.s.format));
    mus.sort(cmp);
    tlk.sort(cmp);
    addIf(mus[0]?.s);
    addIf(tlk[0]?.s);
    for(const o of list){
      if(picked.length>=2)break;
      addIf(o.s);
    }
  }else{
    const seen=new Set();
    for(let k=0;k<list.length&&picked.length<want;k++){
      const id=list[k].s.id;
      if(seen.has(id))continue;
      seen.add(id);
      picked.push(list[k].s);
    }
  }
  if(!picked.length)return;
  const qBumpPrimary=Math.round(3+2*eraRamp+(tier==='mega'?2:0));
  const qBumpSecondary=tier==='mega'?Math.max(3,qBumpPrimary-1):Math.max(2,qBumpPrimary-1);
  const idBump=tier==='mega'?Math.round(9+5*eraRamp):Math.round(6+3*eraRamp);
  const frBump=0.042+0.024*eraRamp+(tier==='mega'?0.014:0);
  const dayparts=['morningDrive','afternoonDrive','midday','evening'];
  picked.forEach((s,idx)=>{
    if(tier==='mega'){
      s._modernColdIncumbentSeedW=idx===0?1.28:1.06;
    }else{
      s._modernColdIncumbentSeedW=1.18;
    }
    if(tier==='mega'&&idx===0&&!TALK_FMTS.includes(s.format)){
      s.str='dominant';
    }else if(tier==='large'&&idx===0){
      bumpStrSteps(s,2);
    }else{
      bumpStrSteps(s,tier==='mega'?2:1);
    }
    const qb=idx===0?qBumpPrimary:qBumpSecondary;
    for(const sl of dayparts){
      const sd=s.prog?.[sl];
      if(sd&&sd.quality!=null)sd.quality=Math.min(93,Math.round(sd.quality+qb));
    }
    refreshStationOQ(s,Gx);
    s.identity=Math.min(100,Math.max(0,Math.round((s.identity||0)+idBump*(idx===0?1:0.78))));
    const fr=s.talentFranchise;
    const baseFr=fr==null||!Number.isFinite(fr)?0.88:fr;
    s.talentFranchise=Math.min(0.97,baseFr+frBump*(idx===0?1:0.65));
  });
}

/**
 * Gen-only headline correction after cold `recalc`/`seedRev`: mega/large modern starts sometimes
 * land with PUBLIC_NEWS #1 purely because the commercial leader is a few points too soft.
 * Lifts the top commercial station’s cohort mass modestly (caps), then re-derives AQH headline shares.
 * Does not edit public NCE math, tiers, or appeal formulas.
 */
function nudgeModernColdStartCommercialLeaderHeadline(stations,marketId,startYear,Gctx){
  const y=Math.round(Number(startYear))||1970;
  if(y<2000)return;
  const m=MARKETS[marketId||ACTIVE_MARKET]||MARKETS.atlanta;
  const tier=String(m.rankTier||'');
  if(tier!=='mega'&&tier!=='large')return;
  const news=stations.find(s=>s&&!s._bpSlotDeferred&&s.isPublic&&s.format==='PUBLIC_NEWS');
  const comm=stations.filter(s=>s&&!s._bpSlotDeferred&&!stationIsNoncommercialInstitutional(s)&&!s.isPublic&&s.rat);
  if(!news||comm.length<6)return;
  const nShare=Number(news.rat?.share)||0;
  let lead=null,lShare=0;
  for(const s of comm){
    const sh=Number(s.rat?.share)||0;
    if(sh>lShare){lShare=sh;lead=s;}
  }
  if(!lead||lShare<1e-6)return;
  const eraG=_smoothstep(2000,2014,y);
  const floor=tier==='mega'?0.082+0.007*eraG:0.076+0.005*eraG;
  const ceiling=tier==='mega'?0.115:0.099;
  if(lShare>=floor&&lShare+0.008>=nShare)return;
  const hashSalt='modernColdCommHead|v1';
  const u=(wlHash32(`${hashSalt}|${String(marketId)}|${y}|${lead.callLetters||lead.id}`)>>>0)/4294967296;
  const newsMargin=tier==='mega'?0.011+0.007*eraG:0.007+0.004*eraG;
  const wantBeat=u<(tier==='mega'?0.30:0.16);
  let tgt=Math.min(
    ceiling,
    Math.max(
      floor,
      Math.min(wantBeat?nShare+newsMargin:nShare*0.91,lShare*(tier==='mega'?1.48:1.24)),
    ),
  );
  if(tgt<=lShare*1.015)return;
  const f=tgt/lShare;
  COH.forEach(coh=>{
    const c=lead.rat.cur[coh];
    if(!c)return;
    c.share=Math.min(0.215,Math.round(c.share*f*1e4)/1e4);
    const pop=(POP.cohorts[coh]?.t||0)*effUniverse(lead);
    const engage=AQH_ENGAGE[coh]||0.060;
    c.aqh=Math.round(c.share*pop*engage);
    if(lead.mom[coh]){
      lead.mom[coh].cur=c.share;
      lead.mom[coh].tgt=Math.max(lead.mom[coh].tgt||0,c.share);
    }
  });
  lead.rat.aqh=COH.reduce((sum,c)=>sum+(lead.rat.cur[c]?.aqh||0),0);
  applyListeningHoursShareFromAqh(stations,Gctx||{year:y,marketId,stations});
}

/** Seeded stations + calls for scripted solo tutorial (1970 Atlanta-style BP). */
function applyTutorialTurnaroundPostGen(stations,sc,bpYear){
  if(sc.id!=='tutorial_turnaround'||bpYear!==1970)return;
  const assignRandomCall=st=>{
    if(!st||st._bpSlotDeferred)return;
    UC.delete(st.callLetters);
    st.callLetters=gc();
  };
  sc.idx.forEach(pi=>{
    const st=stations[pi];
    if(!st||st._bpSlotDeferred)return;
    st.str='moderate';
    st.oq=Math.max(38,Math.min(58,Math.round(st.oq*0.76)));
    assignRandomCall(st);
    st.brand=gb(st.format,st.freq,MARKETS[ACTIVE_MARKET]?.label||'Atlanta',ACTIVE_MARKET,_gbBrandIdTaken,st.callLetters);
    Object.values(st.prog||{}).forEach(sd=>{
      if(sd&&sd.quality!=null)sd.quality=Math.round(sd.quality*0.88);
    });
    const p=st.prog||{};
    const tune=(t,q,mor,ac,ar)=>{
      if(!t)return;
      t.quality=q;
      t._trueQuality=q;
      const ff={...t.formatFit}, tf={...t._trueFormatFit};
      ff.MOR=mor;ff.ADULT_CONTEMP=ac;ff.ALBUM_ROCK=ar;
      tf.MOR=mor;tf.ADULT_CONTEMP=ac;tf.ALBUM_ROCK=ar;
      t.formatFit=ff;
      t._trueFormatFit=tf;
    };
    if(p.morningDrive?.talent)tune(p.morningDrive.talent,58,0.78,0.44,0.40);
    if(p.midday?.talent)tune(p.midday.talent,40,0.24,0.22,0.20);
    if(p.afternoonDrive?.talent)tune(p.afternoonDrive.talent,55,0.52,0.40,0.42);
    if(p.evening?.talent)tune(p.evening.talent,54,0.50,0.38,0.42);
    if(p.morningDrive)p.morningDrive.quality=Math.max(10,Math.round(p.morningDrive.quality*0.95));
    if(p.midday)p.midday.quality=Math.max(10,Math.round((p.midday.quality||30)*0.72));
    if(p.afternoonDrive)p.afternoonDrive.quality=Math.max(10,Math.round(p.afternoonDrive.quality*0.92));
    if(p.evening)p.evening.quality=Math.max(10,Math.round(p.evening.quality*0.92));
    refreshStationOQ(st,{year:bpYear});
  });
  const acR=stations[8], rkR=stations[9];
  if(acR&&!acR._bpSlotDeferred){
    assignRandomCall(acR);
    acR.brand=gb(acR.format,acR.freq,MARKETS[ACTIVE_MARKET]?.label||'Atlanta',ACTIVE_MARKET,_gbBrandIdTaken,acR.callLetters);
    acR.str='strong';
    acR.oq=Math.min(88,Math.round(acR.oq+5));
    Object.values(acR.prog||{}).forEach(sd=>{if(sd&&sd.quality!=null)sd.quality=Math.min(93,Math.round(sd.quality+2));});
    refreshStationOQ(acR,{year:bpYear});
  }
  if(rkR&&!rkR._bpSlotDeferred){
    assignRandomCall(rkR);
    rkR.brand=gb(rkR.format,rkR.freq,MARKETS[ACTIVE_MARKET]?.label||'Atlanta',ACTIVE_MARKET,_gbBrandIdTaken,rkR.callLetters);
    rkR.str='strong';
    rkR.oq=Math.min(90,Math.round(rkR.oq+8));
    Object.values(rkR.prog||{}).forEach(sd=>{if(sd&&sd.quality!=null)sd.quality=Math.min(93,Math.round(sd.quality+3));});
    refreshStationOQ(rkR,{year:bpYear});
  }
}

/** Scripted tutorial only: headline share targets (0–1) after coached beats — not used in normal play. */
const WL_TUTORIAL_TURNAROUND_SHARE_BY_TIER=[0.035,0.050,0.062,0.070,0.078];
const WL_TUTORIAL_TURNAROUND_COACHED_FORMATS=new Set(['TOP40','CHR','RHYTHMIC','HOT_AC']);

function wlTutorialTurnaroundRatingsBoostActive(){
  return !!(G&&G.tutorialMode&&G.sc?.id==='tutorial_turnaround'&&MP.mode!=='live'&&(G.tutorialAct|0)<8);
}
function wlTutorialTurnaroundShareTier(){
  return Math.max(0,Math.min(WL_TUTORIAL_TURNAROUND_SHARE_BY_TIER.length-1,G._tutorialShareTier|0));
}
/** Pin player commercial share for tutorial theater; rivals scale down (same math as harness pin). */
function wlTutorialTurnaroundApplyShareBoost(stations,Gctx){
  if(!wlTutorialTurnaroundRatingsBoostActive())return;
  const tier=wlTutorialTurnaroundShareTier();
  const target=WL_TUTORIAL_TURNAROUND_SHARE_BY_TIER[tier];
  if(!(target>0)||typeof applyWlHarnessPlayerSharePin!=='function')return;
  const prev=Gctx._wlHarnessPinPlayerShare;
  Gctx._wlHarnessPinPlayerShare=target;
  applyWlHarnessPlayerSharePin(stations,Gctx);
  if(prev!=null)Gctx._wlHarnessPinPlayerShare=prev;
  else delete Gctx._wlHarnessPinPlayerShare;
}
function wlTutorialTurnaroundOnCoachedFormatFlip(s,oldFmt,newFmt){
  if(!wlTutorialTurnaroundRatingsBoostActive()||!s?.isPlayer)return;
  if(!WL_TUTORIAL_TURNAROUND_COACHED_FORMATS.has(newFmt))return;
  G._tutorialCoachedFormatApplied=true;
  G._tutorialShareTier=Math.max(G._tutorialShareTier|0,1);
}
function wlTutorialTurnaroundOnCoachedTalentHire(s,slot){
  if(!wlTutorialTurnaroundRatingsBoostActive()||!s?.isPlayer||slot!=='midday')return;
  G._tutorialCoachedTalentApplied=true;
  G._tutorialShareTier=Math.max(G._tutorialShareTier|0,2);
  if(typeof recalc==='function'){
    recalc(G.stations,G);
    wlTutorialTurnaroundApplyShareBoost(G.stations,G);
    if(typeof seedRev==='function')seedRev(G.stations,G);
  }
}
function wlTutorialTurnaroundOnAdvTurnForBoost(){
  if(!wlTutorialTurnaroundRatingsBoostActive()||!G._tutorialCoachedTalentApplied)return;
  G._tutorialAdvSinceTalent=(G._tutorialAdvSinceTalent|0)+1;
  if(G._tutorialAdvSinceTalent>=1)G._tutorialShareTier=Math.max(G._tutorialShareTier|0,3);
  if(G._tutorialAdvSinceTalent>=2)G._tutorialShareTier=Math.max(G._tutorialShareTier|0,4);
}

// ── GENERATE MARKET ───────────────────────────────────────────────
function genMarket(scenId){
  UC=new Set();amfIdx=0;fmfIdx=0;
  _gbBrandIdTaken=new Set();
  setNextFreqListsForMarket(ACTIVE_MARKET);
  shuffleFreqListsForNewGame();
  // Resolve scenario first so we can build BP talent at the correct start year
  const sc=scenId?SC.find(s=>s.id===scenId)||pick(SC):pick(SC);
  const bpYear=sc.startYear||1970;
  const startCash=scaledScenarioCash(sc.cash,ACTIVE_MARKET,sc.startYear||1970);
  const scForGame={...sc,cash:startCash};
  const stations=[];
  const dialCtx={stations,marketId:ACTIVE_MARKET};
  const tierDialScaling=tierUsesDialScaling(ACTIVE_MARKET)&&sc.id!=='tutorial_turnaround';
  const commercialTarget=tierDialScaling
    ?tierMarketCommercialTargetForGen(ACTIVE_MARKET,bpYear)
    :19;
  const atlantaDefSet=new Set();
  if(bpYear===1970){
    for(let i=0;i<BP.length;i++){
      if(isBpSlotDeferred1970(i,ACTIVE_MARKET))atlantaDefSet.add(i);
    }
  }
  const playerBpIdxSet=new Set(Array.isArray(sc.idx)?sc.idx:[]);
  const tierTailDef=tierDialScaling
    ?tierMarketBpTailDeferIndices(ACTIVE_MARKET,commercialTarget,atlantaDefSet,playerBpIdxSet)
    :new Set();
  for(let i=0;i<BP.length;i++){
    let eff=effectiveBpForMarket(i,ACTIVE_MARKET,bpYear);
    eff=adjustBlueprintForMarketDial(eff,i,ACTIVE_MARKET,bpYear);
    const freq=nextUnusedCommercialFreq(dialCtx,eff.type);
    if(freq==null){
      const lab=(MARKETS[ACTIVE_MARKET]||{}).label||ACTIVE_MARKET;
      throw new Error(
        `No available ${eff.type} frequency for blueprint slot ${i} in ${lab}. Add entries to amFreqs/fmFreqs or dialBpAmToFm in MARKETS.${ACTIVE_MARKET}.`,
      );
    }
    if((bpYear===1970&&isBpSlotDeferred1970(i,ACTIVE_MARKET))||tierTailDef.has(i))
      stations.push({_bpSlotDeferred:true,_bpIdx:i,_deferFreq:freq});
    else
      stations.push(mkStn(eff,freq,bpYear));
  }
  if(tierDialScaling)injectTierMarketCommercialExtras(stations,dialCtx,bpYear,commercialTarget);
  stations.forEach((s,i)=>{ if(s&&!s._bpSlotDeferred) s.color=CLR[i%CLR.length]; });
  // BP stations are established — mark them mature so recalc
  // uses their full tier b-value, not launchB (which is for new entrants)
  stations.forEach(s=>{ if(s&&!s._bpSlotDeferred) s.launchPeriod=-999; });

  // AM 50kW count by market tier (mega vs large vs medium); excess → 10/5/1kW/DA. Clear-channel on top two survivors.
  applyMarketTierAmPowerCaps(stations,ACTIVE_MARKET);
  applyMarketDialFacilityOverrides(stations,ACTIVE_MARKET);

  applyMarketOpeningShape(stations,ACTIVE_MARKET);

  sc.idx.forEach((i,pi)=>{if(stations[i]&&!stations[i]._bpSlotDeferred){stations[i].isPlayer=true;
    const oqAdj=sc.oqBoost||0;
    if(sc.heritageIncumbent){
      stations[i].oq=Math.max(66,Math.min(88,stations[i].oq-ri(2,8)+oqAdj));
    }else{
      const base=Math.max(28,stations[i].oq-ri(8,18));
      stations[i].oq=Math.max(15,Math.min(85,base+oqAdj));
    }
    const hqBonus=sc.heritageIncumbent?3:0;
    Object.values(stations[i].prog).forEach(sd=>{if(sd)sd.quality=Math.max(12,Math.min(90,(sd.quality||30)+oqAdj*0.6+hqBonus));});
    stations[i].color='#f5a623';}});
  // Underdog: morning drive is empty — the scenario says the host just quit
  if(sc.id==='under'||sc.id==='gm_under'){
    sc.idx.forEach(i=>{
      const st=stations[i];
      if(!st||st._bpSlotDeferred||!st.isPlayer)return;
      const md=st.prog?.morningDrive;
      if(md){
        md.talent=null;
        md.quality=Math.max(12,Math.round((md.quality||30)*0.52));
      }
      refreshStationOQ(st,{year:bpYear});
    });
  }
  // One old-style 3-letter call (W/K + 2 letters) on the dominant-heritage AM slot (BP idx 4 first); same K/W rule as gc(); only one per market.
  (function applyMarketHeritageSlot(){
    const preferAmIdx=[4,0,2,5,1,10,3,13,6,11,12,17];
    for(const i of preferAmIdx){
      const st=stations[i];
      if(!st||st._bpSlotDeferred||st.sig?.type!=='AM')continue;
      UC.delete(st.callLetters);
      st.callLetters=gcHeritage3Letter();
      return;
    }
    for(let i=0;i<stations.length;i++){
      const st=stations[i];
      if(!st||st._bpSlotDeferred)continue;
      UC.delete(st.callLetters);
      st.callLetters=gcHeritage3Letter();
      return;
    }
  })();
  applyTutorialTurnaroundPostGen(stations,sc,bpYear);
  // Validate FCC: stack scenario has 1AM+1FM which is legal; others have 1 station
  // ── PUBLIC RADIO STATIONS (injected 1975+, always present) ──
  // WABE-style public news/talk and WCLK-style public classical
  // These are permanent fixtures — not on the Rival Board, not purchasable
  // Build public stations manually — skips mkStn/mkTal which expects commercial formats
  function mkPub(cl,freq,fmt,pw,reach,brand,oq,launchYear,color){
    const p={};Object.keys(SL).forEach(k=>{p[k]=null;});
    const m={};COH.forEach(c=>{m[c]={tgt:0.01,cur:0.01};});
    return{
      id:Math.random().toString(36).substr(2,8),
      callLetters:cl,freq,brand,format:fmt,oq,color,
      sig:{type:'FM',pw,reach,universe:reach*0.7},
      str:'moderate',launchPeriod:0,
      rat:{cur:{},hist:[],share:0,aqh:0,margin:0.018},
      ops:{spots:0,sell:0,promo:0,progBudget:0},
      stream:{active:false,aqh:0,rev:0,upkeep:0,dragOffset:0,launchYear:0},
      fin:{rev:0,cost:0,ebitda:0},
      cp:null,mom:m,prog:p,pers:PD.PUBLIC,
      isPlayer:false,isPublic:true,
      _pubLaunchYear:launchYear,
      simulcastWith:null,simulcastSourceStationId:null,demoLean:0,progInvestment:0,entryTurn:null,_history:[],
      drift:{},flog:[],
    };
  }
  const _pubCity=MARKETS[ACTIVE_MARKET]?.label||'Atlanta';
  const _pubClNews=gc(),_pubClClass=gc(),_pubClEclectic=gc(),_pubClJazz=gc();
  const pubNews=mkPub(_pubClNews,'88.5 FM','PUBLIC_NEWS','50kw',0.92,gb('PUBLIC_NEWS','88.5 FM',_pubCity,ACTIVE_MARKET,_gbBrandIdTaken,_pubClNews),72,1975,'#94a3b8');
  const pubClass=mkPub(_pubClClass,'90.1 FM','PUBLIC_CLASSICAL','25kw',0.78,gb('PUBLIC_CLASSICAL','90.1 FM',_pubCity,ACTIVE_MARKET,_gbBrandIdTaken,_pubClClass),68,1979,'#7c8fa8');
  stations.push(pubNews,pubClass);
  const startYear=sc.startYear||1970;
  assignPublicNceTierToStation(pubNews,ACTIVE_MARKET,startYear);
  assignPublicNceTierToStation(pubClass,ACTIVE_MARKET,startYear);
  const pubExp=computePublicExpansionFormatsAfterBase(ACTIVE_MARKET,startYear);
  for(let exi=0;exi<pubExp.length;exi++){
    const exFmt=pubExp[exi];
    if(stations.some(s=>s&&!s._bpSlotDeferred&&s.isPublic&&s.format===exFmt))continue;
    const fe=nextUnusedCommercialFreq({stations,marketId:ACTIVE_MARKET},'FM');
    if(!fe)continue;
    const callEx=exFmt==='PUBLIC_ECLECTIC'?_pubClEclectic:_pubClJazz;
    const launchEx=exFmt==='PUBLIC_ECLECTIC'?Math.max(1991,Math.round(Number(startYear))||1970):Math.max(1988,Math.round(Number(startYear))||1970);
    const reachEx=exFmt==='PUBLIC_ECLECTIC'?0.82:0.76;
    const oqEx=exFmt==='PUBLIC_ECLECTIC'?70:69;
    const colEx=exFmt==='PUBLIC_ECLECTIC'?'#6b8cae':'#5b7fa4';
    const pubX=mkPub(callEx,fe,exFmt,'25kw',reachEx,gb(exFmt,fe,_pubCity,ACTIVE_MARKET,_gbBrandIdTaken,callEx),oqEx,launchEx,colEx);
    stations.push(pubX);
    assignPublicNceTierToStation(pubX,ACTIVE_MARKET,startYear);
  }
  const genMarketRelNetNews=[];
  injectReligiousNetworkAtMarketGenIfDue(stations,dialCtx,startYear,genMarketRelNetNews);
  seedRat(stations,1970);

  stations.forEach(s=>{
    if(s&&!s._bpSlotDeferred&&s.isPlayer)applyDefaultBrandToPlayerStation(s);
  });

  // For non-1970 starts: inject rivals that would have launched between 1970 and startYear.
  // Events with rival- in their effect string add stations; pre-apply them to the market.
  if(startYear>1970){
    const preEvents=EVDATA.filter(ev=>ev.y<startYear&&ev.e&&ev.e.includes('rival-'));
    preEvents.forEach(ev=>{
      ev.e.split('|').filter(p=>p.startsWith('rival-')).forEach(part=>{
        const [,fmt,type,pw,str]=part.split('-');
        let mechFmt=canonicalHitsFormatKey(fmt);
        if(!mechFmt||!FM[mechFmt])return;
        const mktId=ACTIVE_MARKET;
        if(marketUrbanRhythmicPlausibilityBlocked(mktId)&&SMALL_MARKET_URBAN_RHYTHM_FMTS.includes(mechFmt))
          mechFmt=marketUrbanRhythmicSubstituteFmt(mktId,startYear,type);
        if(!formatAllowedInMarket(mechFmt,mktId,startYear))return;
        // Don't add if this format is already represented in market
        const already=stations.some(s=>s&&!s._bpSlotDeferred&&s.format===mechFmt&&!s.isPlayer);
        if(already)return;
        const freq=nextUnusedCommercialFreq({stations,marketId:ACTIVE_MARKET},type);
        if(!freq)return;
        const ns=mkStn({type,fmt:mechFmt,pw,str},freq,startYear);
        ns.color=CLR[stations.length%CLR.length];
        ns.launchPeriod=-999; // treat as established
        stations.push(ns);
      });
    });

    // Pre-apply format sunsets/purges
    const sunsetEvs=EVDATA.filter(ev=>ev.y<startYear&&ev.e&&(ev.e.includes('fmt_sunset')||ev.e.includes('fmt_purge')));
    sunsetEvs.forEach(ev=>{
      ev.e.split('|').forEach(part=>{
        if(part.startsWith('fmt_sunset:')){
          const [,deadFmt,pivot]=part.split(':');
          // Distribute dead-format rivals across realistic successors, not just one pivot
          const MOR_SUCCESSORS=['NEWS_TALK','ADULT_CONTEMP','ADULT_STANDARDS','BEAUTIFUL_MUSIC'];
          const BEAUTIFUL_SUCCESSORS=['ADULT_CONTEMP','HOT_AC','ADULT_STANDARDS'];
          const successors=deadFmt==='MOR'?MOR_SUCCESSORS:deadFmt==='BEAUTIFUL_MUSIC'?BEAUTIFUL_SUCCESSORS:[pivot];
          stations.filter(s=>s&&!s._bpSlotDeferred&&!s.isPlayer&&s.format===deadFmt).forEach((s,i)=>{
            // Cycle through successors so rivals spread across formats naturally
            const target=successors[i%successors.length];
            if(target&&FM[target]){
              s.format=target;
              const taken=collectBrandIdentityKeysFromStationList(stations,s.id);
              taken.delete(brandMarketIdentityKey(s.brand||''));
              s.brand=gb(target,s.freq,MARKETS[ACTIVE_MARKET]?.label||'Atlanta',ACTIVE_MARKET,taken,s.callLetters);
              if(!s.drift)s.drift={};
              s.drift[target]=DRIFT?.[target]?.default||40;
            }
          });
        } else if(part.startsWith('fmt_purge:')){
          const deadFmt=part.split(':')[1];
          // Remove dead-format stations (replace with market-appropriate alternatives)
          stations.forEach(s=>{if(s&&!s._bpSlotDeferred&&!s.isPlayer&&s.format===deadFmt)s.format='NEWS_TALK';});
        }
      });
    });

    applyMarketDialFacilityOverrides(stations,ACTIVE_MARKET);

    // Pre-apply FCC expansion
    const fccEvs=EVDATA.filter(ev=>ev.y<=startYear&&ev.e&&ev.e.startsWith('fcc-'));
    let fccAM=1,fccFM=1;
    fccEvs.forEach(ev=>{
      const yr=parseInt(ev.e.split('-')[1]);
      if(yr<=1992){fccAM=2;fccFM=2;}
      if(yr<=1994){fccAM=3;fccFM=3;}
      if(yr<=1996){fccAM=8;fccFM=8;}
    });

    // Pre-apply adx changes from events before startYear
    let adxMod=1.0;
    EVDATA.filter(ev=>ev.y<startYear&&ev.e&&(ev.e.startsWith('ad+')||ev.e.startsWith('ad-'))).forEach(ev=>{
      const delta=parseFloat(ev.e.replace('ad',''));
      adxMod=Math.max(0.5,Math.min(2.0,adxMod*(1+delta)));
    });

    seedRat(stations, startYear);

    const mockG2={adx:adxMod,streamDrag:0,year:startYear};
    seedRev(stations,mockG2);
    const activeMkt2=MARKETS[ACTIVE_MARKET]||MARKETS.atlanta;
    const finalAdx=adxMod*(1.0+activeMkt2.adxBonus);
    const finalStream=Math.min(.60,EVDATA.filter(ev=>ev.e==='stream+'&&ev.y<startYear).length*0.06);
    const fragShell={
      stations,marketId:ACTIVE_MARKET,year:startYear,period:1,
      turn:(startYear-1970)*2,adx:finalAdx,streamDrag:finalStream,
      ps:stations.filter(s=>s&&s.isPlayer),
      news:[],
      _megaFragmentationQueue:isMegaMarketId(ACTIVE_MARKET)
        ?megaFragmentationQueueRemainingAfterStart(startYear,1)
        :[],
      _megaFragmentationAdded:0,
      _spanishLaunchesQueue:spanishLaunchesQueueRemainingAfterStart(startYear,1,ACTIVE_MARKET),
      _fragmentationLaunchesQueue:fragmentationLaunchesQueueRemainingAfterStart(startYear,1,ACTIVE_MARKET),
    };
    injectMegaFragmentationThroughPeriod(fragShell,startYear,1);
    injectMarketSpanishLaunchesThroughPeriod(fragShell,startYear,1);
    injectMarketFragmentationLaunchesThroughPeriod(fragShell,startYear,1);
    applyModernColdStartCommercialIncumbentConcentration(stations,startYear,ACTIVE_MARKET,{
      year:startYear,
      marketId:ACTIVE_MARKET,
      adx:finalAdx,
      streamDrag:finalStream,
      period:1,
    });
    seedRat(stations, startYear);
    const mockGRecalc={
      stations,marketId:ACTIVE_MARKET,year:startYear,period:1,turn:fragShell.turn,
      adx:finalAdx,streamDrag:finalStream,satDrag:0,
      fmp:effectiveFmpForMarket(startYear,ACTIVE_MARKET),
      ps:fragShell.ps,
      _modernColdStartIncumbentRecalc:true,
    };
    recalc(stations,mockGRecalc);
    seedRev(stations,mockGRecalc);
    nudgeModernColdStartCommercialLeaderHeadline(stations,ACTIVE_MARKET,startYear,mockGRecalc);
    stations.forEach(s=>{if(s)delete s._modernColdIncumbentSeedW;});
    delete mockGRecalc._modernColdStartIncumbentRecalc;
    // Filter out events that already happened
    const remainingEvq=EVDATA.filter(ev=>ev.y>startYear||(ev.y===startYear&&ev.p===2));
    _gbBrandIdTaken=null;
    const campaignOpening={
      v:'LOW',
      t:`Campaign begins — ${activeMkt2.label} radio, ${startYear}. ${sc.d.split('.')[0]}.`,
      y:startYear,
      p:1,
    };
    const fragNewsTail=
      fragShell.news && fragShell.news.length ? fragShell.news.slice().reverse() : [];
    initIndieLicenseeKeysFromStations(stations,{marketId:ACTIVE_MARKET});
    return{
      city:activeMkt2.label,marketId:ACTIVE_MARKET,year:startYear,period:1,
      turn:(startYear-1970)*2,
      _scenarioAnchorYear:bpYear,
      stations,ps:stations.filter(s=>s&&s.isPlayer),
      sc:scForGame,cash:startCash,
      fmp:effectiveFmpForMarket(startYear,ACTIVE_MARKET),adx:finalAdx,satDrag:0,
      streamDrag:finalStream,
      fccAM,fccFM,
      unlockedFormats:Object.keys(FM).filter(f=>formatAllowedInMarket(f,ACTIVE_MARKET,startYear)),
      news:[campaignOpening,...genMarketRelNetNews,...fragNewsTail],
      evq:remainingEvq,
      score:{shareHistory:[],peakRevenue:0,decadeScores:{},isSandbox:false},
      rankerHistory:[],
      finHistory:[],
      _playerFinHistory:{},
      stationFinHistory:{},
      debtWarningQ:0,
      loans:[],
      talentBench:[],
      _atl1970DeferredQueue:[],
      _megaFragmentationQueue:fragShell._megaFragmentationQueue||[],
      _megaFragmentationAdded:fragShell._megaFragmentationAdded||0,
      _spanishLaunchesQueue:fragShell._spanishLaunchesQueue||[],
      _fragmentationLaunchesQueue:fragShell._fragmentationLaunchesQueue||[],
      sportsRights:{},franchiseRights:{},teamRecords:{},
    };
  }
  _gbBrandIdTaken=null;

  const mockG={adx:1.0,streamDrag:0,year:1970};
  seedRev(stations,mockG);
  const activeMkt=MARKETS[ACTIVE_MARKET]||MARKETS.atlanta;
  initIndieLicenseeKeysFromStations(stations,{marketId:ACTIVE_MARKET});
  return{
    city:activeMkt.label,marketId:ACTIVE_MARKET,year:1970,period:1,turn:0,
    _scenarioAnchorYear:bpYear,
    stations,ps:stations.filter(s=>s&&s.isPlayer),
    sc:scForGame,cash:startCash,
    fmp:effectiveFmpForMarket(1970,ACTIVE_MARKET),adx:1.0+activeMkt.adxBonus,satDrag:0,streamDrag:0,
    fccAM:1,fccFM:1,
    unlockedFormats:Object.keys(FM).filter(f=>formatAllowedInMarket(f,ACTIVE_MARKET,1970)),
    news:[...genMarketRelNetNews],evq:[...EVDATA],
    score:{shareHistory:[],peakRevenue:0,decadeScores:{},isSandbox:false},
    rankerHistory:[],
    finHistory:[],
    _playerFinHistory:{},
    stationFinHistory:{},
    debtWarningQ:0,
    loans:[],
    talentBench:[],
    _atl1970DeferredQueue:ATLANTA_1970_DEFERRED_LAUNCHES.map(({bpIdx,y,p})=>({bpIdx,y,p})),
    _megaFragmentationQueue:megaMarketFragmentationQueueForNewGame(ACTIVE_MARKET),
    _megaFragmentationAdded:0,
    _spanishLaunchesQueue:marketSpanishLaunchesQueueForNewGame(ACTIVE_MARKET),
    _fragmentationLaunchesQueue:marketFragmentationLaunchesQueueForNewGame(ACTIVE_MARKET),
    ...(sc.id==='tutorial_turnaround'?{
      tutorialMode:true,tutorialAct:1,tutorialStep:0,
      _tutorialIntroDone:false,
      _tutorialConsultantDone:false,_tutorialTalentAdjusted:false,
      _tutorialProgExtraStep:0,_tutorialTalentRosterIntroDone:false,_tutorialTalentExplainerDismissed:false,_tutorialHireListCoachDismissed:false,
      _tutorialAct5MiddayTurns:0,_tutorialOpeningPromo:null,_tutorialOpeningSpots:null,
      _tutorialPromoRaised:false,_tutorialSpotsAdjusted:false,_tutorialAct8Turns:0,
      _tutorialBrandExtraStep:0,_tutorialBrandTourDone:false,_tutorialBrandEverOpened:false,
      _tutorialAct4ContractTipDone:false,_tutorialAct4ContractGutterDone:false,_tutorialAct4ContractStatsCoachDone:false,
      _tutorialResearchCoachStep:0,_tutorialResearchReportCoachDone:false,
      _tutorialAct5SummariesSeen:0,_tutorialAct5FormatCoachShown:false,_tutorialAct7Phase:0,_tutorialFmtModalHintShown:false,
      _tutorialRankerCoachDismissed:false,
      _tutorialAct4ExtendCoachDone:false,_tutorialAct4MoreActionsCoachDone:false,
      _tutorialAct4BenchCoachStep:0,_tutorialAct4BenchReleaseId:null,
      _tutorialDeferredTalentAdjusted:false,
      _tutorialSalesCoachStep:0,
      _tutorialFmtCoachStep:0,
      _tutorialDriftCoachDismissed:0,_tutorialDriftCoachStep:0,
      _tutorialLeanCoachDismissed:0,_tutorialLeanCoachStep:0,
      _tutorialProgFocusCoachStep:0,
      _tutorialProgModalIntroDone:false,
      _tutorialAct6SalesIntroPending:0,
      _tutorialSecondStationTipShown:false,
      _tutorialGradTurn:0,
      _tutorialShareTier:0,
      _tutorialCoachedFormatApplied:false,
      _tutorialCoachedTalentApplied:false,
      _tutorialAdvSinceTalent:0,
    }:{}),
    sportsRights:{},franchiseRights:{},teamRecords:{},
  };
}

/** Events not yet reached at (year, period) — same idea as genMarket’s `remainingEvq` for mid-era starts. */
function wlEvqRemainingAfterPeriod(year, period) {
  const p = period === 2 ? 2 : 1;
  return EVDATA.filter((ev) => {
    if (!ev || ev.y == null || ev.p == null) return false;
    if (ev.y > year) return true;
    if (ev.y < year) return false;
    return ev.p > p;
  });
}

/**
 * Campaign promotion into a fresh market: keep career sim time instead of resetting to 1970.
 * Temporarily sets `gm_under`’s scenario start year so genMarket uses the non-1970 path (rivals, FCC, evq).
 */
function wlGenMarketGmUnderAtCareerTime(simYear, simPeriod) {
  const y = Math.max(1970, Math.min(2025, simYear | 0));
  const p = simPeriod === 2 ? 2 : 1;
  const sc = SC.find((s) => s.id === 'gm_under');
  if (!sc) return genMarket('gm_under');
  const prevStart = sc.startYear;
  try {
    if (y > 1970) sc.startYear = y;
    const g = genMarket('gm_under');
    if (p === 2) {
      g.period = 2;
      g.turn = (y - 1970) * 2 + 1;
      g.evq = wlEvqRemainingAfterPeriod(y, 1);
    }
    return g;
  } finally {
    sc.startYear = prevStart;
  }
}

/** Headless / console: snapshot appeal, identity, and score for a station + year (e.g. staffing sweep scripts). */
function staffingAutomationDiagnosticBundle(s,G){
  const g=G&&G.year!=null?G:{year:1970,marketId:ACTIVE_MARKET};
  const t=stationAutomationScore(s,g);
  const lf=stationLiveFactor(s);
  return{
    score:+t.toFixed(4),
    liveFactor:+lf.toFixed(4),
    label:stationStaffingAutomationLabel(s,g),
    appeal:+staffingAutomationAppealTradeoffMult(s,g).toFixed(4),
    identity:+staffingAutomationIdentityGrowthMult(s,g).toFixed(4),
    identityLiveGrowth:+stationLiveIdentityGrowthMult(s).toFixed(4),
    liveFranchiseRatings:+stationLiveFranchiseRatingsMult(s).toFixed(4),
    liveAdvertiserRev:+stationLiveAdvertiserConfidenceRevMult(s,g).toFixed(4),
    oqSoftCap:+stationOverallQualitySoftCap(s).toFixed(1),
    staffCostMult:+((staffingAutomationEconomicsActive(s,g)?1-0.48*t:1)).toFixed(3),
    opsFloorMult:+((staffingAutomationEconomicsActive(s,g)?1-0.4*t:1)).toFixed(3),
    fmtPen:+staffingAutomationFormatPenaltyMult(s.format).toFixed(2),
    eraTol:+staffingAutomationEraListenerTolerance(g.year).toFixed(3),
    eraTolEff:+staffingAutomationEffectiveEraTolerance(s,g).toFixed(3),
  };
}

