// Scheduled Atlanta 1970 BP slots: same entry economics as event-driven `rival-` (seedNewEntry).
function processAtlanta1970DeferredLaunches(G){
  const q=G._atl1970DeferredQueue;
  if(!q||!q.length)return;
  const remain=[];
  for(const ent of q){
    if(G.year<ent.y||(G.year===ent.y&&G.period<ent.p)){remain.push(ent);continue;}
    const i=ent.bpIdx;
    const ph=G.stations[i];
    if(!ph||!ph._bpSlotDeferred)continue;
    const bp=effectiveBpForMarket(i,G.marketId||ACTIVE_MARKET,G.year);
    const freq=ph._deferFreq;
    const s=mkStn(bp,freq,G.year);
    s.color=CLR[i%CLR.length];
    s.entryTurn={year:G.year,period:G.period};
    s.launchPeriod=G.turn||0;
    G.stations[i]=s;
    applyMarketDialFacilityOverrides([s],G.marketId||ACTIVE_MARKET);
    if(!s.aiLicenseeKey)s.aiLicenseeKey=rivalFictionalParentName(s,G)||('indie_'+s.id);
    if(bp.type==='FM'){
      const entYr=G.year||1970;
      const isLate70sMusicEnt=[7,15,16,18].includes(i)&&entYr>=1974;
      const oqBump=isLate70sMusicEnt?6:5;
      const qTalent=isLate70sMusicEnt?5:4;
      s.oq=Math.min(90,Math.round(s.oq+oqBump));
      Object.values(s.prog).forEach(sd=>{if(sd&&sd.quality!=null)sd.quality=Math.min(93,Math.round(sd.quality+qTalent));});
      refreshStationOQ(s,G);
    }
    seedNewEntry(s,G);
    calcRev(s,G);
    if(!G.news)G.news=[];
    G.news.unshift({v:'MEDIUM',t:`📡 ${s.callLetters} signs on — ${fmtLabel(bp.fmt)} (${bp.type} ${freq}). The dial keeps filling out.`,y:G.year,p:G.period});
  }
  G._atl1970DeferredQueue=remain;
}

