/**
 * @param {'purchase'|'repaint'|'replace'} mode
 */
async function wlRemoteVanImageOp(stationId,mode){
  if(typeof globalThis!=='undefined'&&globalThis.__WL_HEADLESS__)return;
  const op=G.stations.find(st=>st.id===stationId);
  if(!op)return;
  const turnN=effectiveGameTurn();
  const _bmSafe=bmSafeElId(stationId);
  const statusEl=document.getElementById('bm-van-status-'+_bmSafe);
  if(mode==='purchase'){
    if(op.cosmeticRemoteVanUrl){
      showToast('You already have a remote van for this station.','info');
      return;
    }
  }else if(mode==='repaint'){
    if(!op.cosmeticRemoteVanUrl){
      showToast('Purchase a remote van first.','warn');
      return;
    }
    if(!op.cosmeticLogoUrl){
      showToast('Repaint needs a generated station logo — generate one so the van can match your current art.','warn');
      return;
    }
  }else if(mode==='replace'){
    if(!op.cosmeticRemoteVanUrl){
      showToast('No van to replace.','warn');
      return;
    }
    if(effectiveRemoteVanMarketingLift(op,G)>0){
      showToast('Fleet is still in service — use Repaint to update artwork with a new logo, or wait until the vehicle wears out (~'+REMOTE_VAN_LIFETIME_YEARS+' years).','info');
      return;
    }
  }
  const vanCost=mode==='repaint'?remoteVanRepaintCostDollars(G,op):remoteVanPurchaseCostDollars(G);
  if(mpMyCashOnHand()<vanCost){
    showToast(`Need ${f$(vanCost)}.`,'warn');
    return;
  }
  if(stationCosmeticGenMatchesTurn(op,turnN,'_lastVanGenTurn')){
    const el=document.getElementById('bm-van-status-'+_bmSafe);
    if(el)el.textContent='Remote van actions limited to once per period — try again next period.';
    else showToast('Already used a remote van action this period.','warn');
    return;
  }
  if(op._vanGenPending||op._logoGenPending||op._jingleGenPending){
    const el=document.getElementById('bm-van-status-'+_bmSafe);
    if(el)el.textContent='Wait for the other image or jingle request to finish…';
    else showToast('Another logo, van, or jingle request is still generating.','warn');
    return;
  }
  op._vanGenPending=true;
  wlSetVanGenButtonUi(stationId,true);
  wlSetVanRepaintReplaceUi(stationId,true);
  const msg=mode==='repaint'
    ?'WORKING — Repainting van from your logo. Usually 30–90s. Do not click again; this box will update.'
    :mode==='replace'
      ?'WORKING — New fleet van image. Usually 30–90s. Do not click again; this box will update.'
      :'WORKING — Generating van art. Usually 30–90s. Do not click again; this box will update.';
  if(statusEl){
    wlAiGenStatusBusy(statusEl,true);
    statusEl.textContent=msg;
  }
  const band=(op.fmBooster||op.sig?.type==='FM')?'FM':'AM';
  const logoRel=(typeof op.cosmeticLogoUrl==='string'&&op.cosmeticLogoUrl.trim())?op.cosmeticLogoUrl.split('?')[0]:'';
  const body={
    stationName:(typeof op.brand==='string'&&op.brand.trim())?op.brand.trim():callDisplay(op),
    format:fmtLabel(op.format)||'Radio',
    year:G.year,
    tone:typeof op.cosmeticLogoTone==='string'?op.cosmeticLogoTone:'',
    frequency:String(op.freq||''),
    band,
    cosmeticLogoUrl:logoRel,
    regenerate:mode!=='purchase',
  };
  try{
    try{wlAnalyticsCreativeTool('remote_van','started',{});}catch(_e){}
    const res=await fetch(wlGameApiUrl('/api/generate-remote-van'),{
      method:'POST',
      headers: await wlGameApiAuthJsonHeaders(),
      body:JSON.stringify(body),
    });
    const data=await res.json().catch(()=>({}));
    if(!res.ok||!data.ok){
      const canVanBenefitSansArt=(mode==='purchase'||mode==='replace')
        &&wlPromotionBenefitEligibleWhenCreativeUnavailable(res,data,'van')
        && !(mode==='purchase'&&op.cosmeticRemoteVanUrl);
      if(canVanBenefitSansArt){
        const hitCreativeLimit=data&&(data.code==='trial_quota_exhausted'||data.code==='guest_quota_exhausted'||data.code==='quota_exceeded');
        wlApplyRemoteVanPromotionWithoutGeneratedImage(op,mode,vanCost,turnN,statusEl,{
          creativeLimitPayload:hitCreativeLimit?data:null,
          reasonSnippet:data.error||res.statusText||'no artwork',
          toastMsg:hitCreativeLimit
            ?'Promotion boost applied — creative limit reached; no new van artwork.'
            :'Promotion boost applied — van artwork unavailable; fleet benefit is in place.',
          analyticsReason:hitCreativeLimit?'blocked':'service_unavailable',
        });
        return;
      }
      if(wlAiTrialQuotaToast(data))return;
      if(statusEl)statusEl.textContent=data.error||res.statusText||'Van image failed.';
      showToast(data.error||'Remote van generation failed.','warn');
      try{wlAnalyticsCreativeTool('remote_van','failed',{});}catch(_e){}
      return;
    }
    if(data.trialQuota)wlMaybeTrialApproachingFromQuota(data.trialQuota,'image');
    wlAdjustMyCash(-vanCost);
    op.cosmeticRemoteVanUrl=data.imageUrl;
    op.cosmeticRemoteVanV=Date.now();
    if(mode==='purchase'||mode==='replace'){
      op.remoteVanMarketingLift=REMOTE_VAN_MARKETING_LIFT;
      op.remoteVanPurchasedYear=G.year;
    }
    op._lastVanGenTurn=turnN;
    recalc(G.stations,G);
    if(statusEl){
      statusEl.textContent=mode==='repaint'
        ?'Repaint complete — van image updated'
        :data.cached&&(mode==='purchase')?'From cache (purchase complete)':mode==='replace'?'Fleet replaced — boost restored':'Purchase complete — van saved';
    }
    const logMsg=mode==='repaint'
      ?`Repainted remote van (${f$(vanCost)})`
      :mode==='replace'
        ?`Replaced worn remote fleet (${f$(vanCost)})`
        :`Purchased remote broadcast van (${f$(vanCost)})`;
    logHistory(op,'LOGO',logMsg+'.',G);
    autoSave();
    if(MP.mode==='live'&&MP.socket&&MP.roomId){
      MP.emit('mp_station_logo',{
        roomId:MP.roomId,
        stationId:op.id,
        cosmeticRemoteVanUrl:data.imageUrl,
        cosmeticRemoteVanV:op.cosmeticRemoteVanV,
        remoteVanMarketingLift:op.remoteVanMarketingLift,
        remoteVanPurchasedYear:op.remoteVanPurchasedYear,
      });
    }
    renderAll();
    try{wlAnalyticsCreativeTool('remote_van','succeeded',{});}catch(_e){}
    wlMaybeGuestAiCreativeSuccess('van');
  }catch(_e){
    const canCatch=(mode==='purchase'||mode==='replace')&&!(mode==='purchase'&&op.cosmeticRemoteVanUrl)&&mpMyCashOnHand()>=vanCost;
    if(canCatch){
      wlApplyRemoteVanPromotionWithoutGeneratedImage(op,mode,vanCost,turnN,statusEl,{
        reasonSnippet:'network or API error',
        toastMsg:'Promotion boost applied — could not reach artwork service; fleet benefit is in place.',
        analyticsReason:'network_fallback',
      });
    }else{
      if(statusEl)statusEl.textContent='Network error — try again.';
      showToast('Remote van request failed.','warn');
      try{wlAnalyticsCreativeTool('remote_van','failed',{});}catch(_f){}
    }
  }finally{
    op._vanGenPending=false;
    if(statusEl)wlAiGenStatusBusy(statusEl,false);
    wlSetVanGenButtonUi(stationId,false);
    wlSetVanRepaintReplaceUi(stationId,false);
    wlSyncStationCardAiStatusStrip(stationId);
    if(typeof BM_ACTIVE_SID!=='undefined'&&BM_ACTIVE_SID&&ensureOpsSourceSid(BM_ACTIVE_SID)===ensureOpsSourceSid(stationId)){
      renderBrandMarketingStation(BM_ACTIVE_SID);
    }
  }
}
function wlPurchaseRemoteVan(stationId){return wlRemoteVanImageOp(stationId,'purchase');}
function wlRepaintRemoteVan(stationId){return wlRemoteVanImageOp(stationId,'repaint');}
function wlReplaceRemoteVan(stationId){return wlRemoteVanImageOp(stationId,'replace');}
window.wlRepaintRemoteVan=wlRepaintRemoteVan;
window.wlReplaceRemoteVan=wlReplaceRemoteVan;
async function wlCommissionStationJingle(stationId){
  if(typeof globalThis!=='undefined'&&globalThis.__WL_HEADLESS__)return;
  const op=G.stations.find(st=>st.id===stationId);
  if(!op)return;
  const _bmSafe=bmSafeElId(stationId);
  const statusEl=document.getElementById('bm-jingle-status-'+_bmSafe);
  const turnOk=effectiveGameTurn();
  const jingleCost=stationJinglePackageCostDollars(G);
  if(stationCosmeticGenMatchesTurn(op,turnOk,'_lastJingleGenTurn')){
    if(statusEl)statusEl.textContent='Already commissioned a jingle package this period — try next period.';
    else showToast('Jingle commission limited to once per period.','warn');
    return;
  }
  if(op._jingleGenPending||op._logoGenPending||op._vanGenPending){
    if(statusEl)statusEl.textContent='Wait for the other media request to finish…';
    else showToast('Another logo, van, or jingle request is still running.','warn');
    return;
  }
  if(Array.isArray(op._pendingJingleVariants)&&op._pendingJingleVariants.length){
    if(statusEl)statusEl.textContent='Pick a variant above before commissioning again.';
    else showToast('Choose a jingle variant first.','warn');
    return;
  }
  if(mpMyCashOnHand()<jingleCost){
    showToast(`Need ${f$(jingleCost)}.`,'warn');
    return;
  }
  const tagInp=document.getElementById('bm-jingle-tagline-'+_bmSafe);
  const tagline=tagInp&&typeof tagInp.value==='string'?tagInp.value.trim().slice(0,60):'';
  const brandRaw=(typeof op.brand==='string'&&op.brand.trim())?op.brand.trim():callDisplay(op);
  const band=(op.fmBooster||op.sig?.type==='FM')?'FM':'AM';
  const sonic=wlBuildJingleSonicHints(op,G);
  const body={
    stationId:String(op.id),
    brand:brandRaw.slice(0,120),
    format:(fmtLabel(op.format,G.year)||'Radio').trim().slice(0,100),
    formatId:String(op.format||'').trim().slice(0,40),
    year:Math.floor(Number(G.year))||1970,
    tagline,
    frequency:String(op.freq!=null?op.freq:'').trim().slice(0,24),
    band,
    callLetters:String(brandCallBaseForToken(op.callLetters||'')||'').replace(/[^A-Za-z]/g,'').slice(0,12),
    audienceHint:sonic.audienceHint.slice(0,WL_JINGLE_AUDIENCE_HINT_MAX),
    positionHint:sonic.positionHint.slice(0,WL_JINGLE_POSITION_HINT_MAX),
  };
  op._jingleGenPending=true;
  const btn=document.getElementById('bm-jingle-commission-btn-'+_bmSafe);
  if(btn){
    btn.disabled=true;
    btn.setAttribute('aria-busy','true');
  }
  if(statusEl){
    wlAiGenStatusBusy(statusEl,true);
    statusEl.textContent='WORKING — Creating two jingle takes. Often 1–4 minutes. Do not close this panel or click again; this message will clear when ready.';
  }
  try{
    try{wlAnalyticsCreativeTool('jingle','started',{});}catch(_e){}
    const res=await fetch(wlGameApiUrl('/api/generate-station-jingle'),{
      method:'POST',
      headers: await wlGameApiAuthJsonHeaders(),
      body:JSON.stringify(body),
    });
    const data=await res.json().catch(()=>({}));
    if(!res.ok||!data.ok){
      if(wlPromotionBenefitEligibleWhenCreativeUnavailable(res,data,'jingle')){
        const hitCreativeLimit=data&&(data.code==='trial_quota_exhausted'||data.code==='guest_quota_exhausted'||data.code==='quota_exceeded');
        wlApplyJinglePromotionBoostWithoutAudio(op,jingleCost,turnOk,tagline,statusEl,{
          creativeLimitPayload:hitCreativeLimit?data:null,
          reasonSnippet:data.error||res.statusText||'no audio',
          toastMsg:hitCreativeLimit
            ?'Promotion boost applied — creative limit reached; no new jingle audio.'
            :'Promotion boost applied — jingle audio unavailable; package benefit is in place.',
          analyticsReason:hitCreativeLimit?'blocked':'service_unavailable',
        });
        return;
      }
      if(wlAiTrialQuotaToast(data))return;
      if(statusEl)statusEl.textContent=data.error||res.statusText||'Jingle request failed.';
      showToast(data.error||'Jingle generation failed.','warn');
      try{wlAnalyticsCreativeTool('jingle','failed',{});}catch(_e){}
      return;
    }
    if(data.trialQuota)wlMaybeTrialApproachingFromQuota(data.trialQuota,'jingle');
    let variants=Array.isArray(data.variants)?data.variants:null;
    const jobId=typeof data.jobId==='string'?data.jobId.trim():'';
    const workingBase='WORKING — Creating two jingle takes. Often 1–4 minutes. Do not close this panel or click again; this message will clear when ready.';
    if(!variants||!variants.length){
      if(!jobId){
        wlApplyJinglePromotionBoostWithoutAudio(op,jingleCost,turnOk,tagline,statusEl,{
          reasonSnippet:data.error||'no jingle job id',
          toastMsg:'Promotion boost applied — jingle job could not start; package benefit is in place.',
          analyticsReason:'no_job_id',
        });
        return;
      }
      if(statusEl)statusEl.textContent=workingBase;
      const done=await wlPollStationJingleJob(jobId);
      if(done.status!=='complete'||!done.ok||!Array.isArray(done.variants)||!done.variants.length){
        const hitCreativeLimit=done&&(done.code==='trial_quota_exhausted'||done.code==='guest_quota_exhausted'||done.code==='quota_exceeded');
        wlApplyJinglePromotionBoostWithoutAudio(op,jingleCost,turnOk,tagline,statusEl,{
          creativeLimitPayload:hitCreativeLimit?done:null,
          reasonSnippet:(done&&done.error)||'Jingle generation did not complete.',
          toastMsg:hitCreativeLimit
            ?'Promotion boost applied — creative limit reached; no new jingle audio.'
            :undefined,
          analyticsReason:'poll_failed',
        });
        return;
      }
      if(done.trialQuota)wlMaybeTrialApproachingFromQuota(done.trialQuota,'jingle');
      variants=done.variants;
    }
    if(!variants||!variants.length){
      wlApplyJinglePromotionBoostWithoutAudio(op,jingleCost,turnOk,tagline,statusEl,{
        reasonSnippet:'No jingle variants returned.',
        analyticsReason:'empty_variants',
      });
      return;
    }
    wlAdjustMyCash(-jingleCost);
    op._pendingJingleVariants=variants;
    op._jinglePendingTagline=tagline;
    delete op._jingleSunoPromptNote;
    op._lastJingleGenTurn=turnOk;
    logHistory(op,'LOGO',`Commissioned station jingle package (${f$(jingleCost)}).`,G);
    autoSave();
    showToast('Jingle package ready — pick a variant.','info');
    try{wlAnalyticsCreativeTool('jingle','succeeded',{});}catch(_e){}
    wlMaybeGuestAiCreativeSuccess('jingle');
  }catch(_e){
    if(mpMyCashOnHand()>=jingleCost){
      wlApplyJinglePromotionBoostWithoutAudio(op,jingleCost,turnOk,tagline,statusEl,{
        reasonSnippet:'network error',
        toastMsg:'Promotion boost applied — could not reach audio service; package benefit is in place.',
        analyticsReason:'network_fallback',
      });
    }else{
      if(statusEl)statusEl.textContent='Network error — try again.';
      showToast('Jingle request failed.','warn');
      try{wlAnalyticsCreativeTool('jingle','failed',{});}catch(_f){}
    }
  }finally{
    op._jingleGenPending=false;
    const jingleStatusFresh=document.getElementById('bm-jingle-status-'+_bmSafe);
    if(jingleStatusFresh)wlAiGenStatusBusy(jingleStatusFresh,false);
    if(btn){
      btn.disabled=false;
      btn.setAttribute('aria-busy','false');
    }
    wlSyncStationCardAiStatusStrip(stationId);
    if(typeof BM_ACTIVE_SID!=='undefined'&&BM_ACTIVE_SID&&ensureOpsSourceSid(BM_ACTIVE_SID)===ensureOpsSourceSid(stationId)){
      renderBrandMarketingStation(BM_ACTIVE_SID);
    }
  }
}
function wlPickStationJingleVariant(stationId,idx){
  const op=G.stations.find(st=>st.id===stationId);
  if(!op||!Array.isArray(op._pendingJingleVariants))return;
  const v=op._pendingJingleVariants[idx];
  if(!v||typeof v.audioUrl!=='string'||!v.audioUrl.startsWith('/generated-jingles/'))return;
  op.cosmeticJingleUrl=v.audioUrl;
  op.cosmeticJingleV=Date.now();
  op.jingleMarketingLift=JINGLE_MARKETING_LIFT;
  op.jingleCommissionedYear=G.year;
  op.jingleVariantIndex=idx;
  if(typeof op._jinglePendingTagline==='string'&&op._jinglePendingTagline)op.jingleTagline=op._jinglePendingTagline.slice(0,60);
  else if(!op.jingleTagline)delete op.jingleTagline;
  delete op._jinglePendingTagline;
  delete op._pendingJingleVariants;
  delete op._jingleSunoPromptNote;
  recalc(G.stations,G);
  logHistory(op,'LOGO','Selected station jingle variant.',G);
  autoSave();
  if(MP.mode==='live'&&MP.socket&&MP.roomId){
    MP.emit('mp_station_logo',{
      roomId:MP.roomId,
      stationId:op.id,
      cosmeticJingleUrl:op.cosmeticJingleUrl,
      cosmeticJingleV:op.cosmeticJingleV,
      jingleMarketingLift:op.jingleMarketingLift,
      jingleCommissionedYear:op.jingleCommissionedYear,
      jingleVariantIndex:op.jingleVariantIndex,
      jingleTagline:typeof op.jingleTagline==='string'?op.jingleTagline:'',
    });
  }
  renderAll();
  if(typeof BM_ACTIVE_SID!=='undefined'&&BM_ACTIVE_SID&&ensureOpsSourceSid(BM_ACTIVE_SID)===ensureOpsSourceSid(stationId)){
    renderBrandMarketingStation(BM_ACTIVE_SID);
  }
  showToast('Jingle saved — promotion reach updated.','info');
}
function wlClearStationJingle(stationId){
  const op=G.stations.find(st=>st.id===stationId);
  if(!op)return;
  delete op.cosmeticJingleUrl;
  delete op.cosmeticJingleV;
  delete op.jingleMarketingLift;
  delete op.jingleCommissionedYear;
  delete op.jingleVariantIndex;
  delete op.jingleTagline;
  delete op._pendingJingleVariants;
  delete op._jinglePendingTagline;
  delete op._jingleSunoPromptNote;
  recalc(G.stations,G);
  logHistory(op,'LOGO','Removed station jingle.',G);
  autoSave();
  if(MP.mode==='live'&&MP.socket&&MP.roomId){
    MP.emit('mp_station_logo',{roomId:MP.roomId,stationId:op.id,clearCosmeticJingle:true});
  }
  renderAll();
  if(typeof BM_ACTIVE_SID!=='undefined'&&BM_ACTIVE_SID&&ensureOpsSourceSid(BM_ACTIVE_SID)===ensureOpsSourceSid(stationId))renderBrandMarketingStation(BM_ACTIVE_SID);
  showToast('Jingle removed.','info');
}
async function wlSaveStationJingleFile(stationId,pendingIdx){
  const op=G.stations.find(st=>st.id===stationId);
  if(!op){
    showToast('Station not found.','warn');
    return;
  }
  let rel=null;
  if(pendingIdx!=null&&pendingIdx>=0&&Array.isArray(op._pendingJingleVariants)){
    const v=op._pendingJingleVariants[pendingIdx];
    if(v&&typeof v.audioUrl==='string')rel=v.audioUrl.split('?')[0];
  }else if(typeof op.cosmeticJingleUrl==='string'&&op.cosmeticJingleUrl.startsWith('/generated-jingles/')){
    rel=op.cosmeticJingleUrl.split('?')[0];
  }
  if(!rel){
    showToast('Nothing to save.','warn');
    return;
  }
  const qs=pendingIdx!=null&&pendingIdx>=0?'':(op.cosmeticJingleV?'?v='+encodeURIComponent(op.cosmeticJingleV):'');
  const abs=wlGameMediaAbsUrl(rel+qs);
  const call=(stripCallBandSuffix(op.callLetters||callDisplay(op)||'station').replace(/[^a-z0-9]+/gi,'-').replace(/^-|-$/g,'')||'station').slice(0,40);
  const base=rel.split('/').pop()||'jingle';
  const extMatch=base.match(/\.(mp3|m4a|wav|ogg)$/i);
  const ext=extMatch?extMatch[1].toLowerCase():'mp3';
  const suffix=pendingIdx!=null&&pendingIdx>=0?`-take${pendingIdx+1}`:'';
  const filename=`${call}-jingle${suffix}.${ext}`;
  try{
    const r=await fetch(abs,{mode:'cors',credentials:'omit'});
    if(!r.ok)throw new Error('HTTP '+r.status);
    const blob=await r.blob();
    wlDownloadBlobToFile(blob,filename);
    showToast('Download started.','info');
  }catch(e){
    console.warn('[jingle dl]',e);
    showToast('Could not download — open the game from the same host as the API and try again.','warn');
  }
}
window.wlCommissionStationJingle=wlCommissionStationJingle;
window.wlPickStationJingleVariant=wlPickStationJingleVariant;
window.wlClearStationJingle=wlClearStationJingle;
window.wlSaveStationJingleFile=wlSaveStationJingleFile;
function wlSetVanRepaintReplaceUi(stationId,busy){
  const safe=bmSafeElId(stationId);
  ['bm-van-repaint-btn-','bm-van-replace-btn-'].forEach(prefix=>{
    const btn=document.getElementById(prefix+safe);
    if(btn){
      btn.disabled=!!busy;
      btn.setAttribute('aria-busy',busy?'true':'false');
    }
  });
}
async function wlGenerateLogo(stationId,regenerate,opts){
  opts=opts||{};
  const silent=!!opts.silent;
  if(typeof globalThis!=='undefined'&&globalThis.__WL_HEADLESS__)return;
  const op=G.stations.find(st=>st.id===stationId);
  if(!op)return;
  const _bmSafe=bmSafeElId(stationId);
  const statusEl=document.getElementById('wl-logo-status-'+stationId)||(_bmSafe?document.getElementById('bm-logo-status-'+_bmSafe):null);
  if(op._logoGenPending||op._jingleGenPending){
    if(statusEl)statusEl.textContent='Already generating — please wait…';
    else if(!silent)showToast('Logo or jingle generation already in progress for this station.','warn');
    return;
  }
  if(!silent&&stationCosmeticGenMatchesTurn(op,effectiveGameTurn(),'_lastLogoGenTurn')){
    if(statusEl)statusEl.textContent='Already generated a station logo this period — try next period.';
    else showToast('Already generated a station logo this period.','warn');
    return;
  }
  const reg=typeof regenerate==='boolean'?regenerate:!!op.cosmeticLogoUrl;
  op._logoGenPending=true;
  wlSetLogoGenButtonUi(stationId,true);
  if(statusEl){
    wlAiGenStatusBusy(statusEl,true);
    statusEl.textContent='WORKING — Logo in progress. Usually under a minute. Do not click again; this line will update when finished.';
  }
  const band=(op.fmBooster||op.sig?.type==='FM')?'FM':'AM';
  const yr=Math.floor(Number(G.year));
  const nameRaw=((typeof op.brand==='string'&&op.brand.trim())?op.brand.trim():callDisplay(op)).trim().slice(0,120);
  const body={
    stationName:nameRaw||callDisplay(op)||'Station',
    format:(fmtLabel(op.format)||'Radio').trim().slice(0,100),
    year:Number.isFinite(yr)?Math.min(2040,Math.max(1930,yr)):1970,
    tone:typeof op.cosmeticLogoTone==='string'?op.cosmeticLogoTone.trim().slice(0,80):'',
    frequency:String(op.freq||'').trim().slice(0,40),
    band,
    regenerate:!!reg,
  };
  try{
    try{wlAnalyticsCreativeTool('logo','started',{});}catch(_e){}
    const res=await fetch(wlGameApiUrl('/api/generate-logo'),{
      method:'POST',
      headers: await wlGameApiAuthJsonHeaders(),
      body:JSON.stringify(body),
    });
    const data=await res.json().catch(()=>({}));
    if(!res.ok||!data.ok){
      if(wlAiTrialQuotaToast(data)){
        try{wlAnalyticsCreativeTool('logo','blocked',{reason:'trial_limit'});}catch(_e){}
        wlFallbackLogoOnGenerationError(op,silent);
        if(statusEl)statusEl.textContent=data.error||'Trial generation limit — using basic logo.';
        return;
      }
      wlFallbackLogoOnGenerationError(op,silent);
      if(statusEl)statusEl.textContent=data.error||res.statusText||'Generation failed — using basic logo.';
      try{wlAnalyticsCreativeTool('logo','failed',{});}catch(_e){}
      return;
    }
    if(data.trialQuota)wlMaybeTrialApproachingFromQuota(data.trialQuota,'image');
    op.cosmeticLogoUrl=data.imageUrl;
    op.cosmeticLogoV=Date.now();
    delete op.cosmeticLogoBackupUrl;
    delete op.cosmeticLogoBackupV;
    delete op.cosmeticLogoBackupTone;
    if(!silent)op._lastLogoGenTurn=effectiveGameTurn();
    if(statusEl)statusEl.textContent=data.cached?'From cache':'New image saved';
    logHistory(op,'LOGO',reg?'Station logo updated (regenerated).':'Station logo generated.',G);
    autoSave();
    if(MP.mode==='live'&&MP.socket&&MP.roomId){
      MP.emit('mp_station_logo',{
        roomId:MP.roomId,
        stationId:op.id,
        cosmeticLogoUrl:data.imageUrl,
        cosmeticLogoV:op.cosmeticLogoV,
        cosmeticLogoTone:typeof op.cosmeticLogoTone==='string'?op.cosmeticLogoTone:'',
      });
    }
    renderAll();
    try{wlAnalyticsCreativeTool('logo','succeeded',{});}catch(_e){}
    wlMaybeGuestAiCreativeSuccess('logo');
  }catch(_e){
    wlFallbackLogoOnGenerationError(op,silent);
    try{wlAnalyticsCreativeTool('logo','failed',{});}catch(_f){}
    if(statusEl){
      const base=window.__WL_GAME_SERVER_URL||(typeof location!=='undefined'?location.origin:'');
      statusEl.textContent=base
        ?`No API or network error — using basic logo. (${base})`
        :'No API — using basic logo.';
    }
  }finally{
    op._logoGenPending=false;
    if(statusEl)wlAiGenStatusBusy(statusEl,false);
    wlSetLogoGenButtonUi(stationId,false);
    wlSyncStationCardAiStatusStrip(stationId);
    if(silent&&!op.cosmeticLogoUrl)op._logoAutoGenExhausted=true;
    if(typeof BM_ACTIVE_SID!=='undefined'&&BM_ACTIVE_SID&&ensureOpsSourceSid(BM_ACTIVE_SID)===ensureOpsSourceSid(stationId)){
      renderBrandMarketingStation(BM_ACTIVE_SID);
    }
  }
}

/** Player-owned stations: auto-request AI logos (rivals stay procedural SVG until acquired). Staggered like portraits. */
function queueAutoLogosForPlayerStations(){
  if(typeof globalThis!=='undefined'&&globalThis.__WL_HEADLESS__)return;
  if(!G)return;
  /* Auto logos: Starter + Pro only (free + trial default to procedural “basic logo” unless player generates). */
  try{
    const slug=typeof window!=='undefined'?String(window.__WL_CLERK_PLAN_SLUG||'').trim():'';
    if(slug!=='starter'&&slug!=='pro')return;
  }catch(_e){ return; }
  const list=MP.mode==='live'?G.ps.filter(s=>s._mpOwner===MP.playerId):G.ps;
  list.forEach((st,i)=>{
    if(!st||st.isPublic||st._bpSlotDeferred)return;
    if(st.cosmeticLogoUrl||st._logoGenPending||st._logoAutoGenExhausted)return;
    setTimeout(()=>{wlGenerateLogo(st.id,false,{silent:true});},i*450);
  });
}

// ── COSMETIC: talent portraits (server-side Grok; same identity = same file) ──
function talentPortraitFirstYear(t){
  if(!t)return 1970;
  if(typeof t._portraitFirstHireYear==='number'&&!Number.isNaN(t._portraitFirstHireYear))return t._portraitFirstHireYear;
  return t._hireYear||t._careerStartYear||(G&&G.year)||1970;
}
function wlPortraitFromDataset(el){
  try{
    const raw=el&&el.getAttribute&&el.getAttribute('data-portrait');
    if(!raw)return;
    const o=JSON.parse(decodeURIComponent(raw));
    wlOpenTalentPortraitModal(o);
  }catch(_e){}
}
/** Broken portrait file: show 🎙 and drop bad URL from save state when we can identify the talent. */
function wlPortraitImgError(img){
  if(!img)return;
  img.onerror=null;
  const wrap=img.closest('.tp-thumb');
  if(!wrap)return;
  let talentId=null, portraitUrl=null;
  try{
    const raw=wrap.getAttribute('data-portrait');
    if(raw){
      const o=JSON.parse(decodeURIComponent(raw));
      talentId=o.id||null;
      portraitUrl=o.url||null;
    }
  }catch(_e){}
  if(talentId&&typeof G!=='undefined'&&G){
    const match=t=>{
      if(!t||t.id!==talentId)return;
      if(portraitUrl&&t._portraitUrl&&t._portraitUrl!==portraitUrl)return;
      delete t._portraitUrl;
      delete t._portraitV;
    };
    (G.talentBench||[]).forEach(ent=>{if(ent?.talent)match(ent.talent);});
    (G.ps||[]).forEach(s=>{
      if(!s?.prog)return;
      Object.values(s.prog).forEach(sd=>{if(sd?.talent)match(sd.talent);});
    });
    if(typeof autoSave==='function')try{autoSave();}catch(_e){}
  }
  const cls=(wrap.getAttribute('class')||'').replace(/\btp-thumb--live\b/g,'').replace(/\s+/g,' ').trim();
  const ph=document.createElement('span');
  ph.className=('tp-thumb tp-thumb--ph '+cls).trim();
  ph.setAttribute('aria-hidden','true');
  ph.textContent='🎙';
  wrap.replaceWith(ph);
}
function wlOpenTalentPortraitModal(o){
  if(!o||!o.url)return;
  const img=document.getElementById('wl-portrait-modal-img');
  const nameEl=document.getElementById('wl-portrait-modal-name');
  const ctxEl=document.getElementById('wl-portrait-modal-ctx');
  const v=o.v||0;
  const src=wlGameMediaAbsUrl(o.url+(v?'?v='+v:''));
  const prevFb=document.getElementById('wl-portrait-modal-fallback');
  if(prevFb)prevFb.remove();
  if(img){
    img.style.display='';
    img.onload=function(){
      img.onload=null;
      img.onerror=null;
      const fb=document.getElementById('wl-portrait-modal-fallback');
      if(fb)fb.remove();
    };
    img.onerror=function(){
      img.onerror=null;
      img.onload=null;
      img.style.display='none';
      const d=document.createElement('div');
      d.id='wl-portrait-modal-fallback';
      d.style.cssText='font-size:min(18vh,120px);line-height:1.2;padding:24px 16px;text-align:center';
      d.textContent='🎙';
      d.setAttribute('aria-hidden','true');
      img.insertAdjacentElement('afterend',d);
    };
    img.src=src;
  }
  if(nameEl)nameEl.textContent=o.name||'';
  if(ctxEl)ctxEl.textContent=o.ctx||'';
  om('m-portrait');
}
/** Optional `ctx`: station / daypart line for full-size viewer. */
function talentPortraitThumbHtml(t,cls,ctx){
  if(!t)return '';
  const url=t._portraitUrl;
  const v=t._portraitV||0;
  const src=url?wlGameMediaAbsUrl(url+(v?'?v='+v:'')):'';
  if(!src)return '<span class="tp-thumb tp-thumb--ph '+(cls||'')+'" aria-hidden="true">🎙</span>';
  const payload=encodeURIComponent(JSON.stringify({id:t.id||null,name:t.name||'',url:url,v:v,ctx:ctx||''}));
  return '<span class="tp-thumb '+(cls||'')+' tp-thumb--live" role="button" tabindex="0" data-portrait="'+payload+'" onclick="event.stopPropagation();wlPortraitFromDataset(this)" onkeydown="if(event.key===\'Enter\'||event.key===\' \'){event.preventDefault();event.stopPropagation();wlPortraitFromDataset(this);}"><img alt="" src="'+src+'" draggable="false" onerror="wlPortraitImgError(this)"></span>';
}
/** Library paths already assigned to talents this game (excludes duplicates for /api/generate-portrait). */
function collectClaimedLibraryPortraitAssets(){
  if(!G)return[];
  const out=[];
  const seen=new Set();
  const add=t=>{
    if(!t)return;
    const a=t._portraitLibraryAsset;
    if(a==null||a==='')return;
    const s=String(a).replace(/\\/g,'/').trim();
    if(!s||seen.has(s))return;
    seen.add(s);
    out.push(s);
  };
  (G.ps||[]).forEach(s=>{
    if(!s||!s.prog)return;
    Object.values(s.prog).forEach(sd=>add(sd?.talent));
  });
  (G.talentBench||[]).forEach(ent=>add(ent?.talent));
  return out;
}
async function queueTalentPortrait(t){
  if(typeof globalThis!=='undefined'&&globalThis.__WL_HEADLESS__)return;
  if(!t||!t.name)return;
  if(t._portraitUrl||t._portraitPending)return;
  t._portraitPending=true;
  const firstYear=talentPortraitFirstYear(t);
  try{
    const cy=typeof G!=='undefined'&&G?.year!=null?G.year:1970;
    const start=t._careerStartYear!=null&&t._careerStartYear!==undefined?t._careerStartYear:t._hireYear!=null?t._hireYear:firstYear;
    const yearsExperience=Math.max(0,Math.floor(cy-start));
    const claimed=collectClaimedLibraryPortraitAssets();
    const sessionId=typeof G!=='undefined'&&G&&G._portraitSessionId?String(G._portraitSessionId):'';
    const res=await fetch(wlGameApiUrl('/api/generate-portrait'),{
      method:'POST',
      headers:await wlGameApiAuthJsonHeaders(),
      body:JSON.stringify({
        name:t.name,
        firstHireYear:firstYear,
        gender:t.gender==='female'?'female':t.gender==='male'?'male':undefined,
        talentId:t.id||undefined,
        morale:typeof t.morale==='number'?t.morale:undefined,
        quality:typeof t.quality==='number'?t.quality:undefined,
        yearsExperience,
        claimedLibraryAssets:claimed,
        gamePortraitSession:sessionId||undefined,
      }),
    });
    const data=await res.json().catch(()=>({}));
    if(res.ok&&data.ok&&data.imageUrl){
      t._portraitUrl=data.imageUrl;
      t._portraitV=Date.now();
      const libRaw=data.libraryAsset!=null&&data.libraryAsset!==''?data.libraryAsset:(data.profile&&data.profile.libraryAsset);
      if(libRaw!=null&&libRaw!==''){
        t._portraitLibraryAsset=String(libRaw).replace(/\\/g,'/');
      }else if(data.source&&data.source!=='library'){
        delete t._portraitLibraryAsset;
      }
      if(data.profile){
        t._portraitEra=data.profile.eraBucket;
        t._portraitWardrobe=data.profile.wardrobeType;
      }
      if(data.source && data.source !== 'library' && (!data.cached || data.cached === false))
        wlMaybeGuestAiCreativeSuccess('portrait');
      autoSave();
      renderAll();
    }
  }catch(_e){}
  finally{t._portraitPending=false;}
}
function collectPlayerTalentsForPortraits(){
  if(!G)return[];
  const out=[];
  const seen=new Set();
  const add=t=>{
    if(!t||!t.name)return;
    const k=t.id||normTalentNameKey(t.name)+'|'+talentPortraitFirstYear(t);
    if(seen.has(k))return;
    seen.add(k);
    out.push(t);
  };
  // Derive from G.stations — G.ps can be missing or stale vs stations (e.g. before migrateSave).
  const mpPid=MP.mode==='live'?(MP.playerId!=null?MP.playerId:0):null;
  const my=(G.stations||[]).filter(s=>{
    if(!s||!s.isPlayer||s._bpSlotDeferred)return false;
    if(MP.mode!=='live')return true;
    return (s._mpOwner??0)===mpPid;
  });
  my.forEach(s=>{
    if(!s.prog)return;
    Object.values(s.prog).forEach(sd=>add(sd?.talent));
  });
  (G.talentBench||[]).forEach(ent=>{
    if(MP.mode==='live'&&(ent._mpOwner??0)!==mpPid)return;
    add(ent?.talent);
  });
  return out;
}
function queuePlayerTalentPortraits(){
  if(typeof globalThis!=='undefined'&&globalThis.__WL_HEADLESS__)return;
  if(!G)return;
  const run=async()=>{
    const list=collectPlayerTalentsForPortraits().filter(t=>t&&!t._portraitUrl);
    for(const t of list){
      await queueTalentPortrait(t);
    }
  };
  void run();
}

function exportSave(){
  const _saveStns = MP.mode==='live' ? G.ps.filter(s=>s._mpOwner===MP.playerId) : G.ps;
  const payload=saveGame(`${G.year} ${G.period===1?'Spring':'Fall'} — ${_saveStns.map(s=>s.callLetters).join(', ')}`);
  const blob=new Blob([JSON.stringify(payload,null,2)],{type:'application/json'});
  const url=URL.createObjectURL(blob);
  const a=document.createElement('a');
  a.href=url;
  const d=new Date();
  a.download=`airwave-empire-${G.year}-${String(d.getMonth()+1).padStart(2,'0')}${String(d.getDate()).padStart(2,'0')}.json`;
  a.click();URL.revokeObjectURL(url);
  G.news.unshift({v:'LOW',t:`💾 Game saved: ${payload.label}`,y:G.year,p:G.period});
  openSaveLoad();
}

function importSave(file){
  const reader=new FileReader();
  reader.onload=e=>{
    void (async()=>{
    try{
      const payload=JSON.parse(e.target.result);
      if(!payload.G||!payload.G.year){throw new Error('Invalid save file');}
      await wlRefreshTrialLockFromServer();
      if(!wlTrialSaveResumeAllowed({ G: payload.G, campaign: payload.campaign })){
        showToast('This save does not match your free trial. Load your trial save, or subscribe for full access.','warn',9200);
        return;
      }
      await wlApplyLoadedGamePayload(payload,{source:'file',label:payload.label||`File (${payload.saved?.slice(0,10)||'?'})`});
    }catch(err){
      alert('Could not load save file: '+err.message);
    }
    })();
  };
  reader.readAsText(file);
}

