function wlFeedbackGameContext(){
  if(typeof G==='undefined'||!G||!G.sc)return '';
  try{
    const p=G.period===1?'Spring':'Fall';
    const m=G.marketId||'?';
    const sc=G.sc?.l||G.sc?.id||'';
    const mode=typeof MP!=='undefined'&&MP.mode==='live'?'multiplayer':'solo';
    return `Mode: ${mode}\nYear/period: ${G.year} ${p}\nMarket: ${m}\nScenario: ${sc}`;
  }catch(_e){
    return '';
  }
}
function openFeedback(){
  const st=document.getElementById('wl-feedback-status');
  if(st){
    st.textContent='';
    st.style.color='';
  }
  const hp=document.getElementById('wl-feedback-hp');
  if(hp)hp.value='';
  const em=document.getElementById('wl-feedback-email');
  if(em)em.value='';
  const msg=document.getElementById('wl-feedback-msg');
  if(msg){
    msg.value='';
    msg.placeholder='Bugs, ideas, difficulty, UI…';
  }
  om('m-feedback');
}
async function wlSubmitFeedback(){
  const hp=document.getElementById('wl-feedback-hp');
  if(hp&&String(hp.value||'').trim()){
    cm('m-feedback');
    return;
  }
  const msgEl=document.getElementById('wl-feedback-msg');
  const emEl=document.getElementById('wl-feedback-email');
  const st=document.getElementById('wl-feedback-status');
  const raw=(msgEl?.value||'').trim();
  if(raw.length<3){
    if(st){
      st.textContent='Please enter a bit more detail.';
      st.style.color='var(--red)';
    }
    return;
  }
  const ctx=wlFeedbackGameContext();
  const message=ctx?`${ctx}\n\n${raw}`:raw;
  const replyEmail=(emEl?.value||'').trim();
  const btn=document.getElementById('wl-feedback-send');
  if(btn){
    btn.disabled=true;
    btn.textContent='Sending…';
  }
  if(st){
    st.textContent='';
    st.style.color='';
  }
  const formTo=typeof window!=='undefined'&&window.__WL_FEEDBACK_FORMSUBMIT_EMAIL&&String(window.__WL_FEEDBACK_FORMSUBMIT_EMAIL).trim();
  try{
    let r;
    let j={};
    if(formTo){
      const params=new URLSearchParams();
      params.set('name','Airwave Empire player');
      params.set('email',replyEmail||'anonymous@airwaveempire.com');
      params.set('message',message);
      params.set('_subject','Airwave Empire — player feedback');
      params.set('_template','table');
      params.set('_captcha','false');
      r=await fetch('https://formsubmit.co/ajax/'+encodeURIComponent(formTo),{
        method:'POST',
        headers:{'Content-Type':'application/x-www-form-urlencoded;charset=UTF-8',Accept:'application/json'},
        body:params.toString(),
      });
      j=await r.json().catch(()=>({}));
    }else{
      r=await fetch(wlGameApiUrl('/api/feedback'),{
        method:'POST',
        headers:{'Content-Type':'application/json'},
        body:JSON.stringify({message,replyEmail,_gotcha:''}),
      });
      j=await r.json().catch(()=>({}));
    }
    if(!r.ok){
      const err=j.error||(j.message&&String(j.message))||'Could not send feedback.';
      if(st){
        st.textContent=err;
        st.style.color='var(--red)';
      }
      showToast(err,'warn');
      return;
    }
    if(st){
      st.textContent='Thanks — your message was sent.';
      st.style.color='var(--grn)';
    }
    showToast('Feedback sent. Thank you!','info');
    if(msgEl)msgEl.value='';
    if(emEl)emEl.value='';
    setTimeout(()=>cm('m-feedback'),2400);
  }catch(e){
    if(st){
      st.textContent=formTo?'Could not reach the feedback service. Try again or use the Contact page.':'Could not reach the game server.';
      st.style.color='var(--red)';
    }
    showToast(formTo?'Could not reach the feedback service.':'Could not reach the game server.','warn');
  }finally{
    if(btn){
      btn.disabled=false;
      btn.textContent='Send feedback';
    }
  }
}

/**
 * Legacy bug: a single rankerHistory book can be all zeros (CSV column blank). Repair at load by
 * copying shares from the nearest prior book with a positive total, then renormalizing to ~1.
 */
function repairCollapsedRankerHistorySnaps(G){
  const rh=G.rankerHistory;
  if(!rh||!rh.length)return;
  const COLLAPSE=1e-9;
  const MIN_KEYS=4;
  let fixed=0;
  for(let i=0;i<rh.length;i++){
    const snap=rh[i];
    if(!snap||typeof snap.shares!=='object')continue;
    const ids=Object.keys(snap.shares);
    if(ids.length<MIN_KEYS)continue;
    let sum=0;
    for(let k=0;k<ids.length;k++){
      const v=Number(snap.shares[ids[k]]);
      if(Number.isFinite(v))sum+=v;
    }
    if(sum>COLLAPSE)continue;
    let prev=null;
    for(let j=i-1;j>=0;j--){
      const p=rh[j];
      if(!p||typeof p.shares!=='object')continue;
      let ps=0;
      const pk=Object.keys(p.shares);
      for(let q=0;q<pk.length;q++){
        const v=Number(p.shares[pk[q]]);
        if(Number.isFinite(v))ps+=v;
      }
      if(ps>COLLAPSE){prev=p;break;}
    }
    if(!prev)continue;
    const raw=[];
    let newSum=0;
    for(let k=0;k<ids.length;k++){
      const id=ids[k];
      const v=Math.max(0,Number(prev.shares[id])||0);
      raw.push(v);
      newSum+=v;
    }
    if(newSum<COLLAPSE)continue;
    for(let k=0;k<ids.length;k++){
      snap.shares[ids[k]]=Math.round((raw[k]/newSum)*1e8)/1e8;
    }
    if(prev.pairDedupedShare01ByKey&&typeof prev.pairDedupedShare01ByKey==='object'){
      snap.pairDedupedShare01ByKey={...prev.pairDedupedShare01ByKey};
      Object.keys(snap.pairDedupedShare01ByKey).forEach(pk=>{
        if((Number(snap.pairDedupedShare01ByKey[pk])||0)<=1e-8)delete snap.pairDedupedShare01ByKey[pk];
      });
    }
    fixed++;
    G._rankerHistoryScrubbedBooks=G._rankerHistoryScrubbedBooks||[];
    G._rankerHistoryScrubbedBooks.push({year:Number(snap.year),period:Number(snap.period)});
  }
  if(fixed>0)G._rankerHistoryCollapsedRowsRepaired=(G._rankerHistoryCollapsedRowsRepaired||0)+fixed;
}

/**
 * NPR/public can keep total column mass above the full-collapse threshold while every commercial
 * cell is ~0 (bad save / desync). Rebuild commercial keys from the prior book's commercial mix.
 */
function repairLowCommercialMassRankerHistorySnaps(G){
  const rh=G.rankerHistory;
  if(!rh||!rh.length)return;
  const commIds=(G.stations||[]).filter(s=>s&&!s._bpSlotDeferred&&!stationIsNoncommercialInstitutional(s)&&s.id).map(s=>s.id);
  if(commIds.length<2)return;
  const LOW=0.012;
  let fixed=0;
  for(let i=0;i<rh.length;i++){
    const snap=rh[i];
    if(!snap||typeof snap.shares!=='object')continue;
    let sumC=0;
    for(let k=0;k<commIds.length;k++){
      const v=Number(snap.shares[commIds[k]]);
      if(Number.isFinite(v))sumC+=v;
    }
    if(sumC>LOW)continue;
    let prev=null;
    for(let j=i-1;j>=0;j--){
      const p=rh[j];
      if(!p||typeof p.shares!=='object')continue;
      let ps=0;
      for(let k=0;k<commIds.length;k++){
        const v=Number(p.shares[commIds[k]]);
        if(Number.isFinite(v))ps+=v;
      }
      if(ps>LOW){prev=p;break;}
    }
    if(!prev)continue;
    const raw=[];
    let newSum=0;
    for(let k=0;k<commIds.length;k++){
      const id=commIds[k];
      const v=Math.max(0,Number(prev.shares[id])||0);
      raw.push(v);
      newSum+=v;
    }
    if(newSum<LOW)continue;
    for(let k=0;k<commIds.length;k++){
      snap.shares[commIds[k]]=Math.round((raw[k]/newSum)*1e8)/1e8;
    }
    fixed++;
  }
  if(fixed>0)G._rankerHistoryLowCommMassRepaired=(G._rankerHistoryLowCommMassRepaired||0)+fixed;
}

/**
 * Legacy ratings desync could record a phantom ~37% leg in rankerHistory while the market snap
 * (deduped AQH basis) stayed sane. Repair spike columns from the frozen snap or prior good book.
 */
function repairPhantomRankerHistorySnaps(G){
  const rh=G.rankerHistory;
  if(!rh||!rh.length||!G)return 0;
  const tierMax=marketRankRowShareSanityMax01(G);
  const spikeMax=Math.max(tierMax*1.08,0.22);
  let fixed=0;
  for(let i=0;i<rh.length;i++){
    const col=rh[i];
    if(!col||typeof col.shares!=='object')continue;
    const vals=Object.values(col.shares).map(v=>Number(v)).filter(v=>Number.isFinite(v));
    const max=Math.max(0,...vals);
    if(max<=spikeMax)continue;
    const mktSnap=G._mktRankBookSnap;
    if(mktSnap&&Number(mktSnap.year)===Number(col.year)&&Number(mktSnap.period)===Number(col.period)){
      const built=buildRankerHistorySnapColumnFromMarketBook(G,{preferSnap:true});
      col.shares=built.shares;
      col.pairDedupedShare01ByKey=built.pairDedupedShare01ByKey;
      col.daypartShares=built.daypartShares;
      fixed++;
      G._rankerHistoryScrubbedBooks=G._rankerHistoryScrubbedBooks||[];
      G._rankerHistoryScrubbedBooks.push({year:Number(col.year),period:Number(col.period)});
      continue;
    }
    let prev=null;
    for(let j=i-1;j>=0;j--){
      const p=rh[j];
      if(!p||typeof p.shares!=='object')continue;
      const pmax=Math.max(0,...Object.values(p.shares).map(v=>Number(v)).filter(v=>Number.isFinite(v)));
      if(pmax>spikeMax)continue;
      const ps=Object.values(p.shares).reduce((a,v)=>a+(Number(v)||0),0);
      if(ps>0.05){prev=p;break;}
    }
    if(!prev)continue;
    const ids=Object.keys(col.shares);
    const raw=ids.map(id=>Math.max(0,Number(prev.shares[id])||0));
    const sum=raw.reduce((a,v)=>a+v,0);
    if(sum<1e-6)continue;
    ids.forEach((id,k)=>{col.shares[id]=Math.round((raw[k]/sum)*1e8)/1e8;});
    fixed++;
    G._rankerHistoryScrubbedBooks=G._rankerHistoryScrubbedBooks||[];
    G._rankerHistoryScrubbedBooks.push({year:Number(col.year),period:Number(col.period)});
  }
  if(fixed>0)G._rankerHistoryPhantomRepaired=(G._rankerHistoryPhantomRepaired||0)+fixed;
  return fixed;
}

/**
 * One ranker column: headline shares from `s.rat.share` (see `openRanker`).
 * When the calendar has advanced but this period is not in `G.rankerHistory` yet, `openRanker` may set
 * `_bookPending` and `_lastBookLabel` on the returned object so the UI does not label stale ratings as
 * the new book.
 */
/**
 * One ranker column from the market book display basis (deduped AQH / combined simulcast rows).
 * @param {{preferSnap?:boolean}} [opts] When true, use frozen `G._mktRankBookSnap` for the current book.
 */
function buildRankerHistorySnapColumnFromMarketBook(G,opts){
  const year=Number(G.year),period=Number(G.period);
  const shares=Object.create(null);
  const pairDedupedShare01ByKey=Object.create(null);
  const mktSnap=G._mktRankBookSnap;
  const useSnap=opts?.preferSnap!==false&&mktSnap&&Number(mktSnap.year)===year&&Number(mktSnap.period)===period&&Array.isArray(mktSnap.rows)&&mktSnap.rows.length;
  if(useSnap){
    mktSnap.rows.forEach(sr=>{
      if(!sr||typeof sr.share!=='number'||Number.isNaN(sr.share))return;
      const key=sr.key||'';
      if(key.startsWith('s:'))shares[key.slice(2)]=sr.share;
      else if(key.startsWith('p:')||key.startsWith('str:'))pairDedupedShare01ByKey[key]=sr.share;
    });
  }else{
    buildMarketRankRowsIncludingStreams(G.stations,G).forEach(row=>{
      const key=marketRankRowKey(row);
      if(row.pair)pairDedupedShare01ByKey[key]=row.share;
      else if(row.stream)pairDedupedShare01ByKey[key]=row.share;
      else shares[row.st.id]=row.share;
    });
  }
  (G.stations||[]).forEach(s=>{
    if(!s||s._bpSlotDeferred||!s.id)return;
    if(shares[s.id]==null){
      let v;
      if(s.stream?.active)v=wlLiveTerrestrialSoloShare01(s,G);
      else v=s.rat&&typeof s.rat.share==='number'&&!Number.isNaN(s.rat.share)?s.rat.share:0;
      shares[s.id]=Math.round(v*1e8)/1e8;
    }
  });
  return{
    year,
    period,
    label:`${G.year} ${PERIODS[(G.period||1)-1]}`,
    shares,
    pairDedupedShare01ByKey,
    daypartShares:buildDaypartListeningSharesForStations(G.stations,G),
  };
}
function buildLiveRankerHistorySnapColumn(G){
  return{...buildRankerHistorySnapColumnFromMarketBook(G,{preferSnap:false}),_liveBook:true};
}
/** Align one persisted ranker column with the frozen market book snap (last completed book). */
function syncRankerHistoryColumnFromMarketSnap(G,col){
  if(!G||!col)return;
  const built=buildRankerHistorySnapColumnFromMarketBook(G,{preferSnap:true});
  col.shares=built.shares;
  col.pairDedupedShare01ByKey=built.pairDedupedShare01ByKey;
  col.daypartShares=built.daypartShares;
}
/** Sync the ranker column for the current calendar book from `_mktRankBookSnap`. */
function syncRankerHistoryCurrentBookFromMarketSnap(G){
  const rh=G?.rankerHistory;
  if(!rh||!rh.length||!G?._mktRankBookSnap)return 0;
  const idx=rh.findIndex(c=>Number(c.year)===Number(G.year)&&Number(c.period)===Number(G.period));
  if(idx<0)return 0;
  syncRankerHistoryColumnFromMarketSnap(G,rh[idx]);
  return 1;
}
/** Solo-station share for one ranker column (0–1). */
function rankerColumnSoloShare01(col,stationId){
  if(!col||stationId==null)return 0;
  return Math.max(0,Number(col.shares?.[stationId])||0);
}
/** Combined simulcast share for one ranker column (0–1). */
function rankerColumnPairShare01(col,row){
  if(!col||!row?.pair)return 0;
  const k=marketRankRowKey(row);
  const hist=col.pairDedupedShare01ByKey;
  if(hist&&typeof hist[k]==='number'&&!Number.isNaN(hist[k])&&hist[k]>1e-8)return hist[k];
  const lead=rankerColumnSoloShare01(col,row.lead?.id);
  const rcv=rankerColumnSoloShare01(col,row.rcv?.id);
  return Math.round((lead+rcv)*1e8)/1e8;
}
/** Rebuild `#mtb` / station-card book snap from a persisted ranker column. */
function rebuildMarketSnapFromRankerColumn(G,col){
  if(!G||!col)return;
  const rows=buildMarketRankRowsIncludingStreams(G.stations,G).map(row=>{
    let share;
    if(row.pair)share=rankerColumnPairShare01(col,row);
    else if(row.stream){
      const hk=marketRankRowKey(row);
      const pd=col.pairDedupedShare01ByKey?.[hk];
      share=typeof pd==='number'&&!Number.isNaN(pd)?pd:row.share;
    }else share=rankerColumnSoloShare01(col,row.st.id);
    return{key:marketRankRowKey(row),share:Math.round(share*1e8)/1e8};
  }).filter(r=>r.share>1e-8).sort((a,b)=>b.share-a.share);
  G._mktRankBookSnap={
    year:Number(col.year),
    period:Number(col.period),
    turn:G.turn,
    rows:rows.map((r,i)=>({key:r.key,rank:i+1,share:r.share})),
  };
  snapStationCardShareDisplay(G);
}
/** Calendar is past the rightmost completed ranker book (mid-period before next book closes). */
function wlCalendarAheadOfLastCompletedBook(G,lastCol){
  if(!lastCol)return false;
  const gy=Number(G?.year)||1970,gp=Number(G?.period)||1;
  const ly=Number(lastCol.year),lp=Number(lastCol.period);
  return gy>ly||(gy===ly&&gp>lp);
}
/** Saved market snap rows disagree with the ranker column they claim to represent. */
function wlMktSnapDisagreesWithRanker(G,col){
  const snap=G._mktRankBookSnap;
  if(!snap||!Array.isArray(snap.rows)||!col?.shares)return false;
  if(Number(snap.year)!==Number(col.year)||Number(snap.period)!==Number(col.period))return true;
  let checked=0,mismatch=0;
  snap.rows.forEach(sr=>{
    if(!sr?.key?.startsWith('s:'))return;
    const id=sr.key.slice(2);
    const rk=Number(col.shares[id])||0;
    const ss=Number(sr.share)||0;
    if(rk<0.003&&ss<0.003)return;
    checked++;
    if(Math.abs(ss-rk)>0.005)mismatch++;
    const st=G.stations?.find(x=>x.id===id);
    if(st?.stream?.active){
      const strSh=Number(snap.rows.find(r=>r.key==='str:'+id)?.share)||0;
      const live=Number(st.rat?.share)||0;
      if(ss<0.03&&live>0.05)mismatch++;
      else if(Math.abs(ss-strSh)<0.0025&&live>ss*2)mismatch++;
    }
  });
  return checked>=2&&mismatch>=1;
}
/** Snap has plausible terrestrial shares while ranker still has stream-leg mass on `shares[id]`. */
function wlSnapHealthierThanRankerForStreamStations(G,col){
  const snap=G?._mktRankBookSnap;
  if(!snap?.rows?.length||!col?.shares)return false;
  const snapByKey=new Map(snap.rows.map(r=>[r.key,r.share]));
  return (G.stations||[]).some(s=>{
    if(!s?.stream?.active||!s.id)return false;
    const solo=Number(snapByKey.get('s:'+s.id))||0;
    const rk=Number(col.shares[s.id])||0;
    return solo>0.05&&rk<0.03&&solo>rk*2;
  });
}
/**
 * Mid-period UI must show the last completed book (rightmost ranker column), not live `rat.share`.
 * Resets display snaps when resume/recalc advanced them ahead of `rankerHistory`.
 */
function reconcileBookDisplaySnapToLastCompletedRankerBook(G){
  const rh=G?.rankerHistory;
  if(!rh||!rh.length)return 0;
  wlRepairStreamTerrestrialShareConfusion(G);
  const last=rh[rh.length-1];
  const snap=G._mktRankBookSnap;
  const snapMatches=snap&&Number(snap.year)===Number(last.year)&&Number(snap.period)===Number(last.period)&&Array.isArray(snap.rows)&&snap.rows.length;
  if(
    !snapMatches||
    wlCalendarAheadOfLastCompletedBook(G,last)||
    wlMarketBookSnapDesyncedFromRanker(G,last)||
    wlMktSnapDisagreesWithRanker(G,last)
  ){
    if(snapMatches&&!wlCalendarAheadOfLastCompletedBook(G,last)&&wlSnapHealthierThanRankerForStreamStations(G,last)){
      syncRankerHistoryColumnFromMarketSnap(G,last);
      scrubStationRatHistBooks(G);
      snapStationCardShareDisplay(G);
    }else{
      rebuildMarketSnapFromRankerColumn(G,last);
    }
    return 1;
  }
  snapStationCardShareDisplay(G);
  return 0;
}
function refreshRankerSnapSharesFromStations(snap,stations){
  if(!G||!snap)return;
  syncRankerHistoryColumnFromMarketSnap(G,snap);
}
function maybeRefreshOpenRankerModal(){
  try{
    const el=document.getElementById('m-rk');
    if(el&&el.classList.contains('on')&&typeof G!=='undefined'&&G&&G.rankerHistory&&G.rankerHistory.length)openRanker();
  }catch(_e){}
}

function migrateSave(G){
  G.news=G.news||[];
  migrateHitsLineage(G);
  migrateGospelTaxonomy(G);
  const _chrCross=hitsLineageFirstChrCalendarYear();
  if(_chrCross!=null&&G._hitsChrTransitionNewsShown!==true&&(G.year||1970)>_chrCross)G._hitsChrTransitionNewsShown=true;
  // Fix missing fields added in recent updates
  if(!G._portraitSessionId||typeof G._portraitSessionId!=='string'){
    G._portraitSessionId=(typeof crypto!=='undefined'&&crypto.randomUUID)?crypto.randomUUID():`${Date.now()}-${Math.random().toString(36).slice(2,11)}`;
  }
  if(!G.marketId||!MARKETS[G.marketId])G.marketId='atlanta';
  if(!G.city)G.city=(MARKETS[G.marketId]||MARKETS.atlanta).label;
  if(!G.companyName){
    const mktLbl=MARKETS[G.marketId||'atlanta']?.label||'Atlanta';
    G.companyName=`${mktLbl} Broadcasting Group`;
  }
  // Turn index: half-years since 1970 (must be numeric — old saves / JSON may omit or use strings).
  let _turnN=Number(G.turn);
  if(!Number.isFinite(_turnN)){
    const y=G.year||1970;
    const p=G.period||1;
    _turnN=(y-1970)*2+(p===2?1:0);
  }
  G.turn=_turnN;
  G.loans=G.loans||[];
  if(G._attritionRemovedCumulative==null)G._attritionRemovedCumulative=0;
  if(G._attritionNicheFlipsCumulative==null)G._attritionNicheFlipsCumulative=0;
  migrateLoansV2(G);
  if(G.corps)rehydrateCorps(G); // re-link corp ownership after save/load
  initIndieLicenseeKeysFromStations(G.stations,G);
  if(G.corps){
    G.corps.forEach(c=>{
      const tmpl=CORPS.find(t=>t.id===c.id);
      if(tmpl)c.name=tmpl.name;
    });
  }
  if((G.year||1970)<1990){
    (G.stations||[]).forEach(s=>{ if(s&&s._corpLMAOffer) delete s._corpLMAOffer; });
  }
  (G.stations||[]).forEach(s=>{
    if(!s.corpOwner)return;
    const tmpl=CORPS.find(t=>t.id===s.corpOwner);
    if(tmpl)s.corpName=tmpl.name;
  });
  // Legacy saves: player wallet field present but isPlayer flag missing — ranker / G.ps need this
  (G.stations||[]).forEach(s=>{
    if(!s||s._bpSlotDeferred||s.corpOwner||stationIsNoncommercialInstitutional(s))return;
    if(s.isPlayer===true)return;
    if(s._mpOwner!==undefined&&s._mpOwner!==null)s.isPlayer=true;
  });
  // Old saves: drop internal flag (never shown in UI — 3-letter call is the only cue)
  (G.stations||[]).forEach(s=>{ if(s) delete s.heritageIncumbent; });
  G.corps=G.corps||null;
  G.mpPhase=G.mpPhase??null;
  G.continuesBeyondEnd=G.continuesBeyondEnd??false;
  if(!G._mpBankrupt||typeof G._mpBankrupt!=='object')G._mpBankrupt={};
  if(G._soloBankrupt===undefined)G._soloBankrupt=false;
  if(!G._mpDebtWarningQ||typeof G._mpDebtWarningQ!=='object')G._mpDebtWarningQ={};
  if(!G._loanNegEbitdaStreak||typeof G._loanNegEbitdaStreak!=='object')G._loanNegEbitdaStreak={};
  if(!G._aiRivalDebt||typeof G._aiRivalDebt!=='object')G._aiRivalDebt={};
  if(!G._aiRivalNegEbitdaStreak||typeof G._aiRivalNegEbitdaStreak!=='object')G._aiRivalNegEbitdaStreak={};
  G.rankerHistory=G.rankerHistory||[];
  (G.rankerHistory||[]).forEach(snap=>{
    if(!snap)return;
    if(snap.year!=null)snap.year=Number(snap.year);
    if(snap.period!=null)snap.period=Number(snap.period);
  });
  G.finHistory=G.finHistory||[];
  G._playerFinHistory=G._playerFinHistory||{};
  G.stationFinHistory=G.stationFinHistory||{};
  if(!G.score)G.score={isSandbox:false,shareHistory:[],peakRevenue:0,decadeScores:{}};
  else if(!Array.isArray(G.score.shareHistory))G.score.shareHistory=[];
  G._atl1970DeferredQueue=G._atl1970DeferredQueue||[];
  if(G._megaFragmentationQueue===undefined)G._megaFragmentationQueue=[];
  if(G._megaFragmentationAdded===undefined)G._megaFragmentationAdded=0;
  G.sportsRights=G.sportsRights||{};
  G.franchiseRights=G.franchiseRights||{};
  G.teamRecords=G.teamRecords||{};
  if((G.year||1970)>=1970){
    initSportsRights(G);
    initFranchiseRights(G);
  }
  migrateFranchiseFormatMismatch(G);
  (G.stations||[]).forEach(s=>{ if(s)normalizeSpokenWordStaffingModesOnStation(s); });
  coerceMusicVoiceTrackModesGlobally(G);
  refreshAllStationOQ(G);
  // Ensure fin.fix exists on all stations (added for cost breakdown display)
  (G.stations||[]).forEach(s=>{
    if(s._bpSlotDeferred)return;
    if(s.isZombie==null)s.isZombie=false;
    if(s.isNicheSurvival==null)s.isNicheSurvival=false;
    if(s._amWeakFallCount==null)s._amWeakFallCount=0;
    if(s._zombieFallStreak==null)s._zombieFallStreak=0;
    // Ensure fmBooster field exists
    if(s.fmBooster===undefined)s.fmBooster=false;
  // Translator signal restoration: old saves had universe/reach replaced with translator's weak values.
  // Restore original AM signal parameters — the translator is additive, not a replacement.
  if(s.fmBooster && s._boosterOrigSig && s.sig.universe < 0.50){
    s.sig.reach = s._boosterOrigSig.reach;
    s.sig.universe = s._boosterOrigSig.universe;
  }
  // Salary renormalization: two-way correction so existing talent reflects current scale.
  // Old saves may have talent at legacy low rates OR at old-inflation highs.
  // Bring all talent within a reasonable band around the current market rate
  // for their quality tier at the current year.
  if(s.prog){Object.entries(s.prog).forEach(([sl,sd])=>{
    if(!sd?.talent?.salary||!SAL[sl])return;
    const q=sd.talent.quality||30;
    const tier=q<42?'entry':q<68?'mid':'star';
    const r=SAL[sl][tier];
    const yr=G.year||1970;
    const p1=Math.min(25,yr-1970),p2=Math.max(0,Math.min(15,yr-1995)),p3=Math.max(0,yr-2010);
    const infl=1+p1*.040+p2*.018+p3*.008;
    const isTalk=TALK_FMTS&&TALK_FMTS.includes(s.format)?0.88:1.0;
    const mktPay=marketRankTierOnAirPayMult(G.marketId||ACTIVE_MARKET);
    const shMult=talentStationSharePayFloorMult(s);
    const lo=Math.round(r[0]*infl*isTalk*mktPay*shMult/500)*500;
    const hi=Math.round(r[1]*infl*isTalk*mktPay*shMult/500)*500;
    const mid=Math.round((lo+hi)/2/500)*500;
    // If salary is below entry-tier min or above 130% of mid, snap to mid
    if(sd.talent.salary<lo||sd.talent.salary>hi*1.3){
      sd.talent.salary=mid;
    }
    // Market-leading player stations should not keep entry-tier pay on weak long-tenured hosts
    if(s.isPlayer&&(s.rat?.share||0)>=0.10&&tier==='entry'){
      const leadFl=Math.round(salInfl((SAL[sl]?.mid?.[0]||SAL[sl]?.entry?.[0]||5000),yr)*0.72*mktPay*shMult/500)*500;
      if(sd.talent.salary<leadFl)sd.talent.salary=leadFl;
    }
  });}
    // Ensure translator signal fields exist on boosted stations
    if(s.fmBooster&&s.sig.type!=='FM'){s.sig.type='FM';s.sig.pw='translator';s.sig.reach=0.55;s.sig.universe=0.32;}
  });

  // Remove any corrupted/empty station entries (keep BP-slot placeholders without id/calls yet)
  G.stations=G.stations.filter(s=>s&&(s._bpSlotDeferred||(s.id&&s.callLetters)));
  // Deduplicate by id (can happen from LMA bugs or double-inserts)
  const _seenIds=new Set();
  G.stations=G.stations.filter(s=>{
    if(s._bpSlotDeferred)return true;
    if(_seenIds.has(s.id))return false;
    _seenIds.add(s.id);
    return true;
  });
  // Fix duplicate call letters: `callDisplay()` strips -AM/-FM and re-adds band, so "WNSS" vs "WNSS-FM"
  // both render as WNSS-FM — append a numeric base suffix until the *display* string is unique.
  const _seenCallDisp=new Set();
  G.stations.forEach(s=>{
    if(s._bpSlotDeferred)return;
    let disp=callDisplay(s);
    if(_seenCallDisp.has(disp)){
      const base=stripCallBandSuffix(s.callLetters);
      let n=2;
      for(;n<400;n++){
        s.callLetters=base+String(n);
        disp=callDisplay(s);
        if(!_seenCallDisp.has(disp))break;
      }
    }
    _seenCallDisp.add(callDisplay(s));
  });

  G.stations.forEach(s=>{
    if(s._bpSlotDeferred)return;
    delete s._logoGenPending;
    delete s._vanGenPending;
    delete s._jingleGenPending;
    if(s._lastLogoGenTurn!=null){
      const ln=Number(s._lastLogoGenTurn);
      if(Number.isFinite(ln))s._lastLogoGenTurn=ln; else delete s._lastLogoGenTurn;
    }
    if(s._lastVanGenTurn!=null){
      const vn=Number(s._lastVanGenTurn);
      if(Number.isFinite(vn))s._lastVanGenTurn=vn; else delete s._lastVanGenTurn;
    }
    if(s._lastJingleGenTurn!=null){
      const jn=Number(s._lastJingleGenTurn);
      if(Number.isFinite(jn))s._lastJingleGenTurn=jn; else delete s._lastJingleGenTurn;
    }
    // Stream object
    if(!s.stream)s.stream={active:false,aqh:0,rev:0,upkeep:0,dragOffset:0,launchYear:0};
    // Fin object
    if(!s.fin)s.fin={rev:0,fix:0,tal:0,cost:0,ebitda:0};
    // Rat object
    if(!s.rat)s.rat={share:0.01,aqh:100,cur:{},prev:{},hist:[],dp:{}};
    else{
      if(!s.rat.dp)s.rat.dp={};
      if(!Array.isArray(s.rat.hist))s.rat.hist=[];
    }
    if(!s.momDp)s.momDp={};
    DAYPART_SLOTS.forEach(sl=>{if(!s.momDp[sl])s.momDp[sl]={tgt:0.01,cur:0.01};});
    // Mom object
    if(!s.mom){s.mom={};COH.forEach(c=>{s.mom[c]={tgt:0.01,cur:0.01};});}
    // Ops object
    if(!s.ops)s.ops={spots:14,sell:0.65,promo:0,progBudget:0};
      if(s.ops&&s.ops.progBudget===undefined)s.ops.progBudget=0;
    // Prog object
    if(!s.prog){s.prog={};Object.keys(SL).forEach(k=>{s.prog[k]=null;});}
    // Drift default
    if(!s.drift)s.drift={};
    const _dKey=driftDefKey(s.format);
    const _dStore=hitsDriftStoreKey(s.format);
    if(s.drift[_dStore]===undefined&&DRIFT[_dKey])s.drift[_dStore]=DRIFT[_dKey].default;
    // Community identity fields (added recent version)
    if(s.identity===undefined)s.identity=0;
    if(s.identityBudget===undefined)s.identityBudget=0;
    if(s._formatAge===undefined)s._formatAge=0;
    if(s._identityPeak===undefined)s._identityPeak=0;
    if(s.budgetStress===undefined)s.budgetStress=0;
    // periodsAtStation on prog slots
    if(s.prog){Object.values(s.prog).forEach(sd=>{
          if(sd&&sd.talent){
            // Normalize tenure storage onto the talent object.
            if(sd.talent.periodsAtStation===undefined)sd.talent.periodsAtStation=sd.periodsAtStation||0;
            if(sd.periodsAtStation!==undefined&&sd.periodsAtStation>sd.talent.periodsAtStation)sd.talent.periodsAtStation=sd.periodsAtStation;
            sd.periodsAtStation=sd.talent.periodsAtStation;
            const yearsAtStation=Math.round((sd.talent.periodsAtStation||0)/2);
            // _hireYear = when they joined this station.
            if(!sd.talent._hireYear){
              sd.talent._hireYear=Math.max(1970,(G?.year||1970)-yearsAtStation);
            }
            // _careerStartYear = when they entered radio overall.
            if(!sd.talent._careerStartYear){
              sd.talent._careerStartYear=sd.talent._hireYear;
            }
            // Career can never be shorter than station tenure.
            if(sd.talent._careerStartYear>sd.talent._hireYear){
              sd.talent._careerStartYear=sd.talent._hireYear;
            }
            if(sd.talent._portraitFirstHireYear==null||sd.talent._portraitFirstHireYear===undefined){
              sd.talent._portraitFirstHireYear=sd.talent._hireYear||sd.talent._careerStartYear||(G?.year||1970);
            }
            if(sd.talent._trueQuality==null||sd.talent._trueQuality===undefined)
              sd.talent._trueQuality=Math.round(sd.talent.quality||50);
            if(!sd.talent._trueFormatFit||typeof sd.talent._trueFormatFit!=='object')
              sd.talent._trueFormatFit={...(sd.talent.formatFit||{})};
          }
        });}
    // Ensure color: in MP use per-player color based on _mpOwner, solo always amber
    if(s.isPlayer){
      if(s._mpOwner!==undefined && s._mpOwner!==null){
        // Restore per-player color (player 0=amber, 1=blue, 2=green, 3=red)
        const mpColors=['#f5a623','#60a5fa','#34d399','#f87171'];
        s.color = mpColors[s._mpOwner % 4] || '#f5a623';
      } else {
        s.color='#f5a623'; // solo mode
      }
    } else if(!s.color) s.color=CLR[Math.floor(Math.random()*CLR.length)];
    // Ensure sig object
    if(!s.sig)s.sig={type:'AM',reach:0.5,power:'10kw'};
    // Public station flag
    if(!s.isPublic)s.isPublic=false;
    if(s.isReligiousNetwork!==true)s.isReligiousNetwork=false;
  });

  // Inject public stations if missing (added in new version)
  const hasPubNews=G.stations.some(s=>s.isPublic&&s.format==='PUBLIC_NEWS');
  const hasPubClass=G.stations.some(s=>s.isPublic&&s.format==='PUBLIC_CLASSICAL');
  if(!hasPubNews&&G.year>=1975){
    const _pubPref=getCallPrefixForMarket(G.marketId||ACTIVE_MARKET);
    const pubNews={
      id:'pub_news_'+Date.now(),callLetters:_pubPref+['PBR','PNT','PBC','NPR','PUB'][Math.floor(Math.random()*5)],color:'#94a3b8',isPublic:true,isPlayer:false,
      brand:'Public Radio',oq:72,_pubLaunchYear:1975,
      format:'PUBLIC_NEWS',
      sig:{type:'FM',reach:0.92,power:'50kw'},str:'moderate',
      freq:'88.5 FM',launchPeriod:0,
      ops:{spots:0,sell:0,promo:0,progBudget:0},fin:{rev:0,fix:0,tal:0,cost:0,ebitda:0},
      rat:{share:0.04,aqh:4000,cur:{},prev:{},hist:[]},
      mom:{},prog:{},drift:{},stream:{active:false,aqh:0,rev:0,upkeep:0,dragOffset:0,launchYear:0},
      pers:{l:'Public Station',rs:.20,ag:.00,ms:.20,tr:.20,pt:.002,ic:.05}
    };
    COH.forEach(c=>{pubNews.mom[c]={tgt:0.02,cur:0.02};});
    Object.keys(SL).forEach(k=>{pubNews.prog[k]=null;});
    G.stations.push(pubNews);
    assignPublicNceTierToStation(pubNews,G.marketId||ACTIVE_MARKET,(G.scenario&&G.scenario.startYear!=null)?G.scenario.startYear:(G.year||1970));
  }
  if(!hasPubClass&&G.year>=1979){
    const _pubPref=getCallPrefixForMarket(G.marketId||ACTIVE_MARKET);
    const pubClass={
      id:'pub_class_'+Date.now(),callLetters:_pubPref+['PCL','PCS','CLS','JZC','PBS'][Math.floor(Math.random()*5)],color:'#7c8fa8',isPublic:true,isPlayer:false,
      brand:'Public Classical',oq:68,_pubLaunchYear:1979,
      format:'PUBLIC_CLASSICAL',
      sig:{type:'FM',reach:0.78,power:'25kw'},str:'niche',
      freq:'90.1 FM',launchPeriod:0,
      ops:{spots:0,sell:0,promo:0,progBudget:0},fin:{rev:0,fix:0,tal:0,cost:0,ebitda:0},
      rat:{share:0.02,aqh:2000,cur:{},prev:{},hist:[]},
      mom:{},prog:{},drift:{},stream:{active:false,aqh:0,rev:0,upkeep:0,dragOffset:0,launchYear:0},
      pers:{l:'Public Station',rs:.20,ag:.00,ms:.20,tr:.20,pt:.002,ic:.05}
    };
    COH.forEach(c=>{pubClass.mom[c]={tgt:0.01,cur:0.01};});
    Object.keys(SL).forEach(k=>{pubClass.prog[k]=null;});
    G.stations.push(pubClass);
    assignPublicNceTierToStation(pubClass,G.marketId||ACTIVE_MARKET,(G.scenario&&G.scenario.startYear!=null)?G.scenario.startYear:(G.year||1970));
  }
  const midPubPlan=G.marketId||ACTIVE_MARKET||'atlanta';
  const syPlan=(G.scenario&&G.scenario.startYear!=null)?G.scenario.startYear:(G.year||1970);
  const expFmts=computePublicExpansionFormatsAfterBase(midPubPlan,syPlan);
  for(let ei=0;ei<expFmts.length;ei++){
    const fmtPlan=expFmts[ei];
    const hasF=G.stations.some(s=>s.isPublic&&s.format===fmtPlan);
    const yrNeed=fmtPlan==='PUBLIC_ECLECTIC'?1991:1988;
    if(hasF||G.year<yrNeed)continue;
    const dialCtxM={stations:G.stations,marketId:midPubPlan};
    const fePl=nextUnusedCommercialFreq(dialCtxM,'FM');
    if(!fePl)continue;
    const _pubPrefP=getCallPrefixForMarket(midPubPlan);
    const launchPl=fmtPlan==='PUBLIC_ECLECTIC'?Math.max(1991,Math.round(Number(syPlan))||1970):Math.max(1988,Math.round(Number(syPlan))||1970);
    const brandPl=fmtPlan==='PUBLIC_ECLECTIC'?'Eclectic Public Radio':'Public Jazz';
    const colorPl=fmtPlan==='PUBLIC_ECLECTIC'?'#6b8cae':'#5b7fa4';
    const reachPl=fmtPlan==='PUBLIC_ECLECTIC'?0.82:0.76;
    const oqPl=fmtPlan==='PUBLIC_ECLECTIC'?70:69;
    const strPl=fmtPlan==='PUBLIC_ECLECTIC'?'moderate':'niche';
    const idPrefix=fmtPlan==='PUBLIC_ECLECTIC'?'pub_eclectic_':'pub_jazz_';
    const callsPool=fmtPlan==='PUBLIC_ECLECTIC'?['PEC','ECL','ARC','AIR','SON']:['PJZ','JAZ','WBG','KJZ','CSM'];
    const pubExtra={
      id:idPrefix+Date.now(),callLetters:_pubPrefP+callsPool[Math.floor(Math.random()*callsPool.length)],color:colorPl,isPublic:true,isPlayer:false,
      brand:brandPl,oq:oqPl,_pubLaunchYear:launchPl,
      format:fmtPlan,
      sig:{type:'FM',reach:reachPl,power:'25kw'},str:strPl,
      freq:fePl,launchPeriod:0,
      ops:{spots:0,sell:0,promo:0,progBudget:0},fin:{rev:0,fix:0,tal:0,cost:0,ebitda:0},
      rat:{share:0.02,aqh:1500,cur:{},prev:{},hist:[]},
      mom:{},prog:{},drift:{},stream:{active:false,aqh:0,rev:0,upkeep:0,dragOffset:0,launchYear:0},
      pers:{l:'Public Station',rs:.20,ag:.00,ms:.20,tr:.20,pt:.002,ic:.05}
    };
    COH.forEach(c=>{pubExtra.mom[c]={tgt:0.015,cur:0.015};});
    Object.keys(SL).forEach(k=>{pubExtra.prog[k]=null;});
    G.stations.push(pubExtra);
    assignPublicNceTierToStation(pubExtra,midPubPlan,syPlan);
  }

  // Deterministic institutional CCM ecosystem — repair orphan slot keys, inject missing slots.
  if(!G._religiousNetworkSpawnDisabled){
    const mid=G.marketId||ACTIVE_MARKET||'atlanta';
    const sy=religiousNetworkScenarioStartYear(G);
    const pres=computeReligiousNetworkPresence(mid,sy);
    const used=new Set();
    (G.stations||[]).forEach(s=>{
      if(s&&s._religiousNetworkSlotKey)used.add(s._religiousNetworkSlotKey);
    });
    const orphanSlots=(pres.slots||[]).filter(sl=>sl&&sl.slotKey&&!used.has(sl.slotKey));
    let oi=0;
    const rel=(G.stations||[]).filter(s=>s&&!s._bpSlotDeferred&&(s.format==='RELIGIOUS_NETWORK'||s.isReligiousNetwork))
      .slice()
      .sort((a,b)=>String(a.id||'').localeCompare(String(b.id||'')));
    rel.forEach(s=>{
      if(!s._religiousNetworkTier)s._religiousNetworkTier='typical';
      if(!s._religiousNetworkSlotKey&&orphanSlots[oi]){
        s._religiousNetworkSlotKey=orphanSlots[oi].slotKey;
        s._religiousNetworkTier=orphanSlots[oi].tier;
        used.add(s._religiousNetworkSlotKey);
        oi++;
      }
    });
    ensureReligiousNetworkScheduledForGame(G);
  }

  (G.talentBench||[]).forEach(ent=>{
    const tal=ent?.talent;
    if(tal&&(tal._portraitFirstHireYear==null||tal._portraitFirstHireYear===undefined)){
      tal._portraitFirstHireYear=tal._hireYear||tal._careerStartYear||(G?.year||1970);
    }
  });

  if(!G._daytimerNightSlotsNormalized){
    G._daytimerNightSlotsNormalized=true;
    G.stations.forEach(s=>{
      if(!s||s._bpSlotDeferred)return;
      if(stationIsAmDaytimer(s)) applyAmDaytimerNightSlotsToStation(s,G);
    });
  }

  (G.stations||[]).forEach(s=>{
    if(s&&s.simulcastSourceStationId===undefined)s.simulcastSourceStationId=null;
  });
  migrateSimulcastLegacyPairsToStar(G);
  repairOrphanSimulcastLegPointers(G);
  normalizeSimulcastLinksInPlace(G);
  // Ranker history keys + station list must be final (simulcast/public) before book repairs.
  repairCollapsedRankerHistorySnaps(G);
  repairLowCommercialMassRankerHistorySnaps(G);
  repairPhantomRankerHistorySnaps(G);
  wlRestoreFlatlinedLiveRatingsIfNeeded(G);

  applyAmFccPowerNormalization(G.stations, G);
  reassignAmClearChannelFlags(G.stations);

  repairOrphanPlayerLmaLesseeFlags(G);

  // Rebuild ps
  G.ps=G.stations.filter(s=>s.isPlayer);
  if(G.pendingDecisionEvent && !TROUBLE_SCENARIOS.find(sc=>sc.id===G.pendingDecisionEvent.scenarioId))
    G.pendingDecisionEvent=null;
  const _lastRhBook=G.rankerHistory?.length?G.rankerHistory[G.rankerHistory.length-1]:null;
  const _midPeriodAhead=_lastRhBook&&wlCalendarAheadOfLastCompletedBook(G,_lastRhBook);
  if(
    !G._mktRankBookSnap||!Array.isArray(G._mktRankBookSnap.rows)||!G._mktRankBookSnap.rows.length||
    _midPeriodAhead
  ){
    if(G.rankerHistory&&G.rankerHistory.length)reconcileBookDisplaySnapToLastCompletedRankerBook(G);
    else snapMarketRankBookDisplay(G,{bookClose:true});
  }
  // Saves from rare ratings desync: headline share valid but cohort AQH all zero → $0 revenue until next book.
  // POP + ACTIVE_MARKET must match this save before repair/seedRev (load paths used to call migrateSave first).
  if(G?.marketId&&MARKETS[G.marketId]){
    ACTIVE_MARKET=G.marketId;
    syncMarketPopToMarket(G.marketId);
  }
  const _loadRatRep=(G.stations||[]).reduce((n,st)=>n+(repairRatCurFromHeadlineShareIfAqhCollapsed(st,G.stations,G,{silent:true})?1:0),0);
  const _loadFlatRep=wlRepairDegenerateFlatCohortShares(G.stations,G);
  if(_loadRatRep>0||_loadFlatRep>0){
    if(!G._wlLoadingFromSave){
      try{
        seedRev(G.stations,G);
        updateAllStationsBudgetStress(G);
      }catch(_e){
        if(typeof console!=='undefined'&&console.error)console.error('[migrateSave] seedRev after ratings repair failed',_e);
      }
      G._wlRatingsLoadRepairStations=_loadRatRep;
      G._wlFlatCohortLoadRepairStations=_loadFlatRep;
    }
    repairCollapsedRankerHistorySnaps(G);
    repairLowCommercialMassRankerHistorySnaps(G);
    repairPhantomRankerHistorySnaps(G);
    scrubFinHistoryPhantomEconomicsBooks(G);
    scrubFinHistoryFlatlineBooks(G);
    scrubFinHistoryZeroRevenuePhantomBooks(G);
    scrubStationRatHistBooks(G);
    reconcileBookDisplaySnapToLastCompletedRankerBook(G);
    if(typeof console!=='undefined'&&console.warn){
      console.warn('[migrateSave] ratings load repair @',G.year,G.period,'aqh',_loadRatRep,'flat-demo',_loadFlatRep);
    }
    const _commM=(G.stations||[]).filter(s=>s&&!s._bpSlotDeferred&&!stationIsNoncommercialInstitutional(s));
    wlTrackSimInvariant({
      phase:'migrate_load_rat_cur_repaired',
      n_repaired:_loadRatRep,
      n_flat_demo:_loadFlatRep,
      n_comm:_commM.length,
      sum_share:_commM.reduce((a,s)=>a+(Number(s.rat?.share)||0),0),
    });
    if(G.news){
      const parts=[];
      if(_loadRatRep>0)parts.push(`${_loadRatRep} station(s) with missing cohort AQH`);
      if(_loadFlatRep>0)parts.push(`${_loadFlatRep} station(s) with flattened demo books`);
      G.news.unshift({
        v:'LOW',
        t:`📊 Load repair: fixed ${parts.join(' and ')} — audience mix and revenue display refreshed.`,
        y:G.year,
        p:G.period,
      });
      if(G.news.length>50)G.news=G.news.slice(0,50);
    }
    maybeRefreshOpenRankerModal();
  }
  wlRestoreFlatlinedLiveRatingsIfNeeded(G);
  repairPhantomRankerHistorySnaps(G);
  scrubFinHistoryPhantomEconomicsBooks(G);
  scrubFinHistoryFlatlineBooks(G);
  scrubFinHistoryZeroRevenuePhantomBooks(G);
  scrubStationRatHistBooks(G);
  if(reconcileBookDisplaySnapToLastCompletedRankerBook(G))maybeRefreshOpenRankerModal();
  wlRunGameIntegrityRepair(G,{phase:'load'});
  wlNotifyHistBackfillOnLoad(G);
  snapStationCardShareDisplay(G);
  if(G._finHistoryZeroRevScrubbed||G._wlFlatlineLiveRestored||G._wlIntegrityRepairCount){
    try{
      seedRev(G.stations,G);
      updateAllStationsBudgetStress(G);
    }catch(_e){}
  }
  return G;
}

function applyLoadedGameMarket(){
  if(!G)return;
  ACTIVE_MARKET=G.marketId||'atlanta';
  _selectedMarket=ACTIVE_MARKET;
  syncMarketPopToMarket(ACTIVE_MARKET);
}

/** True when migrateSave repaired ratings enough that mid-period revenue must be re-derived. */
function wlResumeNeedsRatingsEconomicsRefresh(G){
  if(!G)return false;
  return!!(
    G._wlFlatlineLiveRestored||
    G._wlRatingsLoadRepairStations||
    G._wlFlatCohortLoadRepairStations||
    G._rankerHistoryCollapsedRowsRepaired||
    G._rankerHistoryPhantomRepaired||
    G._rankerHistoryLowCommMassRepaired
  );
}
/** Belt-and-suspenders wallet anchor — survives autosave corruption (e.g. EBITDA mistaken for cash). */
function wlStampCashAnchor(G){
  if(!G||!Number.isFinite(G.cash))return;
  G._wlCashAnchor=G.cash;
}
/** Canonical mid-period economics stamped into every save/autosave blob. */
function wlStampPersistedEconomics(G){
  if(!G||!Array.isArray(G.stations)||!G.stations.length)return;
  wlStampCashAnchor(G);
  const byId=Object.create(null);
  const byCall=Object.create(null);
  (G.stations||[]).forEach(s=>{
    if(!s?.id)return;
    const fin=s.fin?JSON.parse(JSON.stringify(s.fin)):null;
    const ratShare=s.rat&&typeof s.rat.share==='number'?s.rat.share:null;
    byId[s.id]={fin,ratShare};
    const cl=s.callLetters?String(s.callLetters).trim().toUpperCase():'';
    if(cl)byCall[cl]={id:s.id,fin,ratShare};
  });
  G._wlPersistedEconomicsV1={
    v:1,
    year:Number(G.year)||1970,
    period:Number(G.period)||1,
    turn:Number(G.turn)||0,
    cash:Number(G.cash)||0,
    cashAnchor:Number.isFinite(G._wlCashAnchor)?G._wlCashAnchor:null,
    byId,
    byCall,
  };
}
function wlEconomicsRowForStation(s,snap){
  if(!s||!snap)return null;
  const byId=snap.byId;
  if(byId&&byId[s.id])return byId[s.id];
  const byCall=snap.byCall;
  const cl=s.callLetters?String(s.callLetters).trim().toUpperCase():'';
  if(byCall&&cl&&byCall[cl])return byCall[cl];
  return null;
}
/** Restore wallet + per-station fin from the save blob (mid-period snapshot). */
function wlRestoreResumeEconomicsSnapshot(G,snap){
  if(!G||!snap)return;
  const cash=wlResolveAuthoritativeResumeCash(G,snap);
  if(Number.isFinite(cash))G.cash=cash;
  (G.stations||[]).forEach(s=>{
    if(!s?.id)return;
    const row=wlEconomicsRowForStation(s,snap);
    if(!row)return;
    if(row.fin&&s.fin)Object.assign(s.fin,row.fin);
    if(row.ratShare!=null&&s.rat)s.rat.share=row.ratShare;
  });
}
function wlCaptureResumeEconomicsSnapshot(srcG){
  const persisted=srcG?._wlPersistedEconomicsV1;
  const py=Number(srcG?.year)||1970,pp=Number(srcG?.period)||1,pt=Number(srcG?.turn)||0;
  if(
    persisted&&persisted.v===1&&
    Number(persisted.year)===py&&Number(persisted.period)===pp&&Number(persisted.turn)===pt&&
    persisted.byId&&typeof persisted.byId==='object'
  ){
    const fh=srcG?.finHistory;
    const fhTail=fh?.length?fh[fh.length-1]:null;
    const fhCash=Number(fhTail?.cash);
    return{
      cash:Number.isFinite(Number(persisted.cash))?Number(persisted.cash):Number(srcG?.cash)||0,
      cashAnchor:Number.isFinite(Number(persisted.cashAnchor))?Number(persisted.cashAnchor):null,
      finHistoryCash:Number.isFinite(fhCash)?fhCash:null,
      byId:JSON.parse(JSON.stringify(persisted.byId)),
      byCall:persisted.byCall?JSON.parse(JSON.stringify(persisted.byCall)):null,
    };
  }
  const byId=Object.create(null);
  const byCall=Object.create(null);
  (srcG?.stations||[]).forEach(s=>{
    if(!s?.id)return;
    const fin=s.fin?JSON.parse(JSON.stringify(s.fin)):null;
    const ratShare=s.rat&&typeof s.rat.share==='number'?s.rat.share:null;
    byId[s.id]={fin,ratShare};
    const cl=s.callLetters?String(s.callLetters).trim().toUpperCase():'';
    if(cl)byCall[cl]={id:s.id,fin,ratShare};
  });
  const fh=srcG?.finHistory;
  const fhTail=fh?.length?fh[fh.length-1]:null;
  const anchor=Number(srcG?._wlCashAnchor);
  const fhCash=Number(fhTail?.cash);
  return{
    cash:Number(srcG?.cash)||0,
    cashAnchor:Number.isFinite(anchor)?anchor:null,
    finHistoryCash:Number.isFinite(fhCash)?fhCash:null,
    byId,
    byCall,
  };
}
/** Detect wallet field overwritten with mid-period EBITDA (or otherwise collapsed vs finHistory). */
function wlResolveAuthoritativeResumeCash(G,snap){
  let cash=Number(snap?.cash);
  if(!Number.isFinite(cash))cash=0;
  const portEbitda=Math.round((G.ps||[]).reduce((s,st)=>s+(Number(st.fin?.ebitda)||0),0));
  const fhCash=Number.isFinite(Number(snap?.finHistoryCash))?Number(snap.finHistoryCash):null;
  const anchor=Number.isFinite(Number(snap?.cashAnchor))?Number(snap.cashAnchor):null;
  const matchesEbitda=cash<0&&portEbitda<0&&Math.abs(cash-portEbitda)<=Math.max(50,Math.abs(portEbitda)*0.02);
  const collapsedVsHistory=fhCash!=null&&fhCash>10000&&cash<fhCash*0.05;
  if(matchesEbitda||collapsedVsHistory){
    const repaired=Math.max(anchor||0,fhCash||0);
    if(repaired>cash){
      if(typeof console!=='undefined'&&console.warn)console.warn('[resume] repaired suspicious cash',cash,'→',repaired,{matchesEbitda,collapsedVsHistory});
      return repaired;
    }
  }
  return cash;
}
/** Post-migrate load hydration: ratings repair only when needed; never rewrite saved mid-period fin on load. */
function wlHydrateGameAfterLoad(G,snap){
  const _loading=!!G._wlLoadingFromSave;
  normalizeSimulcastLinksInPlace(G);
  enforceFmNonDupConstraints(G);
  const _needsRatingsRefresh=wlResumeNeedsRatingsEconomicsRefresh(G);
  if(_needsRatingsRefresh){
    recalc(G.stations,G);
    wlRestoreFlatlinedLiveRatingsIfNeeded(G);
    const _resumeGate=wlAssertBookCloseInvariants(G,{allowMidPeriod:true});
    if(!_resumeGate.ok)wlRepairBookCloseForGate(G);
    if(!_loading){
      seedRev(G.stations,G);
      updateAllStationsBudgetStress(G);
    }
  }else{
    try{recalcDaypartAudience(G.stations,G);}catch(_e){}
  }
  repairPhantomRankerHistorySnaps(G);
  scrubFinHistoryPhantomEconomicsBooks(G);
  scrubFinHistoryFlatlineBooks(G);
  scrubStationRatHistBooks(G);
  reconcileBookDisplaySnapToLastCompletedRankerBook(G);
  wlRunGameIntegrityRepair(G,{phase:'load',silent:true});
  wlRestoreResumeEconomicsSnapshot(G,snap);
  return _needsRatingsRefresh&&!_loading;
}
/** Shared solo load/resume — autosave, cloud, and file import must behave identically. */
async function wlApplyLoadedGamePayload(payload,opts){
  const source=opts?.source||'load';
  const label=opts?.label||payload?.label||'Save';
  if(!payload?.G||payload.G.year==null)throw new Error('Invalid save file');
  await wlRefreshTrialLockFromServer();
  if(!wlTrialSaveResumeAllowed({ G: payload.G, campaign: payload.campaign })){
    showToast('This save does not match your free trial. Load your trial save, or subscribe for full access.','warn',9200);
    return null;
  }
  if(!G)G={};
  const _econSnap=wlCaptureResumeEconomicsSnapshot(payload.G);
  G._wlLoadingFromSave=true;
  try{
    Object.assign(G,payload.G);
    applyLoadedGameMarket();
    migrateSave(G);
    if(!G.news)G.news=[];
    try{
      if(typeof wlCampaignLoadFromSave==='function')wlCampaignLoadFromSave(payload.campaign);
      if(typeof wlCampaignHandleLoadedGame==='function')wlCampaignHandleLoadedGame(G);
      if(typeof wlCampaignSyncFromGame==='function')wlCampaignSyncFromGame(G);
      if(typeof wlCampaignRepairLoadedGameIfMarketMismatch==='function')wlCampaignRepairLoadedGameIfMarketMismatch(G);
      if(typeof wlCampaignScrubPendingEndForNonCareerGame==='function')wlCampaignScrubPendingEndForNonCareerGame(G);
    }catch(_e){}
    const _audienceRepaired=wlHydrateGameAfterLoad(G,_econSnap);
    wlRestoreResumeEconomicsSnapshot(G,_econSnap);
    wlStampPersistedEconomics(G);
    const _srcMsg=source==='resume_autosave'?'Autosave resumed':source==='cloud'?'Cloud save loaded':'Save loaded';
    G.news.unshift({
      v:'HIGH',
      t:`📂 ${_srcMsg}: ${label} — Cash on hand ${f$(G.cash)}${_audienceRepaired?' (audience data repaired under the hood; your saved finances were kept)':''}`,
      y:G.year,
      p:G.period,
    });
    cm('m-save');
    renderAll();
    maybeRefreshOpenRankerModal();
    queuePlayerTalentPortraits();
    queueAutoLogosForPlayerStations();
    if(source==='resume_autosave'){
      wlTrackSoloSession({
        source:'resume_autosave',
        scenarioId:(G.sc&&G.sc.id)||'unknown',
        marketId:G.marketId||'atlanta',
      });
      try{wlAnalyticsTrackGameResumedSolo();}catch(_e){}
      if(MP.mode!=='live'&&typeof wlCampaignShouldBlockAdvTurn==='function'&&wlCampaignShouldBlockAdvTurn(G)){
        if(typeof global.wlCampaignEnsureEndModalVisible==='function')global.wlCampaignEnsureEndModalVisible(G);
      }else{
        cm('m-scen');
      }
    }
    return{audienceRepaired:_audienceRepaired,econSnap:_econSnap};
  }finally{
    delete G._wlLoadingFromSave;
  }
}
function loadLocalSave(){
  void loadLocalSaveAsync();
}
async function loadLocalSaveAsync(){
  const local=getLocalSave();
  if(!local?.G)return;
  await wlApplyLoadedGamePayload(local,{source:'resume_autosave',label:local.label||'Autosave'});
}

if(typeof globalThis!=='undefined'){globalThis.loadLocalSave=loadLocalSave;}

// ── LOAN UI (capacity-based line of credit; see bank lending helpers near scoring) ──

// ── STATION HISTORY MODAL ────────────────────────────────────────────────
const HIST_ICONS={'FORMAT':'📻','TALENT':'🎙','IDENTITY':'🏘','RATINGS':'📊','LAUNCH':'📡','NOTE':'📝','CALLSIGN':'📇','LOGO':'🖼','SIMULCAST':'📡','BRAND':'✨'};

function renderHistoryRows(hist, fuzzy){
  if(!hist||!hist.length) return '<div class="sr"><span style="color:var(--mut)">No recorded history yet.</span></div>';
  return hist.map(e=>{
    const icon=HIST_ICONS[e.type]||'📝';
    const yr=e.y?`<span style="color:var(--mut);font-size:13px;margin-left:auto">${e.y}</span>`:'';
    // Fuzzy mode (competitor intel): hide talent names, show format/ratings only
    if(fuzzy&&e.type==='TALENT') return '';
    const label=e.type==='FORMAT'||e.type==='CALLSIGN'||e.type==='LOGO'||e.type==='BRAND'?'var(--amb)':e.type==='IDENTITY'?'var(--grn)':e.type==='RATINGS'?'var(--yel)':'var(--off)';
    return `<div class="sr" style="gap:8px;padding:6px 0;border-bottom:1px solid rgba(255,255,255,.04)">
      <span style="font-size:18px;line-height:1">${icon}</span>
      <span style="font-family:var(--ft);font-size:14px;color:${label};flex:1">${e.msg}</span>
      ${yr}
    </div>`;
  }).filter(Boolean).join('');
}

function openHistory(sid){
  const s=G.stations.find(st=>st.id===sid);if(!s)return;
  const op=simulcastOperationalSource(s);
  const hist=s._history||[];
  document.getElementById('hist-title').textContent=`${callDisplay(s)} — STATION HISTORY`;
  const fmtAge=op._formatAge?Math.round(op._formatAge/2)+' yrs on current format':'';
  const idLine=op.identity?`Identity: ${Math.round(op.identity)}/100`:'';
  document.getElementById('histb').innerHTML=`
    <div class="ms2" style="margin-bottom:4px">
      <div class="msh">${fmtLabel(op.format)}${fmtAge?' · '+fmtAge:''}${idLine?' · '+idLine:''}</div>
      ${renderHistoryRows(hist,false)}
    </div>
    <button class="cnl" onclick="cm('m-hist')">CLOSE</button>`;
  om('m-hist');
}

// ── STATION HISTORY LOG ───────────────────────────────────────────────────
// Records key station moments: launches, reformats, brand, talent moves, positioning,
// ratings milestones, identity milestones, call letter and logo changes. Shown on station card + intel.
function logHistory(s, type, msg, G){
  if(!s) return;
  if(!s._history) s._history=[];
  s._history.unshift({type, msg, y:G?.year||0, p:G?.period||0});
  // Cap at 50 entries to avoid save bloat
  if(s._history.length>50) s._history=s._history.slice(0,50);
}
/** Append simulcast history to both stations (never replaces _history). */
function logSimulcastPairHistory(src,dst,Gref){
  if(!src||!dst||!Gref)return;
  logHistory(src,'SIMULCAST',`Simulcast partner: ${dst.callLetters} carries this station's programming.`,Gref);
  logHistory(dst,'SIMULCAST',`Simulcast: programming supplied by ${src.callLetters} (${fmtLabel(src.format)}).`,Gref);
}
function updRepay(loanId, maxOwed, rawVal){
  const amt=Math.min(parseInt(rawVal)||0, maxOwed);
  const remaining=Math.max(0, maxOwed-amt);
  const valEl=document.getElementById('rpay-val-'+loanId);
  const noteEl=document.getElementById('rpay-note-'+loanId);
  const btnEl=document.getElementById('rpay-btn-'+loanId);
  if(valEl) valEl.textContent=f$(amt);
  if(noteEl){
    if(remaining===0) noteEl.innerHTML='<span style="color:var(--grn)">✓ Full repayment — balance cleared</span>';
    else noteEl.innerHTML=`Remaining principal: <strong style="color:var(--amb)">${f$(remaining)}</strong>`;
  }
  if(btnEl) btnEl.textContent=`PAY ${f$(amt)}`;
}

function updBorrowPreview(rawVal){
  const v=Math.max(0,parseInt(rawVal,10)||0);
  const el=document.getElementById('loan-borrow-display');
  if(el) el.textContent=f$(v);
}
/** Quick-pick in financing modal: `frac` is 0–1 of max slider. */
function setLoanBorrowFrac(frac){
  const el=document.getElementById('loan-borrow-slider');
  if(!el) return;
  const maxB=parseInt(el.max,10)||0;
  const minB=parseInt(el.min,10)||0;
  const v=Math.max(minB,Math.round(maxB*Math.max(0,Math.min(1,frac))));
  el.value=String(v);
  updBorrowPreview(v);
}

function doRepayPartial(loanId){
  if(!G.loans)return;
  const loan=G.loans.find(l=>(l.id+'')===(loanId+''));
  if(!loan)return;
  const pid=loanPidForGame();
  const bal=loan.principal!=null?loan.principal:loan.owed;
  const sliders=document.querySelectorAll(`input[oninput*="updRepay('${loanId}'"]`);
  let amt=bal;
  if(sliders.length) amt=Math.min(parseInt(sliders[0].value,10)||bal, bal);
  if(amt<=0){showToast('Choose a payment amount greater than zero.','warn');return;}
  if(amt<bal&&amt<10000){showToast('Partial payments must be at least $10,000 — or pay the full remaining balance.','warn');return;}
  if(G.cash<amt){showToast(`Need ${f$(amt-G.cash)} more to make this payment.`,'warn');return;}
  G.cash-=amt;
  const fullRepay=(amt>=bal);
  if(fullRepay){
    G.loans=G.loans.filter(l=>(l.id+'')!==(loanId+''));
    if(G._playerLoans?.[pid]) G._playerLoans[pid]=G._playerLoans[pid].filter(l=>(l.id+'')!==(loanId+''));
    G.news.unshift({v:'LOW',t:`💳 ${loan.label||'Line of credit'} fully repaid.`,y:G.year,p:G.period});
    MP.action('repay',{loanKey:loanId,amt:bal});
  } else {
    const rem=bal-amt;
    if(loan.principal!=null) loan.principal=rem; else loan.owed=rem;
    if(G._playerLoans?.[pid]){
      const mp=G._playerLoans[pid].find(l=>(l.id+'')===(loanId+''));
      if(mp){
        if(mp.principal!=null) mp.principal=rem; else mp.owed=rem;
      }
    }
    G.news.unshift({v:'LOW',t:`💳 ${loan.label||'Line of credit'}: ${f$(amt)} toward principal. ${f$(rem)} left.`,y:G.year,p:G.period});
    MP.action('repay_partial',{loanKey:loanId,amt,remaining:rem});
  }
  if(MP.mode==='live'){if(!G._playerCash)G._playerCash={};G._playerCash[pid]=G.cash;MP.emit('player_cash_update',{playerId:pid,cash:G.cash});}
  openLoan();renderAll();
}

function openLoan(){
  const pid=loanPidForGame();
  if(MP.mode==='live'&&G._mpBankrupt?.[pid]){
    document.getElementById('loanb').innerHTML='<p class="di">You are observing this market — financing is closed.</p><button class="cnl" onclick="cm(\'m-loan\')">CLOSE</button>';
    om('m-loan');
    return;
  }
  if(MP.mode!=='live'&&G._soloBankrupt){
    document.getElementById('loanb').innerHTML='<p class="di">Your company is out of active play.</p><button class="cnl" onclick="cm(\'m-loan\')">CLOSE</button>';
    om('m-loan');
    return;
  }
  const activeLoans=G.loans||[];
  const totalPrincipal=activeLoans.reduce((s,l)=>s+loanPrincipalFromEntry(l),0);
  const coVal=totalEstimatedCompanyValue(G,pid);
  const cap=borrowingCapacityForPlayer(G,pid);
  const debt=debtPrincipalForPid(G,pid);
  const headroomCap=Math.max(0,cap-debt);
  const headroomLev=Math.max(0,Math.floor(LOAN_MAX_LEVERAGE_FRAC*cap)-debt);
  const avail=Math.min(headroomCap,headroomLev);
  const effRate=effectiveAnnualLoanRate(G,pid);
  const lev=loanLeverageRatio(G,pid);
  const perInt=debt>0?Math.round(debt*(effRate/2)):0;
  const negSt=G._loanNegEbitdaStreak?.[pid] ?? 0;
  let warn='';
  if(negSt>=LOAN_MAX_NEG_EBITDA_STREAK_FOR_NEW_DEBT) warn='<div class="wbox" style="border-color:var(--red)"><strong>Operating losses streak.</strong> No new debt until EBITDA turns positive or you repay principal.</div>';
  else if(negSt>=1) warn='<div class="ibox" style="border-color:var(--amb)">Operating loss streak — rates rise; another loss period may freeze new borrowing.</div>';
  if(lev>=0.82) warn+='<div class="wbox" style="border-color:var(--red)"><strong>Debt load critical.</strong> Distress and bankruptcy remain possible if cash stays weak.</div>';
  else if(lev>=0.65) warn+='<div class="ibox" style="border-color:var(--amb)">Debt load is elevated — interest costs rise with what you owe.</div>';

  const loanRows=activeLoans.length?activeLoans.map(l=>{
    const o=Math.max(0,Math.round(l.principal!=null?l.principal:l.owed));
    const under10k=o>0&&o<=10000;
    const minSl=under10k?o:10000;
    const stepSl=under10k?1:1000;
    const lowLbl=under10k?`Full: ${f$(o)}`:'$10K min';
    const rateNote=l.rateAtLastDraw!=null?`<div class="sr"><span class="lb" style="color:var(--mut)">Last draw rate</span><span class="vl">${(l.rateAtLastDraw*100).toFixed(1)}% /yr</span></div>`:'';
    return`
    <div style="padding:10px 0;border-bottom:1px solid var(--bdh)">
      <div class="sr">
        <span class="lb">${l.label||'Line of credit'}</span>
        <span class="vl neg">${f$(o)} principal</span>
      </div>
      ${rateNote}
      <div class="slsec" style="margin-top:8px">
        <div class="sll" style="margin-bottom:4px"><span style="color:var(--mut);font-size:14px">PAYMENT AMOUNT</span><strong id="rpay-val-${l.id}">${f$(o)}</strong></div>
        <input type="range" min="${minSl}" max="${o}" step="${stepSl}" value="${o}"
               oninput="updRepay('${l.id}',${o},this.value)">
        <div style="display:flex;justify-content:space-between;font-family:var(--ft);font-size:13px;color:var(--mut);margin-top:3px"><span>${lowLbl}</span><span>Full: ${f$(o)}</span></div>
        <div class="sln2" id="rpay-note-${l.id}">Remaining principal: <strong>${f$(0)}</strong></div>
      </div>
      <button class="abt g" id="rpay-btn-${l.id}" style="width:100%;margin-top:6px;font-size:15px" onclick="doRepayPartial('${l.id}')">PAY ${f$(o)}</button>
    </div>`;
  }).join(''):'<div class="sr"><span class="lb" style="color:var(--mut)">No principal outstanding.</span></div>';

  const maxB=avail;
  const step=maxB>=5000?5000:(maxB>=1000?1000:Math.max(1,Math.floor(maxB)));
  const smin=Math.min(step,maxB);
  const borrowChk=maxB>0?canBorrowAmount(G,pid,maxB):{ok:false,reason:''};
  let borrowSection='';
  if(maxB<=0) borrowSection='<div class="ibox">No borrowing room left — repay principal or improve station performance.</div>';
  else if(!borrowChk.ok) borrowSection=`<div class="ibox" style="color:var(--amb)">${borrowChk.reason}</div>`;
  else borrowSection=`
    <div class="ms2"><div class="msh">DRAW ON THE LINE</div>
      <div class="slsec" style="margin-top:8px">
        <div class="sll" style="margin-bottom:4px"><span style="color:var(--mut);font-size:14px">AMOUNT</span><strong id="loan-borrow-display">${f$(maxB)}</strong></div>
        <input type="range" id="loan-borrow-slider" min="${smin}" max="${maxB}" step="${step}" value="${maxB}"
               oninput="updBorrowPreview(this.value)">
        <div style="display:flex;justify-content:space-between;font-family:var(--ft);font-size:13px;color:var(--mut);margin-top:3px"><span>Min ${f$(smin)}</span><span>Max ${f$(maxB)}</span></div>
        <div style="display:flex;flex-wrap:wrap;gap:6px;margin-top:8px">
          <button type="button" class="abt" style="font-size:12px;padding:6px 10px" onclick="setLoanBorrowFrac(0.25)">25%</button>
          <button type="button" class="abt" style="font-size:12px;padding:6px 10px" onclick="setLoanBorrowFrac(0.5)">Half</button>
          <button type="button" class="abt" style="font-size:12px;padding:6px 10px" onclick="setLoanBorrowFrac(0.75)">75%</button>
          <button type="button" class="abt" style="font-size:12px;padding:6px 10px" onclick="setLoanBorrowFrac(1)">Max</button>
        </div>
      </div>
      <button class="abt b" style="width:100%;margin-top:8px" onclick="doBorrowConfirm()">BORROW SELECTED AMOUNT</button>
    </div>`;

  document.getElementById('loanb').innerHTML=`
    <p class="di">Borrow against your stations’ estimated value (like real broadcast-secured lending). <strong>Principal</strong> is what you owe; <strong>interest</strong> hits cash each half-year. Rates rise when debt is heavy or you are coming off losses.</p>
    <div class="ms2"><div class="msh">YOUR BANKING SNAPSHOT</div>
      <div class="sr"><span class="lb">Est. company value (stations)</span><span class="vl">${f$(coVal)}</span></div>
      <div class="sr"><span class="lb">Borrowing room (${Math.round(LOAN_BORROW_CAP_FRAC*100)}% of value, EBITDA-adjusted)</span><span class="vl">${f$(cap)}</span></div>
      <div class="sr"><span class="lb">Principal outstanding</span><span class="vl neg">${f$(debt)}</span></div>
      <div class="sr"><span class="lb">Available to borrow</span><span class="vl ${avail>0?'pos':'neg'}">${f$(avail)}</span></div>
      <div class="sr"><span class="lb">Effective annual rate (now)</span><span class="vl">${(effRate*100).toFixed(1)}%</span></div>
      <div class="sr"><span class="lb">Interest this period (est.)</span><span class="vl neg">${debt?f$(perInt):'$0'}</span></div>
      <div class="sr"><span class="lb">Debt load (owed / borrowing room)</span><span class="vl">${Math.round(lev*100)}%</span></div>
      ${headroomCap>avail&&avail>0?`<div class="sr"><span class="lb" style="color:var(--mut);font-size:14px">Borrowing note</span><span class="vl" style="font-size:14px;color:var(--mut)">New draws stop around ~${Math.round(LOAN_MAX_LEVERAGE_FRAC*100)}% debt load — not the full borrowing room.</span></div>`:''}
      ${negSt>0?`<div class="sr"><span class="lb">Operating-loss streak</span><span class="vl ${negSt>=LOAN_MAX_NEG_EBITDA_STREAK_FOR_NEW_DEBT?'neg':'amb'}">${negSt} period(s)</span></div>`:''}
    </div>
    ${warn}
    ${activeLoans.length?`<div class="ms2"><div class="msh">REPAY PRINCIPAL — ${f$(totalPrincipal)} TOTAL</div>${loanRows}</div>`:''}
    ${borrowSection}
    <div class="ibox">Cash on hand: <strong>${f$(G.cash)}</strong> · Outstanding debt reduces decade score.</div>
    <button class="cnl" onclick="cm('m-loan')">CLOSE</button>`;
  activeLoans.forEach(l=>{
    const o=Math.max(0,Math.round(l.principal!=null?l.principal:l.owed));
    updRepay(l.id,o,String(o));
  });
  om('m-loan');
}

function doBorrowConfirm(){
  const pid=loanPidForGame();
  const el=document.getElementById('loan-borrow-slider');
  const amount=Math.round(parseInt(el&&el.value,10)||0);
  const chk=canBorrowAmount(G,pid,amount);
  if(!chk.ok){showToast(chk.reason,'warn');return;}
  if(!G._playerLoans)G._playerLoans={};
  if(!G._playerLoans[pid])G._playerLoans[pid]=[];
  G.loans=G._playerLoans[pid];
  let f=G.loans.find(l=>l.kind==='facility'||l.id==='credit');
  if(!f){
    f={id:'credit',kind:'facility',label:'Line of credit',principal:0,takenYear:G.year,openedYear:G.year,openedPeriod:G.period};
    G.loans.push(f);
  }
  f.principal=(f.principal||0)+amount;
  f.rateAtLastDraw=effectiveAnnualLoanRate(G,pid);
  if(f.openedYear==null){ f.openedYear=G.year; f.openedPeriod=G.period; }
  G.cash=(G.cash||0)+amount;
  if(MP.mode==='live'){
    if(!G._playerCash)G._playerCash={};
    G._playerCash[pid]=G.cash;
    MP.emit('player_cash_update',{playerId:pid,cash:G.cash});
    MP.action('loan',{amount});
  }
  G.news.unshift({v:'MEDIUM',t:`💳 Line of credit: ${f$(amount)} received. Principal now ${f$(f.principal)}.`,y:G.year,p:G.period});
  openLoan();
  renderAll();
}

function doRepay(loanKey){
  if(!G.loans)return;
  const loan=G.loans.find(l=>(l.id+'')===(loanKey+''));
  if(!loan)return;
  const bal=loan.principal!=null?loan.principal:loan.owed;
  if(G.cash<bal){alert(`Need ${f$(bal-G.cash)} more to repay.`);return;}
  const pid=loanPidForGame();
  G.cash-=bal;
  G.loans=G.loans.filter(l=>(l.id+'')!==(loanKey+''));
  if(G._playerLoans?.[pid]) G._playerLoans[pid]=G._playerLoans[pid].filter(l=>(l.id+'')!==(loanKey+''));
  G.news.unshift({v:'LOW',t:`💳 ${loan.label||'Line of credit'} fully repaid.`,y:G.year,p:G.period});
  MP.action('repay',{loanKey,amt:bal});
  if(MP.mode==='live'){if(!G._playerCash)G._playerCash={};G._playerCash[pid]=G.cash;MP.emit('player_cash_update',{playerId:pid,cash:G.cash});}
  openLoan();
  renderAll();
}

function applyLoanInterest(){
  if(!G._lastLoanInterestByPlayer) G._lastLoanInterestByPlayer = {};
  if(!G._lastLoanRateByPlayer) G._lastLoanRateByPlayer = {};
  G._lastLoanInterestCharge = 0;
  const applyCharge = pid=>{
    if(G._mpBankrupt?.[pid]) return;
    const pr = debtPrincipalForPid(G, pid);
    if(pr <= 0) return;
    const rate = effectiveAnnualLoanRate(G, pid);
    G._lastLoanRateByPlayer[pid] = rate;
    const interest = Math.round(pr * (rate/2));
    if(interest <= 0) return;
    if(MP.mode==='live'){
      if(!G._playerCash) G._playerCash = {};
      G._playerCash[pid] = (G._playerCash[pid]||0) - interest;
      G._lastLoanInterestByPlayer[pid] = interest;
      if(MP.playerId===pid) G.cash = G._playerCash[pid];
    } else {
      G.cash = (G.cash||0) - interest;
      G._lastLoanInterestCharge = interest;
    }
  };
  if(MP.mode==='live'){
    const pids = new Set();
    Object.keys(G._playerLoans||{}).forEach(k=> pids.add(Number(k)));
    G.ps.forEach(s=>{ if(s._mpOwner!=null) pids.add(s._mpOwner); });
    pids.forEach(applyCharge);
  } else {
    applyCharge(0);
  }
}

// 7. SELL STATION
/** When any `.ov` is open, lock page scroll so wheel/touch doesn’t move the game behind the modal (esp. Safari/iOS). */
const _wlModalScrollLock={active:false,y:0};
function syncModalBodyScrollLock(){
  const anyOpen=document.querySelector('.ov.on');
  if(anyOpen&&!_wlModalScrollLock.active){
    _wlModalScrollLock.y=window.scrollY||window.pageYOffset||0;
    document.documentElement.classList.add('wl-modal-open');
    document.body.classList.add('wl-modal-open');
    document.body.style.position='fixed';
    document.body.style.top=`-${_wlModalScrollLock.y}px`;
    document.body.style.left='0';
    document.body.style.right='0';
    document.body.style.width='100%';
    _wlModalScrollLock.active=true;
  }else if(!anyOpen&&_wlModalScrollLock.active){
    document.documentElement.classList.remove('wl-modal-open');
    document.body.classList.remove('wl-modal-open');
    document.body.style.position='';
    document.body.style.top='';
    document.body.style.left='';
    document.body.style.right='';
    document.body.style.width='';
    const y=_wlModalScrollLock.y;
    _wlModalScrollLock.active=false;
    _wlModalScrollLock.y=0;
    window.scrollTo(0,y);
  }else if(!anyOpen&&(document.body.classList.contains('wl-modal-open')||document.body.style.position==='fixed')){
    /* Stray lock (navigation / refresh / interrupted close) — don’t leave body fixed with no modal */
    document.documentElement.classList.remove('wl-modal-open');
    document.body.classList.remove('wl-modal-open');
    document.body.style.position='';
    document.body.style.top='';
    document.body.style.left='';
    document.body.style.right='';
    document.body.style.width='';
    _wlModalScrollLock.active=false;
    _wlModalScrollLock.y=0;
  }
}
if(typeof window!=='undefined')window.syncModalBodyScrollLock=syncModalBodyScrollLock;
window.addEventListener('pageshow',()=>{ syncModalBodyScrollLock(); });
/** Safari / tab switches: resync modal scroll lock so body is not left `position:fixed` with no visible modal (wheel dead + clicks swallowed). */
document.addEventListener('visibilitychange',()=>{
  if(document.visibilityState!=='visible')return;
  try{syncModalBodyScrollLock();}catch(_e){}
  try{wlRepairStuckPlayInteractionLayers();}catch(_e){}
});
/** Safari main view: clear stray modal lock / tutorial captures that swallow wheel + clicks until scroll. */
function wlRepairStuckPlayInteractionLayers(){
  if(typeof document==='undefined')return;
  syncModalBodyScrollLock();
  const anyModal=document.querySelector('.ov.on');
  if(anyModal)return;
  const tutActive=!!(_wlTuTr&&_wlTuTr.active);
  const expActive=typeof wlTutorialExpansionCoachActive==='function'&&wlTutorialExpansionCoachActive();
  const ftActive=!!(_wlFtTut&&_wlFtTut.active);
  if(!tutActive&&!expActive){
    try{wlTuTurnaroundTeardownShades();}catch(_e){}
    try{wlTuTurnaroundGateClear();}catch(_e){}
    if(_wlTuTr&&_wlTuTr.root&&!tutActive)_wlTuTr.root.style.display='none';
  }
  if(!ftActive){
    try{wlFtTutorialTeardownShades();}catch(_e){}
    if(_wlFtTut&&_wlFtTut.root&&!ftActive)_wlFtTut.root.style.display='none';
  }
}
if(typeof window!=='undefined')window.wlRepairStuckPlayInteractionLayers=wlRepairStuckPlayInteractionLayers;
(function wlInitPlayInteractionRepairOnce(){
  if(typeof window==='undefined'||window._wlPlayInteractionRepairInit)return;
  window._wlPlayInteractionRepairInit=true;
  const onWheel=()=>{
    if(document.querySelector('.ov.on'))return;
    if(document.body.style.position==='fixed'||document.body.classList.contains('wl-modal-open')){
      try{wlRepairStuckPlayInteractionLayers();}catch(_e){}
    }
  };
  window.addEventListener('wheel',onWheel,{passive:true,capture:true});
  window.addEventListener('touchmove',onWheel,{passive:true,capture:true});
})();
/** LIFO order of open `.ov` modals. Closing a modal also closes any that were opened above it (stack tail). */
const _wlModalStack=[];
function _wlModalZSync(){
  if(_wlModalStack.length===1){
    const one=document.getElementById(_wlModalStack[0]);
    if(one)one.style.removeProperty('z-index');
  }else if(_wlModalStack.length>1){
    /* Above turnaround coach (#wl-tu-tr-root ~13020) and #m-turnaround-tip (26000). */
    const zBase=42200;
    for(let k=0;k<_wlModalStack.length;k++){
      const o=document.getElementById(_wlModalStack[k]);
      if(o)o.style.setProperty('z-index',String(zBase+k*20),'important');
    }
  }
  try{
    document.querySelectorAll('.ov.on').forEach(o=>{
      if(o.id&&_wlModalStack.indexOf(o.id)<0)o.style.removeProperty('z-index');
    });
  }catch(e){}
}
