function recordCompanyFinHistory(G, wasYear, wasPeriod, profit){
  if(!G)return;
  const pushEntry=(pid,ps,pProfit,pCash)=>{
    const revenue=ps.reduce((s,st)=>s+st.fin.rev,0);
    const cost=ps.reduce((s,st)=>s+st.fin.cost,0);
    const margin=revenue>0?Math.round((pProfit/revenue)*100):0;
    const talentCost=ps.reduce((sum,s)=>sum+Object.values(s.prog).filter(sl=>sl?.talent).reduce((a,sl)=>a+payrollHalfPeriodForDaypartSlot(sl),0),0);
    const fixedCost=ps.reduce((s,st)=>s+(st.fin.fix||0),0);
    const shareSum=playerPortfolioBookShareSum01Deduped(G,ps);
    const avgSellout=ps.length?Math.round((ps.reduce((s,st)=>s+(st.ops?.sell||0),0)/ps.length)*1000)/1000:0;
    const _loanPid=pid!=null&&pid!==undefined?pid:0;
    const debtPrincipal=debtPrincipalForPid(G,_loanPid);
    const loanInterest=MP.mode==='live'?(G._lastLoanInterestByPlayer?.[_loanPid]||0):(G._lastLoanInterestCharge||0);
    const lmaNet=MP.mode==='live'?null:playerLmaCashNetForSolo(G).net;
    const pressureNet=MP.mode==='live'?null:(G._lastPressureCashDelta!=null?G._lastPressureCashDelta:0);
    const earlyPipelineNet=MP.mode==='live'?null:(G._advTurnEarlyPipelineCashDelta!=null?G._advTurnEarlyPipelineCashDelta:0);
    const entry={year:wasYear,period:wasPeriod,revenue,cost,ebitda:pProfit,margin,cash:pCash,talentCost,fixedCost,shareSum,avgSellout,debtPrincipal,loanInterest,lmaNet,pressureNet,earlyPipelineNet};
    return entry;
  };
  if(MP.mode==='live'){
    G._playerFinHistory=G._playerFinHistory||{};
    const owners=[...new Set((G.ps||[]).map(s=>s._mpOwner).filter(id=>id!==undefined&&id!==null))].sort((a,b)=>a-b);
    owners.forEach(pid=>{
      const ps=G.ps.filter(s=>s._mpOwner===pid);
      const pProfit=ps.reduce((s,st)=>s+st.fin.ebitda,0);
      const pCash=G._playerCash?.[pid]??0;
      if(!G._playerFinHistory[pid])G._playerFinHistory[pid]=[];
      G._playerFinHistory[pid].push(pushEntry(pid,ps,pProfit,pCash));
      if(G._playerFinHistory[pid].length>120)G._playerFinHistory[pid]=G._playerFinHistory[pid].slice(-120);
    });
    return;
  }
  G.finHistory=G.finHistory||[];
  const ps=myPS();
  const cash=G.cash;
  G.finHistory.push(pushEntry(null,ps,profit,cash));
  if(G.finHistory.length>120)G.finHistory=G.finHistory.slice(-120);
}
function recordStationFinHistory(G, wasYear, wasPeriod){
  if(!G)return;
  G.stationFinHistory=G.stationFinHistory||{};
  const toRecord=MP.mode==='live'?(G.ps||[]).filter(Boolean):myPS();
  toRecord.forEach(st=>{
    if(!G.stationFinHistory[st.id])G.stationFinHistory[st.id]=[];
    const rev=st.fin.rev||0,stcost=st.fin.cost||0,ebit=st.fin.ebitda||0;
    const margin=rev>0?Math.round((ebit/rev)*100):0;
    const sh=typeof st.rat?.share==='number'&&!Number.isNaN(st.rat.share)?st.rat.share:null;
    G.stationFinHistory[st.id].push({year:wasYear,period:wasPeriod,revenue:rev,cost:stcost,ebitda:ebit,margin,share:sh});
    if(G.stationFinHistory[st.id].length>120)G.stationFinHistory[st.id]=G.stationFinHistory[st.id].slice(-120);
  });
}

/** Book share for a closed period (station fin history / financials tables). */
function stationBookShareForPeriod(st,year,period){
  if(!st)return null;
  const ey=Number(year),ep=Number(period);
  const finHist=G.stationFinHistory?.[st.id];
  if(Array.isArray(finHist)){
    const row=finHist.find(h=>Number(h.year)===ey&&Number(h.period)===ep);
    if(row&&typeof row.share==='number'&&!Number.isNaN(row.share))return row.share;
  }
  const hist=st.rat?.hist;
  if(Array.isArray(hist)){
    const row=hist.find(h=>Number(h.year)===ey&&Number(h.period)===ep);
    if(row&&typeof row.share==='number'&&!Number.isNaN(row.share))return row.share;
  }
  return null;
}
function finHistoryRowShare(st,h){
  if(h&&typeof h.share==='number'&&!Number.isNaN(h.share))return h.share;
  return stationBookShareForPeriod(st,h.year,h.period);
}
function simulcastPairRankerHistoryKey(stA,stB){
  return 'p:'+[String(stA.id),String(stB.id)].sort().join(':');
}
/** Deduped combined simulcast share for a past book (financials cluster rows). */
function simulcastPairDedupedShareForFinPeriod(stA,stB,year,period,G){
  if(!stA||!stB||!G)return null;
  const ey=Number(year),ep=Number(period);
  const pk=simulcastPairRankerHistoryKey(stA,stB);
  const rh=G.rankerHistory;
  if(Array.isArray(rh)){
    const col=rh.find(c=>Number(c.year)===ey&&Number(c.period)===ep);
    if(col){
      const map=col.pairDedupedShare01ByKey;
      if(map&&typeof map==='object'&&typeof map[pk]==='number'&&!Number.isNaN(map[pk]))return map[pk];
      const sa=col.shares?.[stA.id],sb=col.shares?.[stB.id];
      if(typeof sa==='number'&&typeof sb==='number'){
        const mx=Math.max(sa,sb),mn=Math.min(sa,sb);
        return Math.round((mx+mn*SIMULCAST_SAME_FEED_AUDIENCE_INCREMENT)*1e8)/1e8;
      }
    }
  }
  const snap=G._mktRankBookSnap;
  if(snap&&Number(snap.year)===ey&&Number(snap.period)===ep){
    const row=(snap.rows||[]).find(r=>r&&r.key===pk);
    if(row&&typeof row.share==='number'&&!Number.isNaN(row.share))return row.share;
  }
  if(Number(G.year)===ey&&Number(G.period)===ep)return stationCardSimulcastCombinedShare01(stA,stB);
  return null;
}
function mergeSimulcastClusterFinHistory(src,flw,G){
  const lists=[G.stationFinHistory?.[src.id]||[],G.stationFinHistory?.[flw.id]||[]];
  const byKey=new Map();
  lists.forEach(list=>{
    list.forEach(h=>{
      if(!h)return;
      const k=Number(h.year)+'\x1e'+Number(h.period);
      if(!byKey.has(k))byKey.set(k,{year:h.year,period:h.period,revenue:0,cost:0,ebitda:0});
      const e=byKey.get(k);
      e.revenue+=(h.revenue||0);
      e.cost+=(h.cost||0);
      e.ebitda+=(h.ebitda||0);
    });
  });
  return [...byKey.values()].map(e=>{
    e.margin=e.revenue>0?Math.round((e.ebitda/e.revenue)*100):0;
    e.share=simulcastPairDedupedShareForFinPeriod(src,flw,e.year,e.period,G);
    return e;
  }).sort((a,b)=>a.year!==b.year?a.year-b.year:a.period-b.period);
}
function finHistoryShareCell(share01,title){
  if(share01==null||typeof share01!=='number'||Number.isNaN(share01))
    return '<td style="padding:4px 8px;text-align:right;color:var(--mut)">—</td>';
  const tip=title?` title="${String(title).replace(/&/g,'&amp;').replace(/"/g,'&quot;')}"`:'';
  return `<td style="padding:4px 8px;text-align:right"${tip}>${pct(share01)}</td>`;
}
function finHistorySimulcastShareTip(src,flw,h,combined01){
  const la=finHistoryRowShare(src,h),lb=finHistoryRowShare(flw,h);
  if(la==null||lb==null||combined01==null)
    return 'Combined share dedupes listeners who hear both AM and FM on the same feed (matches market rankings).';
  const sum=la+lb;
  return `Per-license book shares ${pct(la)} + ${pct(lb)} = ${pct(sum)}. Combined ${pct(combined01)} after same-feed overlap dedupe (matches market rankings). Revenue and costs below are still summed across both licenses.`;
}
function buildFinancialsHistoryTableHead(includeCash,shareColLabel){
  const shareHdr=shareColLabel||'Share';
  const cashTh=includeCash?'<th style="padding:6px 8px;border-bottom:1px solid var(--bdr);text-align:right">Cash</th>':'';
  return `<thead><tr style="color:var(--mut);text-align:left;font-family:var(--ft);letter-spacing:1px">
    <th style="padding:6px 8px;border-bottom:1px solid var(--bdr)">Year</th>
    <th style="padding:6px 8px;border-bottom:1px solid var(--bdr)">Period</th>
    <th style="padding:6px 8px;border-bottom:1px solid var(--bdr);text-align:right">${shareHdr}</th>
    <th style="padding:6px 8px;border-bottom:1px solid var(--bdr);text-align:right">Revenue</th>
    <th style="padding:6px 8px;border-bottom:1px solid var(--bdr);text-align:right">Costs</th>
    <th style="padding:6px 8px;border-bottom:1px solid var(--bdr);text-align:right">EBITDA</th>
    <th style="padding:6px 8px;border-bottom:1px solid var(--bdr);text-align:right">Margin</th>
    ${cashTh}
  </tr></thead>`;
}
function buildFinancialsHistoryTableRows(entries,opts){
  const getShare=opts&&opts.getShare;
  const getShareTitle=opts&&opts.getShareTitle;
  const includeCash=!!(opts&&opts.includeCash);
  return entries.map(h=>{
    const pnm=PERIODS[(h.period||1)-1]||'';
    const share01=getShare?getShare(h):h.share;
    const shareTip=getShareTitle?getShareTitle(h):'';
    const cashTd=includeCash?`<td style="padding:4px 8px;text-align:right">${f$(h.cash)}</td>`:'';
    return `<tr>
      <td style="padding:4px 8px;font-family:var(--fd)">${h.year}</td>
      <td style="padding:4px 8px;color:var(--mut)">${pnm}</td>
      ${finHistoryShareCell(share01,shareTip)}
      <td style="padding:4px 8px;text-align:right">${f$(h.revenue)}</td>
      <td style="padding:4px 8px;text-align:right">${f$(h.cost)}</td>
      <td style="padding:4px 8px;text-align:right;color:${h.ebitda>=0?'var(--grn)':'var(--red)'}">${h.ebitda>=0?'+':''}${f$(h.ebitda)}</td>
      <td style="padding:4px 8px;text-align:right">${h.margin}%</td>
      ${cashTd}
    </tr>`;
  }).join('');
}
function buildFinancialsStationHistoryBlock(title,entries,opts){
  if(!entries||!entries.length)return '';
  const rev=[...entries].reverse();
  const rows=buildFinancialsHistoryTableRows(rev,opts);
  const subtitle=opts&&opts.subtitle?`<p class="di" style="margin:6px 0 8px;font-size:13px;line-height:1.45">${opts.subtitle}</p>`:'';
  const shareCol=opts&&opts.shareColLabel;
  return `<div class="ms2" style="margin-top:14px"><div class="msh">${title}</div>${subtitle}
    <div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:14px">
      ${buildFinancialsHistoryTableHead(!!(opts&&opts.includeCash),shareCol)}
      <tbody>${rows}</tbody>
    </table></div></div>`;
}
function buildFinancialsStationHistoryBlocksHtml(G){
  const ps=myPS();
  const seen=new Set();
  const blocks=[];
  ps.forEach(st=>{
    if(!st||seen.has(st.id))return;
    const partner=simulcastPartnerStation(st);
    const legs=partner&&ps.some(x=>x.id===partner.id)?simulcastPairProgrammingLegs(st,partner):null;
    if(legs){
      seen.add(legs.src.id);
      seen.add(legs.flw.id);
      const srcHist=G.stationFinHistory?.[legs.src.id]||[];
      const flwHist=G.stationFinHistory?.[legs.flw.id]||[];
      const clusterHist=mergeSimulcastClusterFinHistory(legs.src,legs.flw,G);
      const clusterTitle=`${callDisplay(legs.src)}/${callDisplay(legs.flw)} Simulcast`;
      const simExplainer=`<div class="ms2 fin-simulcast-note" style="margin-top:14px;padding:10px 12px;border:1px solid rgba(216,155,43,.28);border-radius:6px;background:rgba(216,155,43,.06)"><p class="di" style="margin:0;font-size:13px;line-height:1.5"><strong>Simulcast shares:</strong> AM and FM each have their own license-level book share. Many listeners count on <em>both</em> dials — the <strong>combined</strong> row dedupes that overlap (same number as market rankings). <strong>Revenue and costs are always added</strong> across both licenses.</p></div>`;
      blocks.push(simExplainer);
      if(clusterHist.length)blocks.push(buildFinancialsStationHistoryBlock(clusterTitle,clusterHist,{
        shareColLabel:'Combined share',
        subtitle:'Overlap deduped — matches market ranker. Hover a share cell for the AM+FM breakdown.',
        getShare:h=>h.share,
        getShareTitle:h=>finHistorySimulcastShareTip(legs.src,legs.flw,h,h.share),
      }));
      if(srcHist.length)blocks.push(buildFinancialsStationHistoryBlock(callDisplay(legs.src),srcHist,{
        shareColLabel:'Leg share',
        subtitle:'This license’s book share only (do not add to FM for a market total).',
        getShare:h=>finHistoryRowShare(legs.src,h),
      }));
      if(flwHist.length)blocks.push(buildFinancialsStationHistoryBlock(callDisplay(legs.flw),flwHist,{
        shareColLabel:'Leg share',
        subtitle:'This license’s book share only (do not add to AM for a market total).',
        getShare:h=>finHistoryRowShare(legs.flw,h),
      }));
      return;
    }
    seen.add(st.id);
    const hist=G.stationFinHistory?.[st.id]||[];
    if(hist.length)blocks.push(buildFinancialsStationHistoryBlock(callDisplay(st),hist,{getShare:h=>finHistoryRowShare(st,h)}));
  });
  return blocks.join('');
}

function openFinancials(){
  if(!G)return;
  const r=companyFinanceRollup();
  const perName=PERIODS[(G.period||1)-1]||'';
  const histSrc=MP.mode==='live'
    ?(G._playerFinHistory?.[MP.playerId]||[])
    :(G.finHistory||[]);
  const hist=[...histSrc].reverse();
  const histRows=buildFinancialsHistoryTableRows(hist,{includeCash:true,getShare:h=>h.shareSum});
  const stHistBlocks=buildFinancialsStationHistoryBlocksHtml(G);
  document.getElementById('finb').innerHTML=`
    <div style="padding:16px 20px 20px;font-family:var(--ft);font-size:15px;max-height:min(72vh,640px);overflow-y:auto">
      <p class="di" style="margin-top:0">Company-wide totals from your owned stations (same basis as the period-end summary).</p>
      <div class="ms2"><div class="msh">${G.year} ${perName} — SNAPSHOT</div>
        <div class="sr"><span class="lb">Total revenue</span><span class="vl">${f$(r.revenue)}</span></div>
        <div class="sr"><span class="lb">Total expenses</span><span class="vl">${f$(r.cost)}</span></div>
        <div class="sr"><span class="lb">EBITDA</span><span class="vl ${r.ebitda>=0?'pos':'neg'}">${r.ebitda>=0?'+':''}${f$(r.ebitda)}</span></div>
        <div class="sr"><span class="lb">EBITDA margin</span><span class="vl">${r.margin}%</span></div>
        <div class="sr"><span class="lb" title="On-air pay only — host + co-host, annual, rounded to nearest $500.">Total annual talent pay</span><span class="vl">${f$(r.talentCostAnnual||0)}</span></div>
        <div class="sr"><span class="lb" title="This half-year period: payroll to talent (per station economics).">Talent payroll (this period)</span><span class="vl">${f$(r.talentCost)}</span></div>
        <div class="sr"><span class="lb">Total fixed cost</span><span class="vl">${f$(r.fixedCost)}</span></div>
        <div class="sr"><span class="lb">Cash on hand</span><span class="vl amb">${f$(r.cash)}</span></div>
        <div class="sr"><span class="lb">Owned share (sum)</span><span class="vl">${pct(r.shareSum)}</span></div>
        <div class="sr"><span class="lb">Avg sellout</span><span class="vl">${Math.round(r.avgSellout*100)}%</span></div>
        ${(G.year||0)>=2005?`<div class="sr"><span class="lb" title="Digital reflects streaming and on-demand audience extension.">Digital revenue (total)</span><span class="vl">${f$(r.digitalRev||0)}</span></div>
        <div class="sr"><span class="lb">Digital share (portfolio)</span><span class="vl">${r.digitalSharePct||0}%</span></div>`:''}
      </div>
      ${buildFinancialsPerformanceDriversHtml(G)}
      ${buildLateEraFinancialsPanelHtml(G)}
      <div class="ms2" style="margin-top:14px"><div class="msh">HISTORY (newest first)</div>
        ${hist.length?`<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:14px">
          ${buildFinancialsHistoryTableHead(true)}
          <tbody>${histRows}</tbody>
        </table></div>`:'<p class="enote">No closed periods recorded yet. Advance a period to build history.</p>'}
      </div>
      ${stHistBlocks?`<div class="ms2" style="margin-top:16px"><div class="msh">BY STATION (newest first)</div></div>${stHistBlocks}`:''}
    </div>`;
  om('m-fin');
}

// ── PERIOD SUMMARY ────────────────────────────────────────────────
function playerRelevantRightsActs(sportsActs,franchiseActs){
  const seen=new Set();
  const out=[];
  const mine=new Set(myPS().map(s=>s.callLetters));
  const consider=(arr)=>{
    (arr||[]).forEach(a=>{
      if(!a?.t||seen.has(a.t))return;
      if(MP.mode==='live'&&a.mpForPids&&a.mpForPids.length){
        if(a.mpForPids.includes(MP.playerId)){seen.add(a.t);out.push(a.t);}
        return;
      }
      if(a.iy||[...mine].some(c=>a.t.includes(c))){seen.add(a.t);out.push(a.t);}
    });
  };
  consider(sportsActs);
  consider(franchiseActs);
  return out;
}

// ── Performance explanation (qualitative drivers — no raw engine numbers) ──
/** Programming source vs follower in a linked pair (legacy mutual link or star source + receiver). */
function simulcastPairProgrammingLegs(a,b){
  if(!a||!b)return null;
  if(a.simulcastWith===b.id&&b.simulcastWith===a.id){
    if(a._simulcastSource===true)return{src:a,flw:b};
    if(b._simulcastSource===true)return{src:b,flw:a};
    return null;
  }
  if(a._simulcastSource===true&&b.simulcastSourceStationId===a.id)return{src:a,flw:b};
  if(b._simulcastSource===true&&a.simulcastSourceStationId===b.id)return{src:b,flw:a};
  return null;
}
// cat: 'audience' = ratings/revenue-from-audience, 'cost' = costs/profit/financing, 'cross' = both
function stationDriverCandidates(s,G,junior){
  const op=simulcastOperationalSource(s);
  const rev=junior?(s.fin.rev||0)+(junior.fin.rev||0):(s.fin.rev||0);
  const fix=junior?(s.fin.fix||0)+(junior.fin.fix||0):(s.fin.fix||0);
  const tal=junior?(s.fin.tal||0)+(junior.fin.tal||0):(s.fin.tal||0);
  const ebitda=junior?(s.fin.ebitda||0)+(junior.fin.ebitda||0):(s.fin.ebitda||0);
  const margin=rev>0?ebitda/rev:0;
  const pr=s.cp;
  const candidates=[];
  const add=(score,text,cat)=>{candidates.push({score,text,cat});};
  if(s.lmaLessorId){
    add(78,'Leased-out license — fee income with no operating spend on this line.','cost');
    return candidates;
  }
  const shareN=(junior?stationCardSimulcastCombinedShare01(s,junior):s.rat.share)||0;
  if(pr){
    if(pr.col) add(96,'Sharp share losses are cutting billing power.','cross');
    else if(pr.under) add(84,'Slipping share is capping what you can bill.','cross');
    else if(pr.sur) add(78,'Rising share is opening up ad demand.','audience');
  }
  if(rev>0){
    if(margin<-0.12) add(92,'Costs are running ahead of revenue — profits are squeezed.','cost');
    else if(margin<0.03&&ebitda<0) add(88,'Thin margins mean small revenue swings hit the bottom line hard.','cost');
    else if(margin>0.32&&(op.ops?.sell||0)>0.58) add(72,'Strong share and sellout are supporting profits.','cross');
    else if(margin>0.32) add(68,'Profits are holding up on decent margins at this signal.','cost');
    const fixR=fix/rev,talR=tal/rev;
    if(fixR>0.38){
      if(shareN<0.06) add(86,'High fixed costs are hard to cover at this share level.','cross');
      else add(84,'High fixed costs are pressuring profits despite the audience you have.','cross');
    }else if(fixR>0.28) add(58,'Fixed overhead is a big slice of every dollar you bill.','cost');
    if(talR>0.42) add(82,'Heavy talent payroll is weighing on margins.','cost');
    else if(talR>0.30) add(54,'Talent spend is a noticeable drag on profit.','cost');
  }
  const mdQ=Math.round(op.prog?.morningDrive?.quality||0);
  const slotQs=DAYPART_SLOTS.map(k=>Math.round(op.prog?.[k]?.quality||0)).filter(q=>q>0);
  const avgQ=slotQs.length?slotQs.reduce((a,b)=>a+b,0)/slotQs.length:mdQ;
  if(mdQ>=avgQ+10&&mdQ>=52) add(76,'Strong mornings are lifting overall audience.','audience');
  if(mdQ>0&&mdQ<avgQ-8&&mdQ<48) add(78,'Weak mornings are dragging overall audience share.','audience');
  const aftQ=Math.round(op.prog?.afternoonDrive?.quality||0);
  if(aftQ>0&&aftQ<avgQ-8&&aftQ<45) add(64,'Soft afternoons are letting listeners slip away.','audience');
  if(op.oq>=72) add(66,'High programming quality is helping ratings hold up.','audience');
  else if(op.oq<=38) add(74,'Thin programming is holding back audience growth.','audience');
  const progBudget=op.ops?.progBudget||0;
  if(rev>0&&progBudget/rev<0.014&&op.oq<52) add(70,'Under-spend on programming is limiting audience growth.','cross');
  const sell=op.ops?.sell||0;
  if(sell<0.42) add(76,'Low sellout means share isn’t converting to full ad revenue.','cross');
  else if(sell>0.74) add(62,'Strong sellout is turning audience into ad dollars.','audience');
  if((G.year||0)>=2012&&rev>0){
    const dig=junior
      ?((s.fin.digitalRev??s.fin.streamRev)||0)+((junior.fin.digitalRev??junior.fin.streamRev)||0)
      :((s.fin.digitalRev??s.fin.streamRev)||0);
    const on=op.stream?.active;
    if(on&&dig/rev<0.045) add(71,'Digital is live but still a thin slice of revenue — talent and format fit still matter.','cross');
    if((G.year||0)>=2018&&!on) add(79,'No Digital investment yet — competitors with online reach are easier buys in the modern era.','cross');
    if(on&&dig/rev>=0.16) add(64,'Digital revenue is a meaningful part of the mix for this signal.','audience');
  }
  const fmp=G.fmp||0;
  const talkFmt=['NEWS_TALK','SPORTS_TALK','PERSONALITY_TALK','ALL_NEWS'].includes(op.format);
  if(s.sig.type==='AM'&&!talkFmt&&fmp>0.52) add(74,'This AM is losing listeners to FM — billing suffers.','cross');
  if(s.sig.type==='FM'&&fmp>0.48) add(50,'FM listening is strong here — tailwind for this signal.','audience');
  const sm=seasonMult(G.year,G.period,op.format);
  if(sm<0.9) add(46,'Soft season for this format — expect lighter billing.','audience');
  else if(sm>1.07) add(44,'Peak season is helping this format’s billings.','audience');
  if(junior){
    const legs=simulcastPairProgrammingLegs(s,junior);
    if(legs){
      const {src:srcLeg,flw:flwLeg}=legs;
      const srcCall=callDisplay(srcLeg), flwCall=callDisplay(flwLeg);
      const rS=srcLeg.fin?.rev||0,rF=flwLeg.fin?.rev||0;
      const eS=srcLeg.fin?.ebitda||0,eF=flwLeg.fin?.ebitda||0;
      const mS=rS>0?eS/rS:0,mF=rF>0?eF/rF:0;
      const costRtS=rS>0?(srcLeg.fin?.cost||0)/rS:0,costRtF=rF>0?(flwLeg.fin?.cost||0)/rF:0;
      const divProf=Math.abs(eS-eF)>30000,marginDiv=Math.abs(mS-mF)>0.11,costDiv=costRtS-costRtF>0.13;
      if(divProf||marginDiv||costDiv){
        let sc=64;
        if(divProf)sc+=10;
        if(costDiv)sc+=10;
        if(marginDiv)sc+=6;
        if(srcLeg.sig?.type==='AM'&&flwLeg.sig?.type==='FM'&&eF>eS+18000)
          add(Math.min(92,sc+8),'The AM ('+srcCall+') is carrying more programming cost while the FM ('+flwCall+') monetizes shared content with less cost on that license.','cross');
        else if(eF>eS+40000&&mF>mS+0.05)
          add(Math.min(90,sc+6),flwCall+' is more profitable this period — same programming, but economics favor the follower license.','cross');
        else if(costDiv)
          add(Math.min(86,sc),srcCall+' runs a heavier cost ratio; '+flwCall+' keeps a leaner load as the simulcast follower.','cross');
        else
          add(Math.min(82,sc-4),srcCall+' feeds the simulcast and carries most programming spend; '+flwCall+' adds reach without duplicating full production cost.','cross');
      }
    }
    const simFee=(s.fin?.simulcastProgFee||0)+(junior.fin?.simulcastProgFee||0);
    if(simFee>0) add(58,'Simulcast program fees are a small add-on — the point is savings vs. duplicating a full staff.','cost');
  }else if((s.fin?.simulcastProgFee||0)>0) add(58,'Simulcast program fees are a small add-on — you still save by sharing content across licenses.','cost');
  const pid=loanPidForGame();
  const lev=loanLeverageRatio(G,pid);
  const streakKey=MP.mode==='live'?MP.playerId:0;
  const streak=G._loanNegEbitdaStreak?.[streakKey]||0;
  if(lev>0.52) add(64,'Company debt is adding interest pressure on cash.','cost');
  else if(lev>0.36&&streak>=2) add(60,'Losses plus heavy debt are tightening financing room.','cost');
  return candidates.sort((a,b)=>b.score-a.score);
}
function pickBalancedStationDrivers(candidates,max){
  max=max||4;
  if(!candidates.length)return [];
  const byScore=[...candidates].sort((a,b)=>b.score-a.score);
  const majorCost=candidates.some(c=>c.cat==='cost'&&c.score>=80);
  const out=[];
  const used=new Set();
  const take=c=>{
    if(!c||used.has(c.text)||out.length>=max)return false;
    used.add(c.text);
    out.push(c.text);
    return true;
  };
  const cross=byScore.filter(c=>c.cat==='cross');
  const cost=byScore.filter(c=>c.cat==='cost');
  const aud=byScore.filter(c=>c.cat==='audience');
  if(majorCost){
    cost.slice(0,2).forEach(c=>take(c));
    aud.slice(0,1).forEach(c=>take(c));
    cross.forEach(c=>{if(out.length<max)take(c);});
  }else{
    if(cross.length&&cross[0].score>=62)take(cross[0]);
    take(cost[0]);
    take(aud[0]);
    for(const c of byScore){
      if(out.length>=max)break;
      take(c);
    }
  }
  if(!majorCost)return out.slice(0,max);
  for(const c of byScore){
    if(out.length>=max)break;
    take(c);
  }
  return out.slice(0,max);
}
function buildStationPerformanceDrivers(s,G,junior){
  const c=stationDriverCandidates(s,G,junior);
  let out=pickBalancedStationDrivers(c,4);
  if(!out.length){
    const e=junior?(s.fin.ebitda||0)+(junior.fin.ebitda||0):(s.fin.ebitda||0);
    const rev=junior?(s.fin.rev||0)+(junior.fin.rev||0):(s.fin.rev||0);
    out.push(e>=0&&rev>0
      ?'Audience and billing are relatively stable — no single major pressure point.'
      :'Results are tight — neither audience nor costs have a clear edge yet.');
  }
  return out.slice(0,4);
}
/** HTML for Financials modal — one driver block per station or combined simulcast pair (same logic as station cards). */
function buildFinancialsPerformanceDriversHtml(G){
  const ps=myPS();
  if(!ps.length)return '';
  const pairSeen=new Set();
  const chunks=[];
  for(const st of ps){
    const partner=simulcastPartnerStation(st);
    const isPair=partner&&ps.some(x=>x.id===partner.id);
    let junior=null, anchor=st;
    if(isPair){
      anchor=simulcastPairStationCardAnchor(st,partner);
      if(st.id!==anchor.id)continue;
      const pk=[st.id,partner.id].sort().join('|');
      if(pairSeen.has(pk))continue;
      pairSeen.add(pk);
      junior=partner;
    }
    const drv=buildStationPerformanceDrivers(anchor,G,junior);
    if(!drv.length)continue;
    const title=junior?callDisplay(anchor)+' + '+callDisplay(junior):callDisplay(anchor);
    chunks.push('<div class="sc-drivers fin-drivers"><div class="sc-drivers-h">'+title+'</div><ul>'+drv.map(t=>'<li>'+t+'</li>').join('')+'</ul></div>');
  }
  if(!chunks.length)return '';
  return '<div class="ms2" style="margin-top:14px"><div class="msh">WHAT’S DRIVING PERFORMANCE</div>'+chunks.join('')+'</div>';
}
function stationPeriodChangeLine(st,G){
  const hist=G.stationFinHistory?.[st.id];
  if(!hist||hist.length<2)return '';
  const cur=hist[hist.length-1], prev=hist[hist.length-2];
  const dE=cur.ebitda-prev.ebitda;
  const dRev=cur.revenue-prev.revenue;
  const dCost=cur.cost-prev.cost;
  const rh=st.rat?.hist;
  let dShare=0;
  if(rh&&rh.length>=2) dShare=(rh[rh.length-1]?.share||0)-(rh[rh.length-2]?.share||0);
  const bigDrop=dE<-Math.max(35000,Math.abs(prev.ebitda||0)*0.12+1);
  const bigGain=dE>Math.max(45000,(prev.ebitda||0)*0.1+1);
  const cand=[];
  if(bigDrop&&dShare<=-0.006&&dRev<0) cand.push({s:95,t:'Profits fell as share and revenue weakened.'});
  else if(bigDrop&&dShare<=-0.006) cand.push({s:93,t:'Profits fell as audience share slipped.'});
  else if(bigDrop&&dCost>Math.max(25000,dRev)) cand.push({s:91,t:'Costs rose faster than revenue — margins took a hit.'});
  else if(bigDrop) cand.push({s:88,t:'Profitability fell sharply vs last period.'});
  if(bigGain&&dShare>=0.006&&dRev>0) cand.push({s:92,t:'Revenue improved as audience share recovered.'});
  else if(bigGain&&dRev>0) cand.push({s:88,t:'Bottom line improved on stronger revenue.'});
  else if(bigGain) cand.push({s:84,t:'This signal’s profit improved vs last period.'});
  if(!bigDrop&&!bigGain){
    if(dShare<=-0.007) cand.push({s:80,t:'Share dipped — watch billing on this signal.'});
    if(dShare>=0.007) cand.push({s:76,t:'Share ticked up — a better billing base.'});
  }
  const dM=cur.margin-prev.margin;
  if(dM<=-7&&!cand.some(x=>x.s>=90)) cand.push({s:72,t:'Margins compressed as costs ate into revenue.'});
  if(dM>=7&&!cand.some(x=>x.s>=85)) cand.push({s:70,t:'Margins widened vs last period.'});
  cand.sort((a,b)=>b.s-a.s);
  return cand[0]?.t||'';
}
function buildPeriodChangeCompanyLines(G){
  const hist=MP.mode==='live'?(G._playerFinHistory?.[MP.playerId]||[]):(G.finHistory||[]);
  if(hist.length<2)return [];
  const cur=hist[hist.length-1], prev=hist[hist.length-2];
  const out=[];
  const de=cur.ebitda-prev.ebitda;
  const dRev=cur.revenue-prev.revenue;
  const dSh=cur.shareSum-prev.shareSum;
  const thr=Math.max(20000,Math.abs(prev.ebitda||0)*0.06);
  const debtUp=typeof cur.debtPrincipal==='number'&&typeof prev.debtPrincipal==='number'&&cur.debtPrincipal>prev.debtPrincipal+50000;
  const intUp=typeof cur.loanInterest==='number'&&typeof prev.loanInterest==='number'&&cur.loanInterest>prev.loanInterest+6000;
  if(de>thr){
    if(dSh>0.012&&dRev>0) out.push('Profits improved as audience share and revenue strengthened.');
    else if(dRev>0) out.push('Profits improved on higher revenue.');
    else out.push('Profits improved vs last period.');
  }else if(de<-thr){
    if(dSh<-0.012&&dRev<0) out.push('Profits fell as share and revenue weakened.');
    else if(dSh<-0.012) out.push('Profits fell as audience share slipped.');
    else if(dRev<0) out.push('Profits fell as revenue softened.');
    else out.push('Profits slipped vs last period.');
  }
  if(intUp){
    if(debtUp) out.push('Interest expense rose after new borrowing.');
    else out.push('Interest expense rose — rates or timing on existing debt.');
  }else if(debtUp&&!intUp) out.push('Debt load increased — interest may follow.');
  if(!debtUp&&dSh<-0.012&&!out.some(t=>t.includes('share'))) out.push('Combined share is down — billing headwind company-wide.');
  else if(!debtUp&&dSh>0.012&&!out.some(t=>t.includes('share'))) out.push('Combined share is up — stronger position with national and retail.');
  return out.slice(0,3);
}
/** Competitor intel: strategic one-liners from safe, visible signals only (no debt/cash). */
function competitorIntelStoryLine(s){
  if(!G||!s)return '';
  const op=simulcastOperationalSource(s);
  const pr=s.cp;
  const pool=[];
  if(pr?.sur) pool.push({p:1,t:'Gaining share with stronger programming.'});
  else if(pr?.col||pr?.under) pool.push({p:1,t:'Losing ground with weak audience performance.'});
  const partner=simulcastPartnerStation(s);
  if(partner){
    const legs=simulcastPairProgrammingLegs(s,partner);
    if(legs){
      const eS=legs.src.fin?.ebitda||0,eF=legs.flw.fin?.ebitda||0;
      if(legs.src.sig?.type==='AM'&&legs.flw.sig?.type==='FM'&&eF>eS+8000)
        pool.push({p:2,t:'FM likely monetizes better while the AM carries more programming cost.'});
      else if(Math.abs(eS-eF)>18000&&eF>eS)
        pool.push({p:2,t:'Follower leg appears to be outperforming the source on profit.'});
      else if(s._simulcastSource===true)
        pool.push({p:3,t:'Likely the programming source — higher cost center than the paired leg.'});
      else if(s._simulcastSource===false)
        pool.push({p:3,t:'Likely benefiting from shared programming vs the simulcast source.'});
    }else{
      const {lead,rcv}=simulcastPairLeadReceiver(s,partner);
      const el=lead.fin?.ebitda||0, er=rcv.fin?.ebitda||0;
      if(Math.abs(el-er)>25000){
        if(rcv.sig?.type==='AM'&&el>er) pool.push({p:2,t:'FM signal is monetizing better than the AM.'});
        else if(lead.sig?.type==='AM'&&er>el) pool.push({p:2,t:'FM leg is outperforming the AM cluster mate.'});
      }
    }
  }
  const sell=op.ops?.sell||0;
  if(sell>0.72) pool.push({p:3,t:'Strong sellout suggests efficient billing.'});
  else if(sell<0.45) pool.push({p:3,t:'Hurting from weak billing efficiency.'});
  const mdQ=Math.round(op.prog?.morningDrive?.quality||0);
  if(mdQ>=52&&!pr?.sur) pool.push({p:4,t:'Strong mornings appear to be helping.'});
  pool.sort((a,b)=>a.p-b.p);
  return [...new Set(pool.map(x=>x.t))].slice(0,2).join(' ');
}

/** Period summary share trend: prioritize last-book move so a rebound isn’t labeled “collapsing” from older two-book momentum. */
function formatPeriodSummaryShareTrendHtml(pr){
  if(!pr)return'';
  const dq=pr.dq||0;
  /* Any last-book gain reads as recovery; two-book “collapsing” only when flat or still drifting down. */
  if(dq>1e-6)return'  <span style="color:var(--grn)">⬆ rebounding</span>';
  if(dq<-1e-6)return'  <span style="color:var(--red)">⬇ sliding</span>';
  if(pr.col)return'  <span style="color:var(--red)">⬇⬇ collapsing</span>';
  if(pr.under)return'  <span style="color:var(--red)">⬇ declining</span>';
  if(pr.sur)return'  <span style="color:var(--grn)">⬆ surging</span>';
  return'  <span style="color:var(--mut)">→ stable</span>';
}
/** Explicit star-model programming pair when both legs are in `ps` (not legacy mutual-only). */
function playerSimulcastProgrammingLegsInPortfolio(st,partner,ps){
  if(!st||!partner||!ps?.length)return null;
  if(!ps.some(x=>x.id===st.id)||!ps.some(x=>x.id===partner.id))return null;
  return simulcastPairProgrammingLegs(st,partner);
}
function simulcastClusterCombinedFinances(src,flw){
  const rev=(src.fin?.rev||0)+(flw.fin?.rev||0);
  const cost=(src.fin?.cost||0)+(flw.fin?.cost||0);
  const ebitda=(src.fin?.ebitda||0)+(flw.fin?.ebitda||0);
  const fix=(src.fin?.fix||0)+(flw.fin?.fix||0);
  const effPromo=(src.fin?.effPromo||0)+(flw.fin?.effPromo||0);
  const effProg=(src.fin?.effProg||0)+(flw.fin?.effProg||0);
  const digRev=((src.fin?.digitalRev??src.fin?.streamRev)||0)+((flw.fin?.digitalRev??flw.fin?.streamRev)||0);
  return{rev,cost,ebitda,fix,effPromo,effProg,digRev};
}
function onAirTalentHalfPeriodForStation(st,G){
  const op=simulcastOperationalSource(st);
  return Object.values(op.prog||{}).filter(sl=>sl?.talent).reduce((sum,sl)=>sum+payrollHalfPeriodForDaypartSlot(sl),0);
}
function vacantDaypartsForPeriodSummary(st,G){
  const op=simulcastOperationalSource(st);
  const progSrc=simulcastProgrammingSource(op);
  return Object.keys(SL).filter(k=>{
    if(progSrc?.prog?.[k]?.talent)return false;
    if(getStationFranchise(op,k,G))return false;
    return !op.prog?.[k]?.talent;
  }).map(k=>SL[k]);
}
function buildPeriodSummarySoloStationHtml(s,G,bookYear,bookPeriod){
  const op=simulcastOperationalSource(s);
  const trd=formatPeriodSummaryShareTrendHtml(stationCardDisplayCp(s)||{});
  const stnMargin=s.fin.rev>0?Math.round((s.fin.ebitda/s.fin.rev)*100):0;
  let mc='amb';
  if(s.fin.ebitda<0)mc='neg';
  else if(s.fin.ebitda>0)mc='pos';
  const talCost=onAirTalentHalfPeriodForStation(s,G);
  const progSrc=simulcastProgrammingSource(s);
  const localMD=s.prog?.morningDrive?.talent;
  const simMD=!localMD&&progSrc?progSrc.prog?.morningDrive?.talent:null;
  const hostStr=localMD?localMD.name:(simMD?`${simMD.name} (${callDisplay(progSrc)})`:'');
  const vacant=vacantDaypartsForPeriodSummary(s,G);
  const simulcastLine=progSrc&&progSrc.id!==s.id?`<div class="sr"><span class="lb" style="color:var(--mut)">Programming</span><span class="vl" style="font-size:14px;color:var(--off)">Supplied by <strong>${callDisplay(progSrc)}</strong></span></div>`:'';
  const simFeeLine=(s.fin?.simulcastProgFee>0)?`<div class="sr"><span class="lb" style="color:var(--mut)">Simulcast program fee</span><span class="vl" style="font-size:14px;color:var(--off)">${f$(s.fin.simulcastProgFee)}/period</span></div>`:'';
  const ln=stationPeriodChangeLine(s,G);
  return `<div class="ms2"><div class="msh">${callDisplay(s)} — "${op.brand}" · ${fmtLabel(op.format)}${stationHasSimulcastLeg(s,G)?' ◈':''}</div>
    <div class="sr"><span class="lb">Share</span><span class="vl">${wlBookDisplaySharePct(s,G,bookYear,bookPeriod)}${trd}</span></div>
    <div class="sr"><span class="lb">Revenue / Costs</span><span class="vl">${f$(s.fin.rev)} / ${f$(s.fin.cost)}</span></div>
    <div class="sr"><span class="lb">EBITDA</span><span class="vl ${mc}">${s.fin.ebitda>=0?'+':''}${f$(s.fin.ebitda)} (${stnMargin}%)</span></div>
    ${(G.year||0)>=2005?`<div class="sr"><span class="lb">Digital revenue</span><span class="vl">${f$((s.fin.digitalRev??s.fin.streamRev)||0)}</span></div>
    <div class="sr"><span class="lb">Digital share</span><span class="vl">${s.fin.rev>0?Math.round((((s.fin.digitalRev??s.fin.streamRev)||0)/s.fin.rev)*100):0}%</span></div>`:''}
    <div class="sr"><span class="lb">Fixed / Talent</span><span class="vl" style="font-size:14px;color:var(--mut)">${f$(s.fin.fix||0)} / ${f$(talCost)}</span></div>
    ${simulcastLine}
    ${simFeeLine}
    <div class="sr"><span class="lb">Quality</span><span class="vl">${op.oq}/100${hostStr?' · '+hostStr:''}</span></div>
    ${vacant.length?`<div class="sr"><span class="lb" style="color:var(--red)">⚠ Vacant</span><span class="vl" style="color:var(--red);font-size:14px">${vacant.join(', ')}</span></div>`:''}
    ${ln?`<div class="sum-stn-narr">${ln}</div>`:''}
  </div>`;
}
function buildPeriodSummarySimulcastClusterHtml(src,flw,legs,G,bookYear,bookPeriod){
  const op=simulcastOperationalSource(legs.src);
  const anchor=legs.src;
  const trd=formatPeriodSummaryShareTrendHtml(stationCardDisplayCp(anchor)||{});
  const shComb=wlBookDisplaySimulcastShare01(src,flw,G,bookYear,bookPeriod);
  const fin=simulcastClusterCombinedFinances(src,flw);
  const stnMargin=fin.rev>0?Math.round((fin.ebitda/fin.rev)*100):0;
  let mc='amb';
  if(fin.ebitda<0)mc='neg';
  else if(fin.ebitda>0)mc='pos';
  const talCost=onAirTalentHalfPeriodForStation(legs.src,G);
  const localMD=op.prog?.morningDrive?.talent;
  const hostStr=localMD?localMD.name:'';
  const vacant=vacantDaypartsForPeriodSummary(legs.src,G);
  const ln=stationPeriodChangeLine(anchor,G)||stationPeriodChangeLine(flw,G);
  const simFee=(src.fin?.simulcastProgFee||0)+(flw.fin?.simulcastProgFee||0);
  const simFeeLine=simFee>0?`<div class="sr"><span class="lb" style="color:var(--mut)">Simulcast program fee</span><span class="vl" style="font-size:14px;color:var(--off)">${f$(simFee)}/period</span></div>`:'';
  return `<div class="ms2"><div class="msh">${callDisplay(src)} / ${callDisplay(flw)} — "${op.brand}" · ${fmtLabel(op.format)} simulcast</div>
    <div class="sr"><span class="lb">Share</span><span class="vl">${pct(shComb)} — combined simulcast audience${trd}</span></div>
    <div class="sr"><span class="lb">Revenue / Costs</span><span class="vl">${f$(fin.rev)} / ${f$(fin.cost)}</span></div>
    <div class="sr"><span class="lb">EBITDA</span><span class="vl ${mc}">${fin.ebitda>=0?'+':''}${f$(fin.ebitda)} (${stnMargin}%)</span></div>
    ${(G.year||0)>=2005?`<div class="sr"><span class="lb">Digital revenue</span><span class="vl">${f$(fin.digRev)}</span></div>
    <div class="sr"><span class="lb">Digital share</span><span class="vl">${fin.rev>0?Math.round((fin.digRev/fin.rev)*100):0}%</span></div>`:''}
    <div class="sr"><span class="lb">Fixed / Talent</span><span class="vl" style="font-size:14px;color:var(--mut)">${f$(fin.fix)} / ${f$(talCost)}</span></div>
    ${fin.effPromo+fin.effProg>0?`<div class="sr"><span class="lb">Promo / Programming</span><span class="vl" style="font-size:14px;color:var(--mut)">${f$(fin.effPromo)} / ${f$(fin.effProg)}</span></div>`:''}
    ${simFeeLine}
    <div class="sr"><span class="lb">Quality</span><span class="vl">${op.oq}/100${hostStr?' · '+hostStr:''}</span></div>
    ${vacant.length?`<div class="sr"><span class="lb" style="color:var(--red)">⚠ Vacant</span><span class="vl" style="color:var(--red);font-size:14px">${vacant.join(', ')}</span></div>`:''}
    ${ln?`<div class="sum-stn-narr">${ln}</div>`:''}
  </div>`;
}
function buildPeriodSummaryStationBlocksHtml(ps,G,bookYear,bookPeriod){
  const seen=new Set();
  const blocks=[];
  ps.forEach(s=>{
    if(!s||seen.has(s.id))return;
    const partner=simulcastPartnerStation(s);
    const legs=partner?playerSimulcastProgrammingLegsInPortfolio(s,partner,ps):null;
    if(legs){
      const anchor=simulcastPairStationCardAnchor(s,partner);
      const other=anchor.id===s.id?partner:s;
      seen.add(s.id);
      seen.add(partner.id);
      blocks.push(buildPeriodSummarySimulcastClusterHtml(anchor,other,legs,G,bookYear,bookPeriod));
      return;
    }
    seen.add(s.id);
    blocks.push(buildPeriodSummarySoloStationHtml(s,G,bookYear,bookPeriod));
  });
  return blocks.join('');
}
function showSum(profit,events,acts,alerts,displayYear,displayPeriod,rightsExtra){
  if(typeof globalThis!=='undefined'&&globalThis.__WL_HEADLESS__)return;
  const ps=myPS(),tRev=ps.reduce((s,st)=>s+st.fin.rev,0),tCost=ps.reduce((s,st)=>s+st.fin.cost,0);
  const vis=acts.filter(a=>['HIGH','MEDIUM'].includes(a.v));
  const margin=tRev>0?Math.round((profit/tRev)*100):0;
  const marginColor=margin>=35?'var(--grn)':margin>=15?'var(--amb)':'var(--red)';
  // Use passed year/period so the title reflects the period that just ran, not the next one
  const yr=displayYear||G.year, per=displayPeriod||G.period;
  const periodName=per===2?'FALL':'SPRING';
  const isElYr=yr%2===0&&per===2;
  const rightsLines=playerRelevantRightsActs(rightsExtra?.sportsActs,rightsExtra?.franchiseActs);
  const myLoanInt=MP.mode==='live'?(G._lastLoanInterestByPlayer?.[MP.playerId]||0):(G._lastLoanInterestCharge||0);
  const debtShow=debtPrincipalForPid(G,loanPidForGame());
  const _periodNarr=buildPeriodChangeCompanyLines(G);
  const _periodNarrHtml=_periodNarr.length?`<div class="sum-period-narr">${_periodNarr.map(t=>`<div class="sum-narr-line">${t}</div>`).join('')}</div>`:'';
  document.getElementById('sumt').textContent=`${yr} ${periodName} — PERIOD END`;
  document.getElementById('sumb').innerHTML=`
    <div class="ms2"><div class="msh">YOUR RESULTS</div>
      <div class="sr"><span class="lb">Revenue</span><span class="vl">${f$(tRev)}/period</span></div>
      <div class="sr"><span class="lb">Operating Costs</span><span class="vl">${f$(tCost)}/period</span></div>
      <div class="sr"><span class="lb">Net EBITDA</span><span class="vl ${profit>=0?'pos':'neg'}">${profit>=0?'+':''}${f$(profit)}</span></div>
      <div class="sr"><span class="lb">Margin</span><span class="vl" style="color:${marginColor}">${margin}%</span></div>
      ${myLoanInt>0?`<div class="sr"><span class="lb">Loan interest</span><span class="vl neg">−${f$(myLoanInt)}</span></div>`:''}
      <div class="sr"><span class="lb">Cash on Hand</span><span class="vl amb">${f$(mpMyCashOnHand())}</span></div>
      ${debtShow>0?`<div class="sr"><span class="lb" style="color:var(--red)">Debt principal</span><span class="vl neg">${f$(debtShow)} — click &#36; to manage</span></div>`:''}
      <div class="sr"><span class="lb" style="color:var(--mut)">Ad Market</span><span class="vl" style="color:${per===2?'var(--grn)':'var(--amb)'}">${per===2?'FALL — peak season (+12%)':'SPRING — lean season (−12%)'}${isElYr?' 🗳 +4% political for Talk/Sports':''}</span></div>
      ${_periodNarrHtml}
    </div>
    ${rightsLines.length?`<div class="ms2"><div class="msh">RIGHTS &amp; SYNDICATION (THIS PERIOD)</div>${rightsLines.map(t=>`<div class="sr"><span class="vl" style="color:var(--off);font-size:15px;font-family:var(--ft)">${t}</span></div>`).join('')}</div>`:''}
    ${buildPeriodSummaryStationBlocksHtml(ps,G,yr,per)}
    ${events.length?`<div class="ms2"><div class="msh">MARKET EVENTS</div>${events.map(ev=>`<div class="sr"><span class="lb" style="color:var(--amb)">📡 ${ev.t}</span><span class="vl" style="color:var(--off);font-size:15px;font-family:var(--fm)">${ev.d}</span></div>`).join('')}</div>`:''}
    ${vis.length?`<div class="ms2"><div class="msh">COMPETITOR MOVES</div>${vis.map(a=>`<div class="sr"><span class="vl" style="color:${a.v==='HIGH'?'var(--amb)':'var(--off)'};font-size:15px;font-family:var(--fm)">${a.t}</span></div>`).join('')}</div>`:''}
    ${alerts.length?`<div class="ms2"><div class="msh" style="color:var(--red)">⚠ ALERTS</div>${alerts.map(a=>`<div class="sr"><span class="vl" style="color:var(--red);font-size:15px">${a}</span></div>`).join('')}</div>`:''}`;
  // Decade-end notice so player doesn't dismiss before grade shows
  const _dEndYrs=[1979,1989,1999,2009,2019,2020].filter(y=>y>(G.sc?.startYear||1970));
  if(_dEndYrs.includes(displayYear)&&displayPeriod===2){
    document.getElementById('sumb').innerHTML+=
      '<div style="margin-top:12px;padding:10px;border:2px solid var(--amb);border-radius:4px;text-align:center">'+
      '<div style="font-family:var(--fd);color:var(--amb);font-size:14px">📊 DECADE REPORT CARD INCOMING</div>'+
      '<div style="font-family:var(--ft);color:var(--mut);font-size:15px;margin-top:4px">Your '+displayYear+' decade score will appear after you close this summary</div></div>';
  }
  om('m-sum');
  wlFtTutorialOnPeriodSummaryShown();
  if(isTutorialTurnaroundScen()&&typeof G!=='undefined'&&G&&G.tutorialMode&&MP.mode!=='live'&&(G.tutorialAct|0)===5&&!G._tutorialAct5FormatCoachShown)
    requestAnimationFrame(()=>tutorialTurnaroundCoachAfterRender());
}

